&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;用户名+生日&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;用户名@生日&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;用户名+特定字符&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;用户名@年份&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;姓名全拼+生日&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;姓名全拼@生日&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;姓名全拼@特定字符&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;用户名@domain&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;用户名@domain+特定字符&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;domain@特 定字符&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;键盘固定顺序及变形&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;各种系统的初始口令&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
